use super::*;

fn transpile_str(rust_code: &str) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    cg.emit_file(&file, None);
    cg.into_output()
}

fn transpile_str_module(rust_code: &str, module_name: &str) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    cg.emit_file(&file, Some(module_name));
    cg.into_output()
}

/// Module-mode variant that lets the test simulate a multi-file
/// crate by seeding the codegen's view of sibling module names.
/// Used by the cross-module use-path resolution tests so they can
/// assert that `use super::sibling::Item;` becomes
/// `import <crate>.<parent>.<sibling>;` rather than the broken
/// `using ::sibling::Item;`.
fn transpile_str_module_with_sibling_modules(
    rust_code: &str,
    module_name: &str,
    sibling_module_names: &[&str],
) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    let crate_root = module_name.split('.').next().unwrap_or(module_name);
    cg.set_crate_name(crate_root);
    cg.set_crate_module_names(
        sibling_module_names
            .iter()
            .map(|s| (*s).to_string())
            .collect(),
    );
    cg.emit_file(&file, Some(module_name));
    cg.into_output()
}

fn transpile_str_module_with_cpp_members(
    rust_code: &str,
    module_name: &str,
    cpp_module_member_symbols: HashMap<String, HashSet<String>>,
) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    cg.set_cpp_module_member_symbols(cpp_module_member_symbols);
    cg.emit_file(&file, Some(module_name));
    cg.into_output()
}

fn transpile_str_with_by_value_cycle_breaking_prototype(rust_code: &str) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    cg.set_by_value_cycle_breaking_prototype(true);
    cg.emit_file(&file, None);
    cg.into_output()
}

/// §13.14 Phase-4: transpile with the constraint-solver engine flag on
/// (deterministic via the setter, independent of the ambient env var).
fn transpile_str_infer_engine(rust_code: &str) -> String {
    let file: syn::File = syn::parse_str(rust_code).unwrap();
    let mut cg = CodeGen::new();
    cg.set_infer_engine(true);
    cg.emit_file(&file, None);
    cg.into_output()
}

#[test]
fn test_infer_engine_call_signature_resolves_vec_element_live() {
    // §13.14 C2 live wiring, on the case the existing heuristic CANNOT do:
    // generic instantiation. `identity<T>(x: T) -> T` called as
    // `v.push(identity(7u8))` must monomorphize T = u8 from the argument so the
    // Vec element is u8. The existing forward-scan heuristic leaves the generic
    // return unresolved; the engine's per-call unification (arg ↔ param, result
    // = return) pins it. Proves both that the live path works AND that the
    // engine adds capability the heuristic lacks.
    let src = r#"
        fn identity<T>(x: T) -> T { x }
        fn build() {
            let mut v = Vec::new();
            v.push(identity(7u8));
            let _ = v;
        }
    "#;
    let on = transpile_str_infer_engine(src);
    assert!(
        on.contains("rusty::Vec<uint8_t>"),
        "engine-on should resolve the Vec element to u8 via generic call instantiation:\n{on}"
    );
    // NB: the engine-OFF transpile of this snippet leaks `rusty::Vec<auto>`
    // (the heuristic can't instantiate the generic return), which the
    // auto-leak guard in `into_output` rejects with a panic — so we can't
    // assert the OFF spelling here. That the engine adds capability the
    // heuristic lacks is covered by the engine-level test
    // `block_local_element_from_generic_call_instantiates_from_arg`.
}

#[test]
fn test_infer_engine_method_call_resolves_vec_element_live() {
    // §13.14 C2 method form, live: a Vec element pushed as a user-method-call
    // result (`v.push(f.make_item())`) resolves to the method's return type
    // (Widget) via the MethodResolver (unique-method-return lookup) when the
    // engine flag is on.
    let src = r#"
        struct Widget;
        struct Factory;
        impl Factory {
            fn make_item(&self) -> Widget { loop {} }
        }
        fn build(f: Factory) {
            let mut v = Vec::new();
            v.push(f.make_item());
            let _ = v;
        }
    "#;
    let on = transpile_str_infer_engine(src);
    assert!(
        on.contains("rusty::Vec<Widget>"),
        "engine-on should resolve the Vec element via the method's return type:\n{on}"
    );
}

#[test]
fn test_simple_function() {
    let out = transpile_str("fn add(a: i32, b: i32) -> i32 { a + b }");
    assert!(out.contains("int32_t add(int32_t a, int32_t b)"), "{out}");
    // Operands may be wrapped in `deref_if_pointer_like` to tolerate
    // reference scrutinees.
    assert!(
        out.contains("return a + b;")
            || out.contains(
                "return rusty::detail::deref_if_pointer_like(a) + rusty::detail::deref_if_pointer_like(b);"
            ),
        "{out}"
    );
}

