fn test_void_function() {
    let out = transpile_str("fn noop() {}");
    assert!(out.contains("void noop()"));
}

#[test]
fn test_struct() {
    let out = transpile_str("struct Point { x: f64, y: f64 }");
    assert!(out.contains("struct Point {"));
    assert!(out.contains("double x;"));
    assert!(out.contains("double y;"));
}

#[test]
fn test_const() {
    let out = transpile_str("const MAX: i32 = 100;");
    // Literal RHS may be wrapped in static_cast for type pinning.
    assert!(
        out.contains("constexpr int32_t MAX = 100;")
            || out.contains("constexpr int32_t MAX = static_cast<int32_t>(100);"),
        "{out}"
    );
}

#[test]
fn test_primitive_max_lowers_to_numeric_limits_max() {
    let out = transpile_str("const X: i32 = i32::MAX;\nconst Y: u64 = u64::MAX;");
    assert!(
        out.contains("std::numeric_limits<int32_t>::max()"),
        "expected i32::MAX → numeric_limits<int32_t>::max(); got:\n{out}"
    );
    assert!(
        out.contains("std::numeric_limits<uint64_t>::max()"),
        "expected u64::MAX → numeric_limits<uint64_t>::max(); got:\n{out}"
    );
}

#[test]
fn test_primitive_int_min_lowers_to_numeric_limits_min() {
    // Regression: `iN::MIN` and `uN::MIN` used to fall through and be
    // emitted verbatim (e.g. `i32::MIN`) because the lowering helper
    // only matched `MAX`.
    let out = transpile_str(
        "const A: i32 = i32::MIN;\n\
         const B: i64 = i64::MIN;\n\
         const C: u32 = u32::MIN;",
    );
    assert!(
        out.contains("std::numeric_limits<int32_t>::min()"),
        "expected i32::MIN → numeric_limits<int32_t>::min(); got:\n{out}"
    );
    assert!(
        out.contains("std::numeric_limits<int64_t>::min()"),
        "expected i64::MIN → numeric_limits<int64_t>::min(); got:\n{out}"
    );
    assert!(
        out.contains("std::numeric_limits<uint32_t>::min()"),
        "expected u32::MIN → numeric_limits<uint32_t>::min(); got:\n{out}"
    );
    assert!(
        !out.contains("i32::MIN") && !out.contains("u32::MIN"),
        "Rust-syntax `iN::MIN`/`uN::MIN` should not survive into the C++ output; got:\n{out}"
    );
}

#[test]
fn test_primitive_assoc_const_emits_single_constexpr_no_extern() {
    // Top-level constants whose initializer is a primitive associated
    // constant lower to a `constexpr` `numeric_limits` call, which is
    // itself `constexpr` in C++14+. We should NOT additionally emit a
    // redundant `extern const T NAME;` forward declaration ahead of
    // the definition — the combined `constexpr T NAME = ...;` line
    // covers both.
    let out = transpile_str(
        "const A: i32 = i32::MIN;\nconst B: u64 = u64::MAX;\nconst C: f32 = f32::MIN;",
    );
    let extern_decls: Vec<&str> = out.lines().filter(|l| l.contains("extern const")).collect();
    assert!(
        extern_decls.is_empty(),
        "expected no `extern const ...;` forward decl for primitive \
         assoc-const initializers; saw: {extern_decls:?}\nfull output:\n{out}"
    );
}

#[test]
fn test_primitive_float_min_keeps_lowest_semantics() {
    // `f32::MIN` is the most negative representable value, which is
    // `numeric_limits<float>::lowest()` in C++ — NOT `min()` (which is
    // the smallest positive normal). The float-specific handler must
    // still win over the generic integer-MIN path.
    let out = transpile_str("const A: f32 = f32::MIN;\nconst B: f64 = f64::MIN;");
    assert!(
        out.contains("std::numeric_limits<float>::lowest()"),
        "expected f32::MIN → numeric_limits<float>::lowest(); got:\n{out}"
    );
    assert!(
        out.contains("std::numeric_limits<double>::lowest()"),
        "expected f64::MIN → numeric_limits<double>::lowest(); got:\n{out}"
    );
    assert!(
        !out.contains("numeric_limits<float>::min()")
            && !out.contains("numeric_limits<double>::min()"),
        "float `MIN` must not collapse to `min()`; got:\n{out}"
    );
}

#[test]
fn test_leaf10531_top_level_const_is_forward_declared_before_inline_use() {
    let out = transpile_str(
        r#"
        struct CapacityError;
        impl CapacityError {
            fn cap() -> usize { CAPERROR }
        }
        const CAPERROR: usize = 1;
        "#,
    );
    // Either a separate forward declaration precedes the use, or the
    // codegen reorders the const definition to come before the use site
    // (which makes the forward declaration unnecessary).
    let use_pos = out
        .find("return CAPERROR;")
        .expect("missing inline const use site");
    let forward_decl_pos = out.find("extern const size_t CAPERROR;");
    let def_pos = out
        .find("constexpr size_t CAPERROR")
        .expect("missing top-level const definition");
    let decl_or_def_pos = forward_decl_pos.unwrap_or(def_pos);
    assert!(
        decl_or_def_pos < use_pos,
        "const must be declared or defined before its inline use sites\nGot: {out}"
    );
    // Definition may use bare literal or `static_cast<size_t>(1)`.
    assert!(
        out.contains("constexpr size_t CAPERROR = 1;")
            || out.contains("constexpr size_t CAPERROR = static_cast<size_t>(1);"),
        "expected top-level const definition to remain present\nGot: {out}"
    );
}

#[test]
fn test_leaf523_top_level_const_mut_pointer_forward_decl_preserves_pointee_mutability() {
    let out = transpile_str(
        r#"
        const P: *mut i32 = std::ptr::null_mut();
        fn f() -> *mut i32 { P }
        "#,
    );
    assert!(
        out.contains("extern int32_t* const P;"),
        "expected pointer-const forward declaration shape, got:\n{}",
        out
    );
    assert!(
        !out.contains("extern const int32_t* P;"),
        "forward declaration must not turn *mut T into const T*:\n{}",
        out
    );
    assert!(
        out.contains("int32_t* const P ="),
        "definition must preserve mutable-pointee pointer-const shape, got:\n{}",
        out
    );
}

#[test]
fn test_leaf41543333333327111_local_new_const_uses_factory_materialization() {
    let out = transpile_str(
        r#"
        fn f() {
            const OF_U8: ArrayVec<Vec<u8>, 10> = ArrayVec::new_const();
            let mut var = OF_U8;
            var.push(Vec::new());
        }
        "#,
    );
    assert!(out.contains("const auto OF_U8 = []() -> ArrayVec<rusty::Vec<uint8_t>, 10> {"));
    assert!(out.contains("auto var = OF_U8();"));
    assert!(!out.contains("constexpr ArrayVec<rusty::Vec<uint8_t>, 10> OF_U8"));
}

