#[test]
fn test_binary_operators() {
    let out = transpile_str("fn f() -> i32 { 1 + 2 * 3 }");
    // Integer literals may be wrapped in `static_cast<int32_t>(...)` so
    // they pin the concrete type at the call site.
    assert!(
        out.contains("return 1 + 2 * 3;")
            || out.contains(
                "return static_cast<int32_t>(1) + (static_cast<int32_t>(2) * static_cast<int32_t>(3));"
            ),
        "{out}"
    );
}

#[test]
fn test_static_var() {
    let out = transpile_str("static COUNT: i32 = 0;");
    // RHS may be bare or wrapped in `static_cast<int32_t>(0)`; storage may be
    // emitted as `static` or `inline` (module-mode definition).
    assert!(
        out.contains("static int32_t COUNT = 0;")
            || out.contains("static int32_t COUNT = static_cast<int32_t>(0);")
            || out.contains("inline int32_t COUNT = 0;")
            || out.contains("inline int32_t COUNT = static_cast<int32_t>(0);"),
        "{out}"
    );
}

