#[test]
fn test_leaf49_numeric_literal_method_receiver_is_parenthesized() {
    let out = transpile_str("fn f() { 10.tap(|v| v); }");
    // Closure body may be bare `return v;` or `return std::move(v);`.
    assert!(
        out.contains("(10).tap([&](auto&& v) { return v; });")
            || out.contains("(10).tap([&](auto&& v) { return std::move(v); });"),
        "{out}"
    );
    assert!(!out.contains(" 10.tap("));
}

#[test]
fn test_leaf49_negative_numeric_literal_method_receiver_is_parenthesized() {
    let out = transpile_str("fn f() { (-10).tap(|v| v); }");
    // Closure body may be bare `return v;` or `return std::move(v);`.
    assert!(
        out.contains("((-10)).tap([&](auto&& v) { return v; });")
            || out.contains("((-10)).tap([&](auto&& v) { return std::move(v); });"),
        "{out}"
    );
    assert!(!out.contains("-10.tap("));
}

#[test]
fn test_leaf411_extension_impl_emits_free_function_and_rewrites_call() {
    let out = transpile_str(
        r#"
        trait TapOps { fn tap(self) -> Self; }
        impl<T> TapOps for T { fn tap(self) -> Self { self } }
        fn f() { let _ = 10.tap(); }
    "#,
    );
    assert!(out.contains("namespace rusty_ext {"));
    assert!(out.contains("T tap(T self_) {"));
    // Call may be a direct invocation (`rusty_ext::tap(10)`) or an IIFE
    // probe that selects between bare and deref-wrapped argument shapes.
    let direct = out.contains("static_cast<void>(rusty_ext::tap(10));");
    let probe = out.contains("rusty_ext::tap(std::forward<decltype(__self)>(__self))")
        && out.contains("rusty_ext::tap(rusty::detail::deref_if_pointer_like(std::forward<decltype(__self)>(__self)))");
    assert!(direct || probe, "{out}");
}

#[test]
fn test_leaf411_extension_impl_merged_impl_generics_emit_template_prefix() {
    let out = transpile_str(
        r#"
        trait KeyFunction<A> {
            type Key;
            fn call_mut(&mut self, arg: A) -> Self::Key;
        }

        impl<A, K, F> KeyFunction<A> for F
        where
            F: FnMut(A) -> K,
        {
            type Key = K;
            fn call_mut(&mut self, arg: A) -> Self::Key {
                (*self)(arg)
            }
        }
    "#,
    );
    assert!(
        out.contains("template<typename A, typename K, typename F>")
            || out.contains("template<typename A, typename F, typename K>"),
        "{out}"
    );
    assert!(out.contains("K call_mut(F& self_, A arg) {"), "{out}");
}

#[test]
fn test_leaf411_extension_impl_module_forward_decl_keeps_assoc_bound_generics() {
    let out = transpile_str_module(
        r#"
        trait KeyFunction<A> {
            type Key;
            fn call_mut(&mut self, arg: A) -> Self::Key;
        }

        impl<A, K, F> KeyFunction<A> for F
        where
            F: FnMut(A) -> K,
        {
            type Key = K;
            fn call_mut(&mut self, arg: A) -> Self::Key {
                (*self)(arg)
            }
        }
        "#,
        "itertools",
    );
    assert!(
        out.contains("template<typename A, typename K, typename F>")
            || out.contains("template<typename A, typename F, typename K>"),
        "{out}"
    );
    assert!(out.contains("K call_mut(F& self_, A arg);"), "{out}");
}

#[test]
