#[test]
fn test_leaf411_option_none_extension_call_uses_typed_option_receiver() {
    let out = transpile_str(
        r#"
        trait TapOptionOps<T> { fn tap_none<F>(self, f: F) -> Self; }
        impl<T> TapOptionOps<T> for Option<T> { fn tap_none<F>(self, f: F) -> Self { self } }
        fn f() {
            let _: Option<i32> = None.tap_none(|| 0);
        }
    "#,
    );
    // Call may use direct ctor `(rusty::Option<int32_t>(rusty::None), ...)`
    // or list-initializer ctor `rusty::Option<int32_t>{rusty::None}` wrapped
    // in an IIFE probe via `rusty_ext::tap_none(...)`.
    let direct = out.contains("rusty_ext::tap_none(rusty::Option<int32_t>(rusty::None),");
    let probe = out.contains("rusty_ext::tap_none")
        && out.contains("rusty::Option<int32_t>{rusty::None}");
    assert!(direct || probe, "{out}");
}

#[test]
fn test_leaf411_result_as_mut_if_let_binds_referenced_inner_value() {
    let out = transpile_str(
        r#"
        trait TapResultOps<T, E> { fn tap_err<R, F: FnOnce(&mut E) -> R>(self, f: F) -> Self; }
        impl<T, E> TapResultOps<T, E> for Result<T, E> {
            fn tap_err<R, F: FnOnce(&mut E) -> R>(mut self, f: F) -> Self {
                if let Err(mut val) = self.as_mut() {
                    let _ = f(&mut val);
                }
                self
            }
        }
    "#,
    );
    assert!(out.contains(
        "if (auto&& _iflet_scrutinee = self_.as_mut(); _iflet_scrutinee.is_err()) {"
    ), "{out}");
    // Either the legacy deref-extraction or the deref_if_pointer_like wrap.
    // Plain `auto val = _iflet_scrutinee.unwrap_err();` (no ref) is still wrong.
    assert!(
        out.contains("auto& val = *_iflet_scrutinee.unwrap_err();")
            || out.contains(
                "auto& val = rusty::detail::deref_if_pointer_like(_iflet_scrutinee.unwrap_err())"
            ),
        "{out}"
    );
    assert!(!out.contains("auto val = _iflet_scrutinee.unwrap_err();"), "{out}");
}

