#[test]
fn test_leaf132_extension_trait_callable_bound_preserves_borrow_shape_for_inner_binding() {
    let out = transpile_str(
        r#"
        trait TapResultOps<T, E> { fn tap_err<R, F: FnOnce(&mut E) -> R>(self, f: F) -> Self; }
        impl<T, E> TapResultOps<T, E> for Result<T, E> {
            fn tap_err<R, F: FnOnce(&mut E) -> R>(mut self, f: F) -> Self {
                if let Err(mut val) = self.as_mut() {
                    let _ = f(&mut val);
                }
                self
            }
        }
    "#,
    );
    // Binding extraction may use legacy `auto& val = *_iflet_scrutinee.unwrap_err();`,
    // newer `decltype(auto) val = _iflet_scrutinee.unwrap_err();`, or a
    // `deref_if_pointer_like` wrap. Verify the binding exists in some form.
    assert!(
        out.contains("auto& val = *_iflet_scrutinee.unwrap_err();")
            || out.contains("decltype(auto) val = _iflet_scrutinee.unwrap_err();")
            || out
                .contains("auto& val = rusty::detail::deref_if_pointer_like(_iflet_scrutinee.unwrap_err())"),
        "{out}"
    );
    // The `&mut val` arg must reach the callee unchanged.
    assert!(out.contains("static_cast<void>(f(&val));"), "{out}");
}

