#[test]
fn test_leaf41543333333327451_local_drop_impl_merges_into_local_struct() {
    let out = transpile_str(
        r#"
        use std::cell::Cell;
        fn f() {
            let flag = &Cell::new(0);
            struct Bump<'a>(&'a Cell<i32>);
            impl<'a> Drop for Bump<'a> {
                fn drop(&mut self) {
                    let n = self.0.get();
                    self.0.set(n + 1);
                }
            }
            let _x = Bump(flag);
        }
        "#,
    );
    assert!(out.contains("Bump(const rusty::Cell<int32_t>& _0_init) : _0(_0_init) {}"));
    assert!(out.contains("Bump(Bump&& other) noexcept : _0(other._0) {"));
    assert!(out.contains("~Bump() noexcept(false) {"));
    // LHS of `n + 1` may be bare or wrapped via `deref_if_pointer_like`,
    // and `1` may be bare or `static_cast<int32_t>(1)`.
    assert!(
        out.contains("this->_0.set(n + 1);")
            || out
                .contains("this->_0.set(rusty::detail::deref_if_pointer_like(n) + 1);")
            || out.contains(
                "this->_0.set(rusty::detail::deref_if_pointer_like(n) + static_cast<int32_t>(1));"
            ),
        "{out}"
    );
}

