#[test]
fn test_leaf41543333333327451_local_impl_keeps_outer_self_context() {
    let out = transpile_str(
        r#"
        struct Outer {
            len_field: i32,
        }
        impl Outer {
            fn first(&mut self) {
                struct Local<'a>(&'a mut i32);
                impl<'a> Drop for Local<'a> {
                    fn drop(&mut self) {}
                }
                let _g = Local(&mut self.len_field);
            }
            fn second(self) -> Self {
                Self { len_field: self.len_field }
            }
        }
        "#,
    );
    // Method may be inline `Outer second() {` (non-const) or
    // `Outer second() const {` (const). The B3 fix made by-value
    // `self` const by default, but the heuristic-refinement
    // (body_moves_out_self_field) makes any method whose body
    // contains `self.<field>` accesses emit as non-const — to
    // safely handle move-only-T cases. For Copy-only fields
    // (`len_field: i32` here) either is correct semantically;
    // we accept both.
    assert!(
        out.contains("Outer second() {")
            || out.contains("Outer Outer::second() {")
            || out.contains("Outer second() const {")
            || out.contains("Outer Outer::second() const {"),
        "{out}"
    );
    // Field copy may be bare or wrapped in `std::move(...)`.
    assert!(
        out.contains("return Outer{.len_field = this->len_field};")
            || out.contains("return Outer{.len_field = std::move(this->len_field)};"),
        "{out}"
    );
    assert!(!out.contains("auto second() {"));
    assert!(!out.contains("Self::"));
}

#[test]
fn test_leaf5113_method_local_generic_struct_is_hoisted_out_of_method_body() {
    let out = transpile_str(
        r#"
        struct Bucket<T> {
            item: T,
        }
        impl<T> Bucket<T> {
            fn fill<I: Iterator<Item = T>>(&mut self, mut iter: I) {
                let mut count = 0usize;
                while count < 1 {
                    let value = match iter.next() {
                        Some(v) => v,
                        None => break,
                    };
                    self.item = value;
                    count += 1;
                }
                struct DropOnPanic<U> {
                    ptr: *mut U,
                    skip: Range<usize>,
                    len: usize,
                }
                impl<U> Drop for DropOnPanic<U> {
                    fn drop(&mut self) {
                        let _ = self.skip.start;
                    }
                }
                let _guard = DropOnPanic {
                    ptr: std::ptr::null_mut(),
                    skip: 0..0,
                    len: 0,
                };
            }
        }
        "#,
    );
    let struct_pos = out
        .find("struct DropOnPanic {")
        .expect("missing hoisted DropOnPanic struct");
    let method_pos = out
        .find("void fill(I iter)")
        .expect("missing fill method signature");
    assert!(
        struct_pos < method_pos,
        "method-local generic struct should be hoisted before method signature; got:\n{}",
        out
    );
    assert!(
        !out[method_pos..].contains("struct DropOnPanic {"),
        "DropOnPanic should not be emitted inside method body; got:\n{}",
        out
    );
    assert!(
        out.contains("rusty::range<size_t> skip;"),
        "hoisted local generic structs should keep fully-qualified range types, got:\n{}",
        out
    );
}

#[test]
fn test_leaf5113_local_match_none_break_initializer_lowers_as_statement_flow() {
    let out = transpile_str(
        r#"
        fn f(mut v: Vec<i32>) {
            let mut iter = v.into_iter();
            while true {
                let element = match iter.next() {
                    Some(x) => x,
                    None => break,
                };
                let _ = element;
            }
        }
        "#,
    );
    // Break guard may be single-line or multi-line.
    assert!(
        out.contains("if (_m.is_none()) { break; }")
            || (out.contains("if (_m.is_none()) {") && out.contains("break;")),
        "match-break local init should lower to statement break guard, got:\n{}",
        out
    );
    assert!(
        !out.contains("return break;"),
        "local match-break lowering must not emit return break in an expression context, got:\n{}",
        out
    );
}

#[test]
fn test_leaf5156_local_generic_drop_guard_struct_literal_recovers_owner_type_arg() {
    let out = transpile_str(
        r#"
        struct Bucket<T> {
            item: T,
        }
        impl<T> Bucket<T> {
            fn guard(&mut self, ptr: *mut T) {
                struct DropOnPanic<U> {
                    start: *mut U,
                    len: usize,
                }
                impl<U> Drop for DropOnPanic<U> {
                    fn drop(&mut self) {}
                }
                let guard = DropOnPanic {
                    start: ptr,
                    len: 0,
                };
                let _ = guard;
            }
        }
        "#,
    );
    assert!(
        out.contains("const auto guard = DropOnPanic<T>{")
            || out.contains("const auto guard = DropOnPanic<T>("),
        "local generic guard struct literal should recover explicit owner args, got:\n{}",
        out
    );
    assert!(
        !out.contains("const auto guard = DropOnPanic{")
            && !out.contains("const auto guard = DropOnPanic("),
        "guard construction should not rely on unspecialized CTAD path, got:\n{}",
        out
    );
}

#[test]
fn test_leaf5297_shadowed_local_generic_args_are_elided_for_hoisted_local_struct() {
    let out = transpile_str(
        r#"
        struct Outer<T, const N: usize> {
            _value: T,
        }
        impl<T, const N: usize> Outer<T, N> {
            fn guard(&mut self) {
                struct Guard<'a, T, const N: usize> {
                    outer: &'a mut Outer<T, N>,
                }
                impl<T, const N: usize> Drop for Guard<'_, T, N> {
                    fn drop(&mut self) {}
                }
                let _guard = Guard::<T, N> { outer: self };
            }
        }
        "#,
    );
    assert!(
        out.contains("struct Guard {"),
        "hoisted local guard struct should emit without a shadowing template prefix, got:\n{}",
        out
    );
    // Codegen may still keep the explicit `<T, N>` on the literal-call
    // form. This isn't strictly required for correctness (the inner
    // `Guard` struct doesn't itself need T and N), but the construction
    // still type-checks. Accept either elided or preserved.
    let has_explicit = out.contains("Guard<T, N>")
        || out.contains("Guard<T,N>")
        || out.contains("Guard< T, N >");
    // At minimum we should not have leaked `'a` lifetimes into the C++.
    assert!(
        !out.contains("Guard<'_, T, N>") && !out.contains("Guard<'a, T, N>"),
        "guard should not leak Rust lifetimes, got:\n{}",
        out
    );
    let _ = has_explicit;
}

#[test]
fn test_leaf5175_local_drop_guard_struct_literal_prefers_pointer_item_type_over_owner_scope() {
    let out = transpile_str(
        r#"
        trait ArrayLike {
            type Item;
        }
        impl<T, const N: usize> ArrayLike for [T; N] {
            type Item = T;
        }
        struct SmallVec<A> {
            _a: A,
        }
        impl<A: ArrayLike> SmallVec<A> {
            fn as_mut_ptr(&mut self) -> *mut A::Item {
                std::ptr::null_mut()
            }
            fn insert_many(&mut self) {
                struct DropOnPanic<U> {
                    start: *mut U,
                    len: usize,
                }
                impl<U> Drop for DropOnPanic<U> {
                    fn drop(&mut self) {}
                }
                let start = self.as_mut_ptr();
                let guard = DropOnPanic {
                    start,
                    len: 0,
                };
                let _ = guard;
            }
        }
        "#,
    );
    assert!(
        out.contains("const auto guard = DropOnPanic<rusty::detail::associated_item_t<A>>{")
            || out.contains(
                "const auto guard = DropOnPanic<rusty::detail::associated_item_t<A>>("
            )
            || out.contains("const auto guard = DropOnPanic<typename A::Item>{")
            || out.contains("const auto guard = DropOnPanic<typename A::Item>("),
        "guard should recover item pointer payload type for local generic arg, got:\n{}",
        out
    );
    assert!(
        !out.contains("const auto guard = DropOnPanic<A>{")
            && !out.contains("const auto guard = DropOnPanic<A>("),
        "guard should not recover owner type when pointer field indicates item type, got:\n{}",
        out
    );
}

#[test]
fn test_leaf5157_self_assoc_into_iter_struct_literal_avoids_spurious_alias_template_args() {
    let out = transpile_str(
        r#"
        trait IntoIterLike {
            type IntoIter;
            fn into_iter(self) -> Self::IntoIter;
        }
        struct IntoIter<A> {
            data: A,
            current: usize,
            end: usize,
        }
        struct S<A> {
            data: A,
        }
        impl<A> IntoIterLike for S<A> {
            type IntoIter = IntoIter<A>;
            fn into_iter(self) -> Self::IntoIter {
                IntoIter { data: self.data, current: 0, end: 0 }
            }
        }
        "#,
    );
    assert!(
        out.contains("using IntoIter = IntoIter<A>;")
            || out.contains("using IntoIter = ::IntoIter<A>;"),
        "self-associated IntoIter alias should be preserved, got:\n{}",
        out
    );
    assert!(
        out.contains("return typename S::IntoIter(")
            || out.contains("return typename S::IntoIter{")
            || out.contains("return IntoIter(")
            || out.contains("return IntoIter{"),
        "struct literal should lower through associated alias target, got:\n{}",
        out
    );
    assert!(
        !out.contains("return typename S::IntoIter<A>(")
            && !out.contains("return typename S::IntoIter<A>{"),
        "associated alias target should not gain spurious template args, got:\n{}",
        out
    );
    assert!(
        out.contains("IntoIter into_iter(") || out.contains("typename S::IntoIter into_iter("),
        "associated alias return type should stay non-templated at use sites, got:\n{}",
        out
    );
    // The inherent struct method (no-arg `into_iter()`) must keep its associated-alias
    // return type non-templated. The UFCS free function (`into_iter(S<A> self_)`) legitimately
    // uses the fully-qualified `IntoIter<A>` form (no struct alias in scope), so the absence
    // check is scoped to the no-arg struct-method form.
    assert!(
        !out.contains("IntoIter<A> into_iter()")
            && !out.contains("typename S::IntoIter<A> into_iter()"),
        "associated alias return type should not gain spurious template args, got:\n{}",
        out
    );
}

