fn test_leaf4153_free_function_ref_arg_call_drops_address_of() {
    let out = transpile_str(
        r#"
        fn take<T>(mut_ref: &mut T) {}
        fn f() {
            let mut v = 1;
            take(&mut v);
        }
        "#,
    );
    // Argument may be passed bare (`take(v)`) or through the
    // deref-if-pointer-like wrapper for reference scrutinees.
    assert!(
        out.contains("take(v);")
            || out.contains("take(rusty::detail::deref_if_pointer_like(v));"),
        "{out}"
    );
    assert!(!out.contains("take(&v);"));
}

