#[test]
fn test_leaf4122_std_ptr_and_mem_function_paths_remapped() {
    let out = transpile_str(
        r#"
        fn f(p: *mut i32, v: i32) {
            unsafe {
                let _x = std::ptr::read(p);
                std::ptr::write(p, v);
                std::mem::forget(v);
                std::mem::replace(&mut v, 2);
            }
        }
    "#,
    );
    // The pointer argument may pass through std::move (legacy) or be
    // passed directly (current — raw pointers are trivially copyable
    // so std::move adds nothing for them).
    assert!(
        out.contains("rusty::ptr::read(std::move(p))")
            || out.contains("rusty::ptr::read(p)"),
        "{out}"
    );
    assert!(
        out.contains("rusty::ptr::write(std::move(p), std::move(v))")
            || out.contains("rusty::ptr::write(p, std::move(v))"),
        "{out}"
    );
    assert!(out.contains("rusty::mem::forget(std::move(v))"), "{out}");
    // Integer literal RHS may be wrapped in `static_cast<int32_t>`.
    assert!(
        out.contains("rusty::mem::replace(v, 2)")
            || out.contains("rusty::mem::replace(v, static_cast<int32_t>(2))"),
        "{out}"
    );
    assert!(!out.contains("std::ptr::read"), "{out}");
    assert!(!out.contains("std::ptr::write"), "{out}");
    assert!(!out.contains("std::mem::forget"), "{out}");
}

#[test]
fn test_module_const_typed_with_later_type_alias_emits_alias_first() {
    // A module const whose TYPE is a local type alias declared LATER in source
    // (Rust items are order-independent) must emit the `using` alias before the
    // const that uses it. hashbrown's bitmask module:
    //   const BITMASK_ITER_MASK: BitMaskWord = ...;  type BitMaskWord = u16;
    let out = transpile_str(
        r#"
        mod m {
            pub const MASK: Word = 0xFF;
            pub type Word = u16;
        }
        "#,
    );
    let alias_pos = out
        .find("using Word = uint16_t;")
        .expect("missing Word alias");
    let const_pos = out.find("Word MASK").expect("missing MASK const");
    assert!(
        alias_pos < const_pos,
        "type alias must precede the const that uses it:\n{}",
        out
    );
}

#[test]
fn test_raw_pointer_cast_without_target_uses_cast_proxy() {
    // `ptr.cast()` with no turbofish and a callee whose signature we don't model
    // (here a free fn) has no determinable target pointee — emit the adapting
    // `rusty::ptr::cast(ptr)` proxy, NOT the bare `ptr->cast()` member call
    // (raw pointers have no `cast` member). hashbrown's SSE2 Group::load pattern.
    let out = transpile_str(
        r#"
        struct Tag(u8);
        fn sink(p: *const u64);
        fn f(ptr: *const Tag) {
            unsafe { sink(ptr.cast()); }
        }
        "#,
    );
    assert!(
        out.contains("rusty::ptr::cast(ptr)"),
        "no-target cast should use the proxy, got:\n{}",
        out
    );
    assert!(!out.contains("ptr->cast()"), "{out}");
}

#[test]
fn test_raw_pointer_cast_with_turbofish_uses_reinterpret_cast() {
    // With an explicit target, the cast still lowers directly to reinterpret_cast.
    let out = transpile_str(
        r#"
        struct Tag(u8);
        fn f(ptr: *const Tag) {
            let _q: *const u64 = ptr.cast::<u64>();
        }
        "#,
    );
    assert!(
        out.contains("reinterpret_cast<const uint64_t*>(ptr)"),
        "turbofish cast should lower to reinterpret_cast, got:\n{}",
        out
    );
}

