#[test]
fn test_generic_deref_wrapper_field_access_resolves_through_target() {
    // Field access through a GENERIC user `Deref` wrapper must resolve to the
    // concrete deref-target's field. Two inference steps combine: (1) the local
    // binding's type is the callee's return type with type params substituted
    // from the argument types (`guard(inner, f)` -> `ScopeGuard<Inner, F>`,
    // not the raw `ScopeGuard<T, F>`); (2) the recorded Deref Target `T` is
    // instantiated with the receiver's actual args (`T` -> `Inner`). Then the
    // field is found on `Inner` and emitted as `(*g).field`. Foundation for the
    // auto-deref engine (ScopeGuard).
    let out = transpile_str(
        r#"
        struct Inner { payload: i32 }
        struct ScopeGuard<T, F> { value: T, dropfn: F }
        impl<T, F> std::ops::Deref for ScopeGuard<T, F> {
            type Target = T;
            fn deref(&self) -> &T { &self.value }
        }
        fn guard<T, F>(value: T, dropfn: F) -> ScopeGuard<T, F> {
            ScopeGuard { value, dropfn }
        }
        fn use_it(inner: Inner) -> i32 {
            let g = guard(inner, || {});
            g.payload
        }
    "#,
    );
    assert!(
        out.contains("rusty::detail::deref_if_pointer((*g)).payload"),
        "field access through a generic Deref wrapper should resolve to \
         (*g).payload:\n{out}"
    );
}

#[test]
fn test_generic_deref_wrapper_method_call_resolves_through_target() {
    // Method side of the auto-deref engine: a method that lives on the
    // receiver's Deref Target (not the wrapper) must lower to `(*g).method()`,
    // while a method inherent on the wrapper stays `g.method()`. Mirrors the
    // field path. Clears the hashbrown ScopeGuard cluster (guard.num_buckets()
    // etc.).
    let out = transpile_str(
        r#"
        struct Inner { payload: i32 }
        impl Inner { fn compute(&self) -> i32 { self.payload } }
        struct ScopeGuard<T, F> { value: T, dropfn: F }
        impl<T, F> ScopeGuard<T, F> { fn defuse(&self) {} }
        impl<T, F> std::ops::Deref for ScopeGuard<T, F> {
            type Target = T;
            fn deref(&self) -> &T { &self.value }
        }
        fn guard<T, F>(value: T, dropfn: F) -> ScopeGuard<T, F> {
            ScopeGuard { value, dropfn }
        }
        fn use_it(inner: Inner) -> i32 {
            let g = guard(inner, || {});
            g.defuse();
            g.compute()
        }
    "#,
    );
    assert!(
        out.contains("rusty::detail::deref_if_pointer((*g)).compute()"),
        "method on the Deref target should resolve to (*g).compute():\n{out}"
    );
    assert!(
        out.contains("g.defuse()") && !out.contains("rusty::detail::deref_if_pointer((*g)).defuse()"),
        "method inherent on the wrapper must stay g.defuse():\n{out}"
    );
}

#[test]
fn test_primitive_assoc_function_path_calls_lower_to_rusty_free_fns() {
    // `<primitive>::<assoc_fn>(args)` path-calls (NOT method calls) must lower
    // to the rusty free functions, not leave `u64::`/`usize::` as undeclared
    // identifiers. Regression for hashbrown's `u64::from_ne_bytes(...)` and
    // `usize::max(a, b)`.
    let out = transpile_str(
        r#"
        fn f(bytes: [u8; 8], a: usize, b: usize) -> u64 {
            let x = u64::from_ne_bytes(bytes);
            let _m = usize::max(a, b);
            x
        }
    "#,
    );
    assert!(
        out.contains("rusty::from_ne_bytes<uint64_t>(bytes)"),
        "u64::from_ne_bytes should lower to rusty::from_ne_bytes<uint64_t>:\n{out}"
    );
    assert!(
        out.contains("rusty::max("),
        "usize::max(a, b) should lower to rusty::max(a, b):\n{out}"
    );
    assert!(
        !out.contains("u64::from_ne_bytes") && !out.contains("usize::max"),
        "primitive type name must not survive as an undeclared identifier:\n{out}"
    );
}

#[test]
fn test_use_sibling_module_as_alias_emits_relative_namespace_alias() {
    // `use sibling as alias;` inside a nested module must emit a namespace
    // alias (`namespace alias = sibling;`), not a type alias
    // (`using alias = sibling;`). The bare sibling target resolves relative to
    // the current module scope, so the alias is emitted relative (no `::`).
    // Regression for hashbrown's `use generic as imp;` in control::group.
    let out = transpile_str(
        r#"
        mod group {
            mod generic { pub struct G; }
            use generic as imp;
            pub fn h() -> imp::G { imp::G }
        }
    "#,
    );
    assert!(
        out.contains("namespace imp = generic;"),
        "module rename should emit a (relative) namespace alias:\n{out}"
    );
    assert!(
        !out.contains("using imp = generic;"),
        "module rename must not emit a type alias:\n{out}"
    );
}

