#[test]
fn test_backward_collect_target_from_struct_field_consumption() {
    // indexmap's `IntoKeys::new/clone`: the collect target — and through it
    // the mapper closure's return type and the `MaybeUninit::uninit()` field
    // owner — is pinned ONLY by the consuming struct field's declared type
    // (`iter: vec::IntoIter<Bucket<K, MaybeUninit<V>>>`). Without the
    // backward hop the owner degrades to ill-formed `MaybeUninit<auto>`.
    let out = transpile_str(
        r#"
        use std::mem::MaybeUninit;
        use std::vec;
        pub struct Bucket<K, V> {
            pub hash: u64,
            pub key: K,
            pub value: V,
        }
        pub struct IntoKeys<K, V> {
            iter: vec::IntoIter<Bucket<K, MaybeUninit<V>>>,
        }
        impl<K, V> IntoKeys<K, V> {
            pub(crate) fn new(entries: Vec<Bucket<K, V>>) -> Self {
                let entries = entries
                    .into_iter()
                    .map(|Bucket { hash, key, .. }| Bucket {
                        hash,
                        key,
                        value: MaybeUninit::uninit(),
                    })
                    .collect::<Vec<_>>();
                Self {
                    iter: entries.into_iter(),
                }
            }
        }
    "#,
    );
    assert!(
        out.contains("rusty::MaybeUninit<V>::uninit()"),
        "collect target must flow backward from the consuming field into the mapper's struct-literal field:\n{out}"
    );
    assert!(
        !out.contains("MaybeUninit<auto>"),
        "no `<auto>` owner may survive the backward flow:\n{out}"
    );
}

#[test]
fn test_unguarded_return_arm_match_with_differing_types_lowers_to_statement_expr() {
    // indexmap TryReserveError Display::fmt: `let reason = match &self.kind {
    // Std(e) => return Display::fmt(e, f), CapacityOverflow => "...",
    // AllocError { .. } => "..." }` — no guards, but the return arm's type
    // (fmt::Result) differs from the match value (&str); the IIFE lambda
    // would bind the return to itself. Also covers Pat::Struct arms.
    let out = transpile_str(
        r#"
        use core::fmt;
        pub struct E2;
        pub enum Kind {
            Std(E2),
            CapacityOverflow,
            AllocError { layout: usize },
        }
        pub struct Err2 {
            kind: Kind,
        }
        impl fmt::Display for E2 {
            fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
                f.write_str("std")
            }
        }
        impl fmt::Display for Err2 {
            fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
                let reason = match &self.kind {
                    Kind::Std(e) => return fmt::Display::fmt(e, f),
                    Kind::CapacityOverflow => " because capacity exceeded the maximum",
                    Kind::AllocError { .. } => " because the allocator returned an error",
                };
                f.write_str("memory allocation failed")?;
                f.write_str(reason)
            }
        }
    "#,
    );
    // Batch 78: this shape now lowers via the statement if-chain (decl +
    // per-arm assignment; fn-level returns stay native) instead of a GCC
    // statement expression.
    assert!(
        out.contains("std::string_view reason;"),
        "no-guard return-arm match must declare the local before the if-chain:\n{out}"
    );
    assert!(
        out.contains("reason = std::string_view(\" because capacity exceeded the maximum\");"),
        "value arms must assign into the declared local:\n{out}"
    );
    assert!(
        out.contains("variant_index(rusty::detail::deref_if_pointer(_m)) == 2"),
        "Pat::Struct arm condition must go through deref_if_pointer:\n{out}"
    );
    assert!(!out.contains("const auto reason = ({"));
}

