#[test]
fn test_deref_assigned_local_binding_drops_const() {
    // indexmap update_index: `let index = table.find_mut(..).expect(..); *index = new;`
    // — a `&mut`-holding binding whose type inference fails must still drop
    // `const`, or the deref-assign fails ("cannot assign to return value
    // because function 'deref_if_pointer_like<...>' returns a const value").
    let out = transpile_str(
        r#"
        pub fn update(v: &mut Vec<usize>, old: usize, new: usize) {
            let index = v.iter_mut().find(|i| **i == old).expect("index not found");
            *index = new;
        }
    "#,
    );
    assert!(
        !out.contains("const auto index"),
        "deref-assigned binding must not be const:\n{out}"
    );
    assert!(out.contains("auto index"), "{out}");
}

#[test]
fn test_assoc_method_path_mapper_lowers_to_forwarding_lambda() {
    // indexmap get_disjoint_mut: `indices.map(Some)` + `key_values.map(Option::unwrap)`
    // — path-callable mappers must lower to lambdas; a raw `Option::unwrap`
    // is not a valid C++ callable ("use of undeclared identifier 'Option'").
    let out = transpile_str(
        r#"
        pub fn t(indices: [usize; 3]) -> [usize; 3] {
            let wrapped = indices.map(Some);
            wrapped.map(Option::unwrap)
        }
    "#,
    );
    assert!(
        !out.contains("Option::unwrap"),
        "assoc-method mapper must not emit a raw path:\n{out}"
    );
    assert!(out.contains(".unwrap(); }"), "{out}");
    assert!(out.contains("rusty::Some(std::forward"), "{out}");
}

#[test]
fn test_keyword_named_loop_binding_escapes_consistently() {
    // indexmap update_index loop: `for ((new, old), entry) in …` — the
    // keyword-named binding must be escaped at BOTH the declaration
    // (loop head / destructure prelude, `new_`) and every body use;
    // a verbatim loop-var registration desyncs them (`std::move(new)`).
    let out = transpile_str(
        r#"
        fn f(a: usize) -> usize { a }
        pub fn t1() {
            for new in 0..3 {
                let _ = f(new);
            }
        }
        pub fn t2(start: usize, v: Vec<usize>) {
            for (new, old) in (start..).zip(v) {
                let _ = f(new);
                let _ = f(old);
            }
        }
    "#,
    );
    assert!(
        !out.contains("auto&& new :") && !out.contains("std::move(new)"),
        "keyword-named loop bindings must be escaped at decl and use:\n{out}"
    );
    assert!(out.contains("new_"), "{out}");
}

#[test]
fn test_guarded_match_with_early_fn_return_lowers_to_statement_expr() {
    // indexmap's try_simplify_range: a guarded Bound match whose `_` arm
    // RETURNS FROM THE FUNCTION (`return None`, type Option<Range<usize>>)
    // while the match itself yields usize. The IIFE-lambda lowering binds the
    // `return` to the lambda ("no viable conversion from Option<...> to
    // size_t"); the runtime-match delegation must route it to the
    // statement-expression lowering where `return` stays a function return.
    let out = transpile_str(
        r#"
        use core::ops::{Bound, Range, RangeBounds};
        pub(crate) fn try_simplify_range<R>(range: R, len: usize) -> Option<Range<usize>>
        where
            R: RangeBounds<usize>,
        {
            let start = match range.start_bound() {
                Bound::Unbounded => 0,
                Bound::Included(&i) if i <= len => i,
                Bound::Excluded(&i) if i < len => i + 1,
                _ => return None,
            };
            let end = match range.end_bound() {
                Bound::Unbounded => len,
                Bound::Excluded(&i) if i <= len => i,
                Bound::Included(&i) if i < len => i + 1,
                _ => return None,
            };
            if start > end {
                return None;
            }
            Some(start..end)
        }
    "#,
    );
    assert!(
        out.contains("const auto start = ({"),
        "guarded early-return match must lower to a statement expression:\n{out}"
    );
    assert!(
        !out.contains("-> size_t { auto&& _m"),
        "the IIFE-lambda lowering must not host the function-level return:\n{out}"
    );
}

#[test]
fn test_bare_owner_args_resolve_via_module_subtree_not_global_bare_key() {
    // indexmap's set module: `Slice::from_slice(..)` written under `mod set`
    // must recover set::slice::Slice's params (<T>), not the globally-bare
    // key's first registrant (map's 2-param Slice<K, V>) — which fabricated
    // `Slice<T, S>` ("too many template arguments for class template").
    let out = transpile_str(
        r#"
        pub mod map {
            pub mod slice {
                pub struct Slice<K, V> {
                    pub entries: Vec<(K, V)>,
                }
            }
        }
        pub mod set {
            pub mod slice {
                pub struct Slice<T> {
                    pub entries: Vec<T>,
                }
                impl<T> Slice<T> {
                    pub(crate) fn from_slice(entries: Vec<T>) -> Self {
                        Slice { entries }
                    }
                }
            }
            use self::slice::Slice;
            pub struct IndexSet<T, S> {
                entries: Vec<T>,
                hasher: S,
            }
            impl<T, S> IndexSet<T, S> {
                pub fn as_slice(&self) -> Slice<T> {
                    Slice::from_slice(self.entries.clone())
                }
            }
        }
    "#,
    );
    assert!(
        !out.contains("Slice<T, S>::from_slice"),
        "bare owner must not recover the wrong module's param arity:\n{out}"
    );
    assert!(
        out.contains("Slice<T>::from_slice"),
        "bare owner must resolve to the current module subtree's Slice<T>:\n{out}"
    );
}

#[test]
fn test_module_topo_by_value_dep_wins_over_subtree_name_noise() {
    // serde_yaml shape: `mod error` holds `libyaml::error::Mark` BY VALUE
    // (genuine hard edge error → libyaml), while `mod libyaml` contains only
    // subtree-local name noise that used to fabricate REVERSE edges — a
    // `use self::error::…` (alias recorder read `self` like `crate` and
    // matched its own nested `error` against the ROOT `error` module) and a
    // locally-declared `Mapping` matching a crate re-export of a sibling
    // module's type. The false cycle forced source-order fallback and `mod
    // error`'s struct saw an incomplete `Mark`.
    let out = transpile_str(
        r#"
        mod error {
            use crate::libyaml::error as libyaml;
            pub(crate) struct Pos {
                mark: libyaml::Mark,
                path: u64,
            }
        }
        mod libyaml {
            pub(crate) mod error {
                pub(crate) struct Mark {
                    pub index: u64,
                }
            }
            pub(crate) mod emitter {
                pub(crate) struct Mapping {
                    pub anchor: u64,
                }
                pub(crate) enum Event {
                    MappingStart(Mapping),
                }
            }
            use self::error::Mark;
            pub(crate) fn probe() -> Mark {
                Mark { index: 0 }
            }
        }
        pub mod mapping {
            pub struct Mapping {
                pub len: u64,
            }
        }
        pub use crate::mapping::Mapping;
    "#,
    );
    let mark_def = out
        .find("struct Mark {")
        .expect("Mark definition missing from output");
    let pos_def = out
        .find("struct Pos {")
        .expect("Pos definition missing from output");
    assert!(
        mark_def < pos_def,
        "by-value dep must order Mark's definition before Pos's:\n{out}"
    );
}

#[test]
fn test_grouped_use_rename_does_not_pollute_sibling_or_crate_rooted_paths() {
    // serde_yaml's `mod error`: `use crate::libyaml::{emitter, error as
    // libyaml};` — a grouped use whose RENAME member shadows the root
    // `libyaml` module for expression paths. Two corruptions guarded here:
    // (1) the SIBLING member's target `libyaml::emitter` re-resolved through
    // the rename → `namespace emitter = ::libyaml::error::emitter;`
    // (use-targets are crate-rooted; the rename never applies); (2) a
    // `crate::…` path re-entering emit_path_to_string re-resolved its head
    // through the scope-chain binding → the stuttered
    // `::libyaml::error::error::Error`. Needs a SECOND type named `Error`
    // in the crate (libyaml::emitter::Error) to reproduce — with one, the
    // accidental agreement hid it.
    let out = transpile_str(
        r#"
        mod error {
            use crate::libyaml::{emitter, error as libyaml};
            pub(crate) enum ErrorImpl {
                Libyaml(libyaml::Error),
                Emit(emitter::Error),
                Other(u64),
            }
            pub(crate) fn wrap(e: libyaml::Error) -> ErrorImpl {
                ErrorImpl::Libyaml(e)
            }
        }
        mod libyaml {
            pub(crate) mod emitter {
                pub(crate) enum Error {
                    Broken(u64),
                }
            }
            pub(crate) mod error {
                pub(crate) struct Error {
                    pub code: u64,
                }
            }
        }
    "#,
    );
    assert!(
        !out.contains("error::error::Error"),
        "crate-rooted path must not re-resolve through the scope-local rename (stutter):\n{out}"
    );
    assert!(
        !out.contains("namespace emitter = ::libyaml::error::emitter;"),
        "sibling group member must bind to the real module, not through the rename:\n{out}"
    );
    assert!(
        out.contains("namespace emitter = ::libyaml::emitter;"),
        "sibling group member must emit the crate-rooted namespace alias:\n{out}"
    );
    assert!(
        out.contains("wrap(::libyaml::error::Error e)"),
        "renamed-alias param must spell the absolute un-stuttered type:\n{out}"
    );
}

#[test]
fn test_scope_bound_reexport_resolution_spells_absolute_path() {
    // The variant field `libyaml::Error` resolves through `mod libyaml`'s
    // OWN `use self::error::Error;` re-export (try_map_scope_bound_type_path
    // consults the OTHER module's scope bindings) — crate-global knowledge,
    // so the spelling must be absolute. The relative `libyaml::error::Error`
    // it used to emit was hijacked wherever a same-named local C++ namespace
    // alias is in scope (serde_yaml's `mod error`).
    let out = transpile_str(
        r#"
        mod error {
            pub(crate) enum ErrorImpl {
                Libyaml(libyaml::Error),
            }
            pub(crate) struct Pos {}
        }
        mod libyaml {
            pub(crate) mod emitter {
                pub(crate) enum Error {}
            }
            pub(crate) mod error {
                pub(crate) struct Error {}
                pub(crate) struct Mark {}
            }
            use self::error::Error;
        }
    "#,
    );
    assert!(
        out.contains("::libyaml::error::Error _0;"),
        "re-export-resolved variant field must be absolute:\n{out}"
    );
    assert!(
        !out.contains(" libyaml::error::Error _0;"),
        "re-export-resolved variant field must not be relative:\n{out}"
    );
}

#[test]
fn test_reexport_import_chases_to_canonical_declaration() {
    // value/ser.rs imports `Mapping` THROUGH value.rs's `pub use crate::
    // mapping::Mapping;` — the binding target says `value::Mapping`, but
    // namespace value also holds Value's bare-named variant factory fn
    // `Mapping(...)`, which hides the re-export using-declaration in type
    // contexts ("template argument for template type parameter must be a
    // type"). The single-segment import mapping must chase the re-export to
    // the canonical `::mapping::Mapping`.
    let out = transpile_str(
        r#"
        pub mod mapping {
            pub struct Mapping {
                pub len: u64,
            }
        }
        pub mod value {
            pub use crate::mapping::Mapping;
            pub enum Value {
                Null,
                Mapping(u64),
            }
            mod ser {
                use crate::value::{Mapping, Value};
                pub enum SerializeMap {
                    CheckForTag,
                    Untagged { mapping: Mapping, next_key: Option<Value> },
                }
            }
        }
    "#,
    );
    assert!(
        out.contains("::mapping::Mapping mapping;"),
        "re-export import must spell the canonical absolute declaration:\n{out}"
    );
    assert!(
        !out.contains("value::Mapping mapping;"),
        "re-export import must not spell the re-exporting namespace:\n{out}"
    );
}

#[test]
fn test_self_expanding_alias_rewrite_spells_absolute_path() {
    // `use crate::libyaml::error as libyaml;` inside `mod error`: expanding
    // `libyaml::Error` to the full module path yields a RELATIVE spelling
    // whose first segment re-resolves through the same-named C++ namespace
    // alias emitted for the Rust `use` (`namespace libyaml =
    // ::libyaml::error;`) → `(::libyaml::error)::error::Error` — "no member
    // named 'error'". The expansion must be absolute-qualified.
    let out = transpile_str(
        r#"
        mod error {
            use crate::libyaml::error as libyaml;
            pub(crate) struct ErrorImplLibyaml {
                inner: libyaml::Error,
            }
            pub(crate) fn wrap(err: libyaml::Error) -> ErrorImplLibyaml {
                ErrorImplLibyaml { inner: err }
            }
        }
        mod libyaml {
            pub(crate) mod error {
                pub(crate) struct Error {
                    pub code: u64,
                }
            }
        }
    "#,
    );
    let mut relative_sites = Vec::new();
    let mut search_from = 0usize;
    while let Some(pos) = out[search_from..].find("libyaml::error::Error") {
        let abs = search_from + pos;
        let preceded_by_colon = abs >= 2 && &out[abs - 2..abs] == "::";
        if !preceded_by_colon {
            let line = out[..abs].matches('\n').count() + 1;
            relative_sites.push(line);
        }
        search_from = abs + 1;
    }
    assert!(
        relative_sites.is_empty(),
        "expanded alias paths must be absolute (::libyaml::error::Error); found relative spellings at lines {relative_sites:?}:\n{out}"
    );
    assert!(
        out.contains("::libyaml::error::Error"),
        "expanded alias path should still appear, absolutely qualified:\n{out}"
    );
}

