#[test]
fn test_leaf5133_self_path_mut_reference_expected_coerces_to_deref_mut() {
    let out = transpile_str(
        r#"
        struct Buf {}
        impl Buf {
            fn deref_mut(&mut self) -> &mut [i32] { todo!() }
            fn as_mut(&mut self) -> &mut [i32] { self }
            fn borrow_mut(&mut self) -> &mut [i32] { self }
            fn alias_mut(&mut self) -> &mut Self { self }
        }
    "#,
    );
    // `deref_mut` may be a body that returns `this->deref_mut()` or
    // (when DerefMut is emitted as operator*()) `this->operator*()`,
    // or it may just be a stub-typed body (todo!).
    assert!(
        out.contains("return this->deref_mut();")
            || out.contains("return this->operator*();")
            || out.contains(
                "return throw std::logic_error(\"not yet implemented\");"
            ),
        "{out}"
    );
    // Methods may be inline `<ret> as_mut() {` or out-of-line `<ret> Buf::as_mut() {`.
    assert!(
        out.contains("std::span<int32_t> as_mut() {")
            || out.contains("std::span<int32_t> Buf::as_mut() {"),
        "{out}"
    );
    assert!(
        out.contains("std::span<int32_t> borrow_mut() {")
            || out.contains("std::span<int32_t> Buf::borrow_mut() {"),
        "{out}"
    );
    assert!(
        out.contains("Buf& alias_mut() {") || out.contains("Buf& Buf::alias_mut() {"),
        "{out}"
    );
    assert!(out.contains("return (*this);"), "{out}");
}

#[test]
