#[test]
fn test_impl_const_with_same_named_module_const_qualifies_outer_path() {
    let out = transpile_str(
        r#"
        mod spanned {
            const START_FIELD: &str = "start";
            struct Spanned;
            impl Spanned {
                const START_FIELD: &'static str = START_FIELD;
            }
        }
        "#,
    );
    // String-view coercion may go through the explicit constructor cast
    // (`std::string_view(...)`) or the runtime helper (`rusty::to_string_view(...)`).
    assert!(
        out.contains("static constexpr std::string_view START_FIELD = std::string_view(::spanned::START_FIELD);")
            || out.contains("static constexpr std::string_view START_FIELD = rusty::to_string_view(::spanned::START_FIELD);"),
        "{out}"
    );
}

