#[test]
fn test_drop_in_place_mut_slice_view_passes_range_not_temporary_address() {
    let expr: syn::Expr = syn::parse_str("ptr::drop_in_place(&mut self[..])").unwrap();
    let call = match expr {
        syn::Expr::Call(call) => call,
        _ => panic!("expected call expression"),
    };
    let cg = CodeGen::new();
    let out = cg.emit_call_expr_to_string(&call, None);
    assert!(
        out.contains("drop_in_place(rusty::slice_full((*this)))"),
        "slice-view drop should pass the range object, got:\n{}",
        out
    );
    assert!(
        !out.contains("&rusty::slice_full"),
        "slice-view drop should not take the address of a temporary span, got:\n{}",
        out
    );
}

#[test]
fn test_mem_swap_mut_deref_args_pass_lvalue_references() {
    let expr: syn::Expr = syn::parse_str("mem::swap(&mut *p_r, &mut *p_w)").unwrap();
    let call = match expr {
        syn::Expr::Call(call) => call,
        _ => panic!("expected call expression"),
    };
    let cg = CodeGen::new();
    let out = cg.emit_call_expr_to_string(&call, None);
    assert!(
        out.contains("swap(rusty::detail::deref_if_pointer_like(p_r), rusty::detail::deref_if_pointer_like(p_w))")
            || out.contains("swap(*p_r, *p_w)"),
        "mem::swap should receive pointee lvalue expressions, got:\n{}",
        out
    );
    assert!(
        !out.contains("swap(&*p_r"),
        "mem::swap should not receive pointer values for borrowed deref args, got:\n{}",
        out
    );
}

#[test]
fn test_leaf5119_unreachable_unchecked_paths_are_diverging() {
    assert!(CodeGen::is_diverging_function_path("unreachable_unchecked"));
    assert!(CodeGen::is_diverging_function_path(
        "hint::unreachable_unchecked"
    ));
    assert!(CodeGen::is_diverging_function_path(
        "core::hint::unreachable_unchecked"
    ));
    assert!(CodeGen::is_diverging_function_path(
        "std::hint::unreachable_unchecked"
    ));
    assert!(CodeGen::is_diverging_function_path(
        "alloc::alloc::handle_alloc_error"
    ));
    assert!(CodeGen::is_diverging_function_path(
        "core::alloc::handle_alloc_error"
    ));
    assert!(CodeGen::is_diverging_function_path(
        "std::alloc::handle_alloc_error"
    ));
}

#[test]
fn test_leaf5119_unsafe_tail_match_keeps_value_return_path() {
    let out = transpile_str(
        r#"
        use core::hint::unreachable_unchecked;

        enum Data {
            Inline(i32),
            Heap { ptr: i32, len: usize },
        }

        unsafe fn heap(d: &Data) -> (i32, usize) {
            match d {
                Data::Heap { ptr, len } => (*ptr, *len),
                _ => {
                    if true {
                        ::core::panicking::panic("entered unreachable code");
                    } else {
                        unreachable_unchecked();
                    }
                }
            }
        }
        "#,
    );
    // Match dispatch may use legacy `std::visit(overloaded { ... })`
    // or current index-based dispatch (IIFE with arm returns or stmt-expr
    // accumulator with `_match_value.emplace`).
    assert!(
        out.contains("return [&]() { auto&& _m = d; return std::visit(overloaded {")
            || (out.contains("auto&& _m = d;") && out.contains(") == ")),
        "{out}"
    );
    assert!(
        out.contains(
            "static_cast<void>([&]() { if (true) { rusty::panicking::panic(\"entered unreachable code\"); } else { rusty::intrinsics::unreachable(); } }())"
        ) || (out.contains("rusty::panicking::panic(\"entered unreachable code\")")
            && out.contains("rusty::intrinsics::unreachable()")),
        "{out}"
    );
    assert!(
        out.contains(
            "[&]() -> std::tuple<int32_t, size_t> { rusty::intrinsics::unreachable(); }()"
        ),
        "{out}"
    );
}

#[test]
fn test_unit_variant_match_infers_common_data_enum_owner_with_unsafe_unreachable() {
    let out = transpile_str(
        r#"
        enum CharEscape {
            Backspace,
            Tab,
            AsciiControl(u8),
        }

        fn f(escape: u8, byte: u8) -> CharEscape {
            match escape {
                0 => CharEscape::Backspace,
                1 => CharEscape::Tab,
                2 => CharEscape::AsciiControl(byte),
                _ => unsafe { core::hint::unreachable_unchecked() },
            }
        }
        "#,
    );
    assert!(
        out.contains("std::optional<CharEscape> _match_value;"),
        "{out}"
    );
    assert!(
        out.contains("_match_value.emplace(std::move(CharEscape{CharEscape_Backspace{}}));"),
        "{out}"
    );
    assert!(
        out.contains("_match_value.emplace(std::move(CharEscape{CharEscape_Tab{}}));"),
        "{out}"
    );
    assert!(
        out.contains("[&]() -> CharEscape { rusty::intrinsics::unreachable(); }();"),
        "{out}"
    );
}

