#[test]
fn test_leaf5130_iter_map_untyped_param_single_deref_collapses_in_map_context() {
    let out = transpile_str(
        r#"
        fn f(v: [u8; 3]) -> Vec<u8> {
            v.iter().map(|v| *v).collect::<Vec<_>>()
        }
        "#,
    );
    // The mapper may or may not carry an explicit return annotation /
    // std::move wrap (the expected element type now flows into the closure —
    // see `try_emit_iter_map_call`); the invariant is that the copy-deref
    // `*v` collapsed to a pass-through.
    assert!(out.contains("rusty::map(rusty::iter(v), [&](auto&& v)"), "{out}");
    assert!(
        out.contains("{ return v; }") || out.contains("{ return std::move(v); }"),
        "{out}"
    );
    assert!(!out.contains("return *v;"), "{out}");
}

#[test]
fn test_leaf5130_iter_map_untyped_param_double_deref_collapses_one_layer() {
    let out = transpile_str(
        r#"
        fn f(v: Vec<Box<u8>>) -> Vec<u8> {
            v.iter().map(|v| **v).collect::<Vec<_>>()
        }
        "#,
    );
    // Double-deref `**v` may be `return *v;` (one collapsed) or
    // `return rusty::detail::deref_if_pointer_like(v);` (runtime helper).
    // The mapper may carry an explicit return annotation (the expected element
    // type now flows into the closure — see `try_emit_iter_map_call`).
    assert!(out.contains("rusty::map(rusty::iter(v), [&](auto&& v)"), "{out}");
    assert!(
        out.contains("{ return *v; }")
            || out.contains("{ return rusty::detail::deref_if_pointer_like(v); }"),
        "{out}"
    );
    assert!(!out.contains("return **v;"), "{out}");
}

#[test]
fn test_leaf5298_untyped_closure_param_deref_lowers_via_deref_mut_helper() {
    let out = transpile_str(
        r#"
        fn apply(mut f: impl FnMut(&mut i32)) {
            let mut x = 0;
            f(&mut x);
        }
        fn g() {
            apply(|elt| {
                *elt += 1;
            });
        }
        "#,
    );
    assert!(
        out.contains("rusty::deref_mut(elt) += 1;"),
        "untyped closure deref should lower through reference-aware helper, got:\n{}",
        out
    );
    assert!(
        !out.contains("*elt += 1;"),
        "raw pointer-style unary deref should not be emitted for untyped closure refs, got:\n{}",
        out
    );
}

#[test]
fn test_field_stored_closure_call_passes_borrow_as_reference() {
    // Calling a struct field that holds a closure — `(self.dropfn)(&mut self.value)`
    // — must pass the borrow as a C++ reference bind, NOT address-of. The closure
    // body accesses the param via dot (`self_.bump()`), so the `auto&&` param must
    // deduce a reference, not a pointer. (hashbrown's ScopeGuard::drop pattern.)
    let out = transpile_str(
        r#"
        struct Inner { n: usize }
        impl Inner { fn bump(&self) -> usize { self.n } }
        struct ScopeGuard<T, F: FnMut(&mut T)> { value: T, dropfn: F }
        impl<T, F: FnMut(&mut T)> Drop for ScopeGuard<T, F> {
            fn drop(&mut self) {
                (self.dropfn)(&mut self.value);
            }
        }
        "#,
    );
    assert!(
        out.contains("(this->dropfn)(this->value)"),
        "field-stored closure call should reference-bind the borrow, got:\n{}",
        out
    );
    assert!(
        !out.contains("(this->dropfn)(&this->value)"),
        "field-stored closure call must not take the address of the borrow, got:\n{}",
        out
    );
}

#[test]
fn test_method_call_borrow_arg_unaffected_by_field_closure_rule() {
    // Negative guard: a real METHOD call (`x.method(&mut y)`, syntactically an
    // Expr::MethodCall, not Expr::Call over Expr::Field) must NOT be rewritten by
    // the field-closure reference-bind rule.
    let out = transpile_str(
        r#"
        struct W { v: i32 }
        impl W { fn take(&self, other: &mut i32) { let _ = (other, self.v); } }
        fn run(w: &W) {
            let mut y = 3;
            w.take(&mut y);
        }
        "#,
    );
    // The call still resolves to a normal method invocation on `w`.
    assert!(
        out.contains("w.take(") || out.contains(".take("),
        "method call should be emitted normally, got:\n{}",
        out
    );
}

