#[test]
fn test_runtime_deserialize_any_probe_is_pointer_safe() {
    let helpers = runtime_path_fallback_helpers_text();
    assert!(helpers.contains(
        "rusty::detail::deref_if_pointer_like(std::forward<Deserializer>(deserializer))\n\
        .deserialize_any(std::forward<Visitor>(visitor));"
    ));
    assert!(
        helpers.contains(
            "requires (!std::is_void_v<decltype(rusty::detail::deref_if_pointer_like("
        )
    );

    let local_helpers = runtime_path_fallback_helpers_text_for_local_token_module();
    assert!(local_helpers.contains(
        "requires (!std::is_void_v<decltype(std::forward<Deserializer>(deserializer)"
    ));
    assert!(
        local_helpers.contains(
            "requires (!std::is_void_v<decltype(rusty::detail::deref_if_pointer_like("
        )
    );
}

#[test]
fn test_runtime_serialize_bytes_normalizes_before_token_fallback() {
    let helpers = runtime_path_fallback_helpers_text();
    let normalized = "std::forward<Serializer>(serializer).serialize_bytes(\n\
        rusty::as_u8_slice(rusty::detail::deref_if_pointer_like(\n\
            std::forward<BytesLike>(bytes))));";
    let normalized_pos = helpers
        .find(normalized)
        .expect("serialize_bytes helper should normalize byte-like values");
    let token_fallback_pos = helpers
        .find(
            "rusty::detail::deref_if_pointer_like(std::forward<Serializer>(serializer)).next_token();",
        )
        .expect("serialize_bytes helper should retain token fallback");
    assert!(normalized_pos < token_fallback_pos);
}

#[test]
fn test_runtime_serialize_value_dispatches_scalars_by_exact_category() {
    let helpers = runtime_path_fallback_helpers_text();

    assert!(
        helpers.contains("using ValueType = std::remove_cv_t<std::remove_reference_t<Value>>;")
    );
    assert!(helpers.contains("std::is_same_v<ValueType, bool> && requires"));
    assert!(
        helpers.contains(
            "!std::is_same_v<ValueType, bool> && sizeof(ValueType) <= sizeof(uint8_t)"
        )
    );
    let adl_pos = helpers
        .find("serialize(std::forward<Value>(value), std::forward<Serializer>(serializer));")
        .expect("serialize_value should probe ADL free serialize functions");
    let member_fallback_pos = helpers
        .rfind(
            "return std::forward<Value>(value).serialize(std::forward<Serializer>(serializer));",
        )
        .expect("serialize_value should retain member fallback");
    assert!(adl_pos < member_fallback_pos);
    assert!(
        !helpers.contains("} else if constexpr (requires {\n        std::forward<Serializer>(serializer).serialize_bool(std::forward<Value>(value));")
    );
}

#[test]
fn test_runtime_deserialize_prefers_deserializer_any_before_token_fallbacks() {
    let helpers = runtime_path_fallback_helpers_text();
    assert!(helpers.contains("struct scalar_visitor {"));
    assert!(helpers.contains("std::is_constructible_v<Value, V&&>"));
    assert!(helpers.contains("std::is_enum_v<RawValue> && std::is_integral_v<RawInput>"));
    assert!(helpers.contains("std::is_arithmetic_v<Target> || std::is_enum_v<Target>"));
    assert!(helpers.contains("RawValue::Other"));
    assert!(helpers.contains("struct option_visitor {"));

    let scalar_any_pos = helpers
        .find("detail::scalar_visitor<Target>{});")
        .expect("scalar targets should have a deserialize_any visitor path");
    let numeric_token_pos = helpers
        .find("Err::custom(\"expected numeric token\")")
        .expect("numeric token fallback should remain");
    assert!(scalar_any_pos < numeric_token_pos);

    let bytes_any_pos = helpers
        .find(
            "detail::bytes_span_visitor{});\n\
        requires (",
        )
        .expect("bytes targets should have a deserialize_any visitor path");
    let bytes_token_pos = helpers
        .find("Target::new_(std::declval<std::span<const uint8_t>>())")
        .expect("bytes token fallback should remain");
    assert!(bytes_any_pos < bytes_token_pos);

    let option_method_pos = helpers
        .find(".deserialize_option(detail::option_visitor<Target>{});")
        .expect("option targets should prefer deserialize_option");
    let option_token_pos = helpers
        .find("Err::custom(\"expected option token\")")
        .expect("option token fallback should remain");
    assert!(option_method_pos < option_token_pos);
}

#[test]
fn test_serde_invalid_length_dependent_error_owner_uses_typename_template_arg() {
    let out = transpile_str(
        r#"
        mod de {
            pub trait Expected {}
            pub trait Error {
                fn invalid_length(len: usize, expected: &dyn Expected) -> Self;
            }
        }

        trait Visitor {
            type Error;
        }

        fn f<V: Visitor>(idx: usize, expected: &dyn de::Expected) -> Result<(), V::Error> {
            Err(de::Error::invalid_length(idx, expected))
        }
        "#,
    );

    assert!(
        out.contains("rusty::error::invalid_length<typename V::Error>("),
        "dependent associated error owner must be a valid C++ template type arg:\n{}",
        out
    );
    assert!(
        !out.contains("rusty::error::invalid_length<V::Error>("),
        "dependent associated error owner without typename is invalid C++:\n{}",
        out
    );
}

#[test]
fn test_deserialize_trait_call_preserves_explicit_mut_deserializer_borrow() {
    let out = transpile_str(
        r#"
        trait Deserialize: Sized {
            fn deserialize<D>(deserializer: D) -> Result<Self, ()>;
        }

        struct Deserializer;

        fn f<T: Deserialize>(mut de: Deserializer) -> Result<T, ()> {
            T::deserialize(&mut de)
        }
        "#,
    );

    assert!(
        out.contains("::de::rusty_ext::deserialize(rusty::PhantomData<T>{}, &de)"),
        "T::deserialize(&mut de) must pass the mutable deserializer by address, got:\n{}",
        out
    );
    assert!(
        !out.contains("::de::rusty_ext::deserialize(rusty::PhantomData<T>{}, de)"),
        "erasing &mut de copies the deserializer cursor, got:\n{}",
        out
    );
}

