#[test]
fn test_leaf1051_try_style_runtime_ident_binding_uses_shadowed_cpp_name() {
    let out = transpile_str(
        r#"
        fn f(rhs: Option<i32>, v: Vec<i32>) -> i32 {
            let rhs = rhs;
            for x in v {
                let rhs = match rhs {
                    Some(rhs) => rhs,
                    None => return 0,
                };
                return rhs;
            }
            0
        }
    "#,
    );
    // The inner `rhs` binding must be renamed (to avoid colliding with
    // the outer `rhs`) and bound to `_mv`, either directly or through
    // one/two layers of `rusty::detail::deref_if_pointer` for safety
    // with reference scrutinees.
    let direct = out.contains("auto&& rhs_shadow1 = _mv;");
    let wrapped_once =
        out.contains("auto&& rhs_shadow1 = rusty::detail::deref_if_pointer(_mv);");
    let wrapped_twice = out.contains(
        "auto&& rhs_shadow1 = rusty::detail::deref_if_pointer(rusty::detail::deref_if_pointer(_mv));",
    );
    assert!(direct || wrapped_once || wrapped_twice, "{out}");
    // The arm tail expression must reference the shadowed binding (or
    // forward _mv directly under the wrapped-shadow shape).
    let emplace_named = out.contains("_match_value.emplace(std::move(rhs_shadow1));");
    let emplace_forwarded =
        out.contains("_match_value.emplace(std::forward<decltype(_mv)>(_mv));");
    assert!(emplace_named || emplace_forwarded, "{out}");
    assert!(!out.contains("auto&& rhs = _mv; _match_value.emplace(std::move(rhs_shadow1));"));
}

