#[test]
fn test_leaf1051_try_style_runtime_tuple_binding_uses_shadowed_cpp_names() {
    let out = transpile_str(
        r#"
        fn f(pair: Option<(i32, i32)>, v: Vec<i32>, lhs: i32, rhs: i32) -> i32 {
            let lhs = lhs;
            let rhs = rhs;
            for x in v {
                let lhs = match pair {
                    Some((lhs, rhs)) => lhs + rhs,
                    None => return 0,
                };
                return lhs;
            }
            0
        }
    "#,
    );
    // Inner tuple-pattern bindings must be shadowed under unique names
    // and extracted from `_mv` via `std::get<N>`, with or without
    // `rusty::detail::deref_if_pointer` wrapping for reference safety.
    let bare_lhs = out.contains("auto&& lhs_shadow1 = std::get<0>(_mv);");
    let bare_rhs = out.contains("auto&& rhs_shadow1 = std::get<1>(_mv);");
    let wrapped_lhs =
        out.contains("auto&& lhs_shadow1 = rusty::detail::deref_if_pointer(std::get<0>(");
    let wrapped_rhs =
        out.contains("auto&& rhs_shadow1 = rusty::detail::deref_if_pointer(std::get<1>(");
    assert!(bare_lhs || wrapped_lhs, "{out}");
    assert!(bare_rhs || wrapped_rhs, "{out}");
    // The arm tail must reference the shadowed bindings, either with
    // bare names or via `rusty::detail::deref_if_pointer_like` wrappers.
    let bare_tail = out.contains("lhs_shadow1 + rhs_shadow1");
    let wrapped_tail = out.contains(
        "rusty::detail::deref_if_pointer_like(lhs_shadow1) + rusty::detail::deref_if_pointer_like(rhs_shadow1)",
    );
    assert!(bare_tail || wrapped_tail, "{out}");
    assert!(out.contains("_match_value.emplace("), "{out}");
}

#[test]
fn test_leaf1051_try_style_runtime_struct_binding_uses_shadowed_cpp_names() {
    let out = transpile_str(
        r#"
        struct Pair { left: i32, right: i32 }
        fn g(opt: Option<Pair>, v: Vec<i32>, left: i32, right: i32) -> i32 {
            let left = left;
            let right = right;
            for x in v {
                let left = match opt {
                    Some(Pair { left, right }) => left + right,
                    None => return 0,
                };
                return left;
            }
            0
        }
    "#,
    );
    // The struct-field extraction may go through `deref_if_pointer`
    // wraps for reference-of-reference scrutinees.
    assert!(
        out.contains("auto&& left_shadow1 = _mv.left;")
            || (out.contains("auto&& left_shadow1 = ") && out.contains("_mv).left")),
        "{out}"
    );
    assert!(
        out.contains("auto&& right_shadow1 = _mv.right;")
            || (out.contains("auto&& right_shadow1 = ") && out.contains("_mv).right")),
        "{out}"
    );
    // The emplace may also wrap operands in deref_if_pointer_like; both
    // shapes preserve `left_shadow1 + right_shadow1` as the arithmetic.
    assert!(
        out.contains("_match_value.emplace(std::move(left_shadow1 + right_shadow1));")
            || (out.contains("_match_value.emplace(std::move(")
                && out.contains("left_shadow1")
                && out.contains("+")
                && out.contains("right_shadow1")),
        "{out}"
    );
}

