/// Regression repro for the deferred-init `auto X;` bug.
///
/// Rust's `let x; unsafe { x = expr; }` pattern is the canonical
/// shape for "I'll initialize this later, possibly via unsafe code"
/// (linked_list_port::split_off_before_node uses it twice). When
/// the RHS expression is a method chain the transpiler can't
/// statically type (e.g. `recv.as_mut().field.take()`), the
/// placeholder-hint path doesn't pick anything up and the emit
/// falls through to bare `auto first_part_tail;` which C++ rejects.
/// The expected fix: defer the uninitialized declaration and
/// merge it with the first assignment.
#[test]
fn test_deferred_init_let_merges_with_first_assignment() {
    let out = transpile_str(
        r#"
        use core::ptr::NonNull;
        struct Node<T> { prev: Option<NonNull<Node<T>>>, element: T }
        fn f<T>(mut node: NonNull<Node<T>>) {
            let first_part_tail;
            unsafe {
                first_part_tail = node.as_mut().prev.take();
            }
            let _ = first_part_tail;
        }
        "#,
    );
    assert!(
        !out.contains("auto first_part_tail;"),
        "deferred-init local emitted as `auto X;` (no initializer):\n{out}"
    );
    // The materialized declaration MUST live at the outer scope so
    // subsequent uses (the `let _ = first_part_tail;` after the
    // unsafe block) see it, NOT bare-uninitialized. Two valid forms:
    //   - merge-into-`auto`: `auto first_part_tail = <rhs>;` (used when the
    //     first-assignment RHS is statically un-typeable), or
    //   - typed deferred storage: `std::optional<T> first_part_tail;` at the
    //     outer scope + `.emplace(<rhs>)` in the unsafe block (used when the
    //     RHS type IS resolvable — here `node.as_mut().prev.take()` resolves
    //     to `Option<NonNull<Node<T>>>` via struct-field type inference).
    assert!(
        out.contains("auto first_part_tail = ")
            || out.contains("> first_part_tail;"),
        "deferred-init local declaration not materialized at outer scope:\n{out}"
    );
    // The substring `{\n    auto first_part_tail = ` would mean
    // the materialization happened INSIDE the unsafe braces,
    // shadowing the outer-scope use. Reject.
    assert!(
        !out.contains("{\n    auto first_part_tail = "),
        "merged emit nested inside unsafe block scope:\n{out}"
    );
}

/// Regression repro for the linked_list_port struct-literal misrouting.
/// `let x = LinkedList { head, tail, len, alloc, marker };` inside a
/// method body that *also* uses Rust's deferred-init pattern
/// (`let x; unsafe { x = expr; }`) emitted `rusty::Vec<T, A>{...}`
/// because the `LinkedList → rusty::Vec` fallback alias in
/// `types.rs:118` shadows the local struct's name when the
/// transpiler walks the literal during deferred-init lowering.
///
/// The dedicated `linked_list_port` module supersedes that fallback,
/// so the local `LinkedList` struct definition should win — the
/// emit should be `LinkedList<T, A>{...}`.
#[test]
fn test_linked_list_struct_literal_keeps_local_type_name() {
    let out = transpile_str(
        r#"
        use core::marker::PhantomData;
        use core::ptr::NonNull;

        struct Node<T> { element: T }

        pub struct LinkedList<T, A: Clone> {
            head: Option<NonNull<Node<T>>>,
            tail: Option<NonNull<Node<T>>>,
            len: usize,
            alloc: A,
            marker: PhantomData<Box<Node<T>>>,
        }

        impl<T, A: Clone> LinkedList<T, A> {
            pub fn split_off_before_node(
                &mut self,
                split_node: Option<NonNull<Node<T>>>,
                at: usize,
            ) -> Self {
                if let Some(mut split_node) = split_node {
                    let first_part_head;
                    let first_part_tail;
                    unsafe {
                        first_part_tail = split_node.as_mut().element;
                    }
                    if let Some(_) = first_part_tail {
                        first_part_head = self.head;
                    } else {
                        first_part_head = None;
                    }
                    let first_part = LinkedList {
                        head: first_part_head,
                        tail: first_part_tail,
                        len: at,
                        alloc: self.alloc.clone(),
                        marker: PhantomData,
                    };
                    first_part
                } else {
                    unimplemented!()
                }
            }
        }
        "#,
    );
    assert!(
        !out.contains("rusty::Vec<T, A>"),
        "LinkedList struct literal mis-routed to rusty::Vec:\n{out}"
    );
    assert!(
        out.contains("LinkedList<T, A>{"),
        "LinkedList<T, A>{{...}} not in output:\n{out}"
    );
}

/// Regression repro for the linked_list_port transpile bug. The Rust
/// pattern `Box::new_in(Node::new(elt), &alloc)` (elided Box generics,
/// arg is a typed constructor call) currently emits `Box<auto>::new_in`,
/// which is ill-formed in C++ (`auto` can't appear as a template
/// argument). The fix should substitute the arg's type for the
/// elided generic: `Box<Node<T>>::new_in(...)`.
///
/// This test starts as failing; the transpiler patch that closes the
/// linked_list_port Phase B blocker should make it pass.
#[test]
fn test_linked_list_box_new_in_with_typed_arg_infers_explicit_generic() {
    let out = transpile_str(
        r#"
        struct Node<T> { elt: T }
        impl<T> Node<T> {
            fn new(elt: T) -> Self { Node { elt } }
        }
        fn make_node<T, A>(elt: T, alloc: A) {
            let _ = Box::new_in(Node::new(elt), alloc);
        }
        "#,
    );
    // The fix should drop the `<auto>` placeholder entirely.
    assert!(
        !out.contains("Box<auto>::new_in"),
        "Box::new_in emitted with <auto> template arg:\n{out}"
    );
}

/// Regression repro for the post-fbb44ce `Box::new_in` owner-template
/// regression: when `Box::new_in(value, alloc)` appears INSIDE an
/// `impl Self<...>` block, the recovery substitutes the enclosing
/// impl Self's template params (e.g. `Box<LinkedList<T, A>>`) for the
/// elided Box generic, instead of inferring from the value arg's
/// type. Correct emit should yield `Box<Node<...>>::new_in(...)`
/// since the first arg is `Node::new(elt)`.
#[test]
fn test_box_new_in_inside_impl_block_infers_from_arg_not_self() {
    let out = transpile_str(
        r#"
        struct Node<T> { elt: T }
        impl<T> Node<T> {
            fn new(elt: T) -> Self { Node { elt } }
        }
        struct LinkedList<T, A> {
            phantom: std::marker::PhantomData<(T, A)>,
            alloc: A,
        }
        impl<T, A> LinkedList<T, A> {
            fn push_front(&self, elt: T) {
                let _ = Box::new_in(Node::new(elt), &self.alloc);
            }
        }
        "#,
    );
    // The buggy emit substitutes the enclosing impl Self
    // (`LinkedList<T, A>`) for Box's T.
    assert!(
        !out.contains("Box<LinkedList"),
        "Box::new_in substituted enclosing impl Self for T:\n{out}"
    );
    // The correct emit infers `Node<...>` from the first arg.
    assert!(
        out.contains("rusty::Box<Node<"),
        "Box::new_in did not infer Node<...> from arg:\n{out}"
    );
}

