#[test]
fn test_leaf44_nested_super_group_use_emits_qualified_using_names() {
    let out = transpile_str(
        r#"
        struct Foo {}
        fn bar() {}
        mod inner {
            use super::{Foo, bar};
        }
    "#,
    );

    assert!(out.contains("namespace inner {"));
    assert!(out.contains("using ::Foo;"));
    // `bar` import may be `using ::bar;` (legacy) or `// Rust-only
    // namespace re-export: using bar;` (current — bar is a free
    // function, skipped from C++ using-declaration).
    assert!(
        out.contains("using ::bar;")
            || out.contains("// Rust-only namespace re-export: using bar;"),
        "{out}"
    );
    assert!(!out.contains("\nusing Foo;"));
    assert!(!out.contains("\nusing bar;"));
}

