#[test]
fn test_leaf428_iterator_trait_impl_on_imported_top_level_either_emits_next_and_count() {
    let out = transpile_str_module(
        r#"
        enum Either<L, R> { Left(L), Right(R) }
        mod iterator {
            use super::Either;
            use std::iter::Iterator;
            impl<L, R> Iterator for Either<L, R> {
                type Item = i32;
                fn next(&mut self) -> Option<Self::Item> { todo!() }
                fn count(self) -> usize { todo!() }
            }
        }
    "#,
        "either",
    );

    // `next()` may be `auto next()` (legacy) or
    // `rusty::Option<int32_t> next()` (current — explicit return type).
    assert!(
        out.contains("auto next() {") || out.contains("rusty::Option<int32_t> next() {"),
        "{out}"
    );
    // `fn count(self)` (Iterator::count) is now emitted as a const
    // method (B3 fix — Rust self-by-value receivers map to C++ const).
    assert!(out.contains("size_t count() const {") || out.contains("size_t count() {"));
    assert!(!out.contains("// Methods for iterator::Either"));
}

