#[test]
fn test_assert_macro_with_message_emits_throw_form() {
    // `assert!(cond, "msg")` cannot pass through to C's `assert(...)`
    // (one-arg macro); it must be rewritten to a throw-based check so
    // the message survives.
    let out = transpile_str(
        r#"fn f(x: i32) { assert!(x > 0, "x must be positive"); }"#,
    );
    assert!(
        out.contains("if (!(")
            && out.contains("throw std::logic_error(")
            && out.contains("x must be positive"),
        "expected throw-form assert with message, got: {out}"
    );
    // The legacy comma-laden `assert(x > 0 , "x must be positive")`
    // form must not leak through — C preprocessor splits on commas.
    assert!(
        !out.contains(r#"assert(x > 0 , "x must be positive")"#),
        "legacy multi-arg `assert(...)` form must not be emitted: {out}"
    );
}

#[test]
fn test_assert_macro_with_format_message_uses_std_format() {
    // `assert!(cond, "fmt {} {}", a, b)` should produce a
    // `std::format(...)` argument inside the throw-form.
    let out = transpile_str(
        r#"fn f(x: i32, y: i32) { assert!(x > y, "x={} y={}", x, y); }"#,
    );
    assert!(
        out.contains("throw std::logic_error(std::format("),
        "expected std::format wrapping the message, got: {out}"
    );
}

#[test]
fn test_assert_macro_with_match_body_lowers_to_iife() {
    // The condition body may itself be a `match` expression. The old
    // path emitted the raw Rust `match` syntax inside `assert(...)`
    // because it only ran token-text substitution. After the fix the
    // condition goes through the real expression emitter, so the
    // match becomes an IIFE / index-dispatched lowering — either
    // way, no raw `match` keyword survives.
    let out = transpile_str(
        r#"
        enum Side { Left(i32), Right(i32) }
        fn f(side: Side) {
            assert!(match side {
                Side::Left(idx) => idx <= 10,
                Side::Right(idx) => idx <= 20,
            });
        }
        "#,
    );
    // No raw Rust `match` keyword should leak into the C++ output's
    // assert site. (The word `match` could appear in surrounding
    // rusty:: preamble error strings; we check for the assert site
    // specifically.)
    let assert_lines: Vec<&str> =
        out.lines().filter(|line| line.contains("assert(")).collect();
    for line in &assert_lines {
        assert!(
            !line.contains(" match "),
            "raw Rust `match` keyword leaked into assert site: {line}"
        );
    }
}

