// ── if let pattern tests ────────────────────────────────────

#[test]
fn test_if_let_some() {
    let out = transpile_str("fn f(opt: Option<i32>) { if let Some(v) = opt { use_v(v); } }");
    assert!(out.contains("if (opt.is_some()) {"), "{out}");
    // Binding may be `auto v = ...` (legacy) or `decltype(auto) v = ...`
    // (current, preserves reference-ness of the unwrap result).
    assert!(
        out.contains("auto v = opt.unwrap();")
            || out.contains("decltype(auto) v = opt.unwrap();"),
        "{out}"
    );
}

#[test]
fn test_if_let_some_with_else() {
    let out = transpile_str(
        "fn f(opt: Option<i32>) { if let Some(v) = opt { ok(v); } else { fail(); } }",
    );
    assert!(out.contains("if (opt.is_some()) {"));
    assert!(out.contains("} else {"));
    assert!(out.contains("fail();"));
}

#[test]
fn test_if_let_ok() {
    let out = transpile_str("fn f(r: Result<i32, String>) { if let Ok(v) = r { use_v(v); } }");
    assert!(out.contains("if (r.is_ok()) {"), "{out}");
    assert!(
        out.contains("auto v = r.unwrap();")
            || out.contains("decltype(auto) v = r.unwrap();"),
        "{out}"
    );
}

#[test]
fn test_if_let_err() {
    let out =
        transpile_str("fn f(r: Result<i32, String>) { if let Err(e) = r { report(e); } }");
    assert!(out.contains("if (r.is_err()) {"), "{out}");
    assert!(
        out.contains("auto e = r.unwrap_err();")
            || out.contains("decltype(auto) e = r.unwrap_err();"),
        "{out}"
    );
}

#[test]
fn test_if_let_none() {
    let out = transpile_str("fn f(opt: Option<i32>) { if let None = opt { nothing(); } }");
    assert!(out.contains("if (opt.is_none()) {"));
}

#[test]
fn test_if_let_some_tuple_payload_binds_nested_tuple_names() {
    let out = transpile_str(
        "fn f(opt: Option<(char, &str)>) { if let Some((ch, text)) = opt { use_ch(ch); use_text(text); } }",
    );
    // The payload extraction may wrap the get in `deref_if_pointer` to
    // tolerate reference-pointer payloads.
    assert!(
        out.contains("auto&& _iflet_payload = opt.unwrap();"),
        "{out}"
    );
    assert!(
        out.contains("auto&& ch = std::get<0>(_iflet_payload);")
            || out.contains(
                "auto&& ch = rusty::detail::deref_if_pointer(std::get<0>(rusty::detail::deref_if_pointer(_iflet_payload)))"
            ),
        "{out}"
    );
    assert!(
        out.contains("auto&& text = std::get<1>(_iflet_payload);")
            || out.contains(
                "auto&& text = rusty::detail::deref_if_pointer(std::get<1>(rusty::detail::deref_if_pointer(_iflet_payload)))"
            ),
        "{out}"
    );
    assert!(out.contains("use_ch(std::move(ch));"), "{out}");
    assert!(out.contains("use_text(std::move(text));"), "{out}");
}

