#[test]
fn test_leaf5120_softened_reference_return_method_uses_decltype_auto() {
    let out = transpile_str_module(
        r#"
        trait Array { type Item; }
        struct SmallVec<A>(A);
        impl<A: Array, I> std::ops::Index<I> for SmallVec<A> {
            type Output = A::Item;
            fn index(&self, _index: I) -> &Self::Output {
                todo!()
            }
        }
    "#,
        "smallvec_like",
    );
    assert!(out.contains("decltype(auto) operator[]("), "{out}");
    assert!(!out.contains("auto operator[]("), "{out}");
}

#[test]
fn test_leaf4154333333332801_softened_index_reference_return_avoids_pointer_layering() {
    let out = transpile_str_module(
        r#"
        trait Array { type Item; }
        struct SmallVec<A>(A);

        impl<A: Array> std::ops::Deref for SmallVec<A> {
            type Target = [A::Item];
            fn deref(&self) -> &Self::Target { todo!() }
        }

        impl<A: Array, I> std::ops::Index<I> for SmallVec<A> {
            type Output = A::Item;
            fn index(&self, index: I) -> &Self::Output {
                &(**self)[index]
            }
        }
    "#,
        "smallvec_like",
    );
    // Deref may use raw `*(*this)` or wrapped via runtime helper.
    assert!(
        out.contains("return (*(*this))[index];")
            || out.contains(
                "return (rusty::detail::deref_if_pointer_like((*this)))[index];"
            ),
        "{out}"
    );
    assert!(!out.contains("return &(*(*this))[index];"), "{out}");
}

