#[test]
fn test_use_super_sibling_module_emits_import_not_broken_using() {
    // `use super::node::NodeRef;` from a file in the same parent
    // module as `node` should emit a C++20 `import` of the
    // sibling module, not a global `using ::node::NodeRef;`
    // (which fails name lookup because there is no global
    // `::node` namespace in module mode).
    let out = transpile_str_module_with_sibling_modules(
        "use super::node::NodeRef;",
        "btree_port.btree.split",
        &["btree_port.btree.node", "btree_port.btree.split"],
    );
    assert!(
        out.contains("import btree_port.btree.node;"),
        "expected sibling-module import; got: {out}"
    );
    assert!(
        !out.contains("using ::node::NodeRef;"),
        "broken `using ::node::NodeRef;` must not be emitted: {out}"
    );
}

#[test]
fn test_use_super_sibling_module_dedups_repeated_imports() {
    // Multiple `use super::node::*;` statements that all resolve
    // to the same sibling module should only emit one `import`.
    let out = transpile_str_module_with_sibling_modules(
        "use super::node::NodeRef; use super::node::Handle; use super::node::marker;",
        "btree_port.btree.split",
        &["btree_port.btree.node", "btree_port.btree.split"],
    );
    let import_count = out
        .matches("import btree_port.btree.node;")
        .count();
    assert_eq!(
        import_count, 1,
        "expected exactly one import of the sibling module, got {import_count}: {out}"
    );
}

#[test]
fn test_use_super_super_ancestor_sibling_module_emits_import() {
    // `use super::super::borrow::DormantMutRef;` from a deeply-
    // nested file (e.g. `btree_port.btree.map.entry`) targets
    // `borrow` as a sibling of the GRANDPARENT, not the parent.
    // The resolver must walk ancestors and match at the right
    // level instead of giving up after the immediate parent.
    let out = transpile_str_module_with_sibling_modules(
        "use super::super::borrow::DormantMutRef;",
        "btree_port.btree.map.entry",
        &[
            "btree_port.btree.borrow",
            "btree_port.btree.map.entry",
        ],
    );
    assert!(
        out.contains("import btree_port.btree.borrow;"),
        "expected ancestor-sibling import; got: {out}"
    );
}

#[test]
fn test_use_super_non_sibling_module_keeps_using_path() {
    // When the first segment isn't a sibling module (e.g. the
    // user wrote `use super::something_that_isnt_a_module::Item;`
    // or pulled from an external crate), the old `using` path
    // emission stays — only sibling C++ modules trigger the
    // import rewrite.
    let out = transpile_str_module_with_sibling_modules(
        "use super::node::NodeRef;",
        "btree_port.btree.split",
        // Note: no `btree_port.btree.node` in this crate list.
        &["btree_port.btree.split"],
    );
    assert!(
        !out.contains("import btree_port.btree.node;"),
        "non-sibling segment must not trigger import: {out}"
    );
}

#[test]
fn test_pub_crate_exported_in_module_mode() {
    // Updated for the BTreeMap-port era: `pub(crate)` items need to
    // be `export`ed in module mode because C++ modules have no
    // analogue to Rust's intra-crate visibility tiers — without
    // export, sibling/parent modules can't name them. Truly
    // private items (no visibility specifier) still skip export.
    let out = transpile_str_module(
        "pub(crate) fn internal() {} fn really_private() {}",
        "my_crate",
    );
    assert!(out.contains("export void internal"), "{out}");
    assert!(!out.contains("export void really_private"), "{out}");
    assert!(out.contains("void really_private()"), "{out}");
}

