#[test]
fn test_method_turbofish_trailing_infer_is_truncated_not_positionally_filled() {
    // `drop_inner_table::<T, _>(&alloc, layout)`: `T` is explicit (used only in
    // the body, deducible from nothing), `_` is the allocator `A` (deducible from
    // the `alloc` argument). The turbofish slot does NOT line up with an argument
    // — `T` consumes none — so positionally filling the `_` from arg 1 would bind
    // `A` to the layout's type. A TRAILING `_` must instead be omitted, keeping
    // the concrete prefix `<T>` and letting C++ deduce `A` from `&self.alloc`.
    let out = transpile_str(
        r#"
        pub struct TableLayout { size: usize }
        pub struct Inner { mask: usize }
        impl Inner {
            pub unsafe fn drop_inner_table<T, A>(&mut self, alloc: &A, table_layout: TableLayout) {
                let _ = (alloc, table_layout);
            }
        }
        pub struct Table<T, A> {
            inner: Inner,
            alloc: A,
            marker: core::marker::PhantomData<T>,
        }
        impl<T, A> Table<T, A> {
            const LAYOUT: TableLayout = TableLayout { size: 8 };
            pub unsafe fn clear(&mut self) {
                self.inner.drop_inner_table::<T, _>(&self.alloc, Self::LAYOUT);
            }
        }
        "#,
    );
    assert!(
        out.contains("drop_inner_table<T>(this->alloc,"),
        "trailing `_` must truncate to `<T>` (A deduced from the alloc arg), not be \
         positionally filled with the layout's type\nGot: {out}"
    );
    assert!(
        !out.contains("drop_inner_table<T, std::remove_cvref_t<decltype"),
        "the `_` must NOT be positionally filled from the (misaligned) call arg\nGot: {out}"
    );
}

#[test]
fn test_blanket_trait_default_const_resolves_at_type_param_use_site() {
    // A trait associated const with a default body + blanket impl
    // (`SizedTypeProperties::NEEDS_DROP = mem::needs_drop::<Self>()`). The trait is
    // skipped (assoc-const traits unsupported), so a type-param access `T::NEEDS_DROP`
    // must resolve to the default body with `Self` → `T`, not a bogus member access.
    let out = transpile_str(
        r#"
        pub trait SizedTypeProperties: Sized {
            const NEEDS_DROP: bool = core::mem::needs_drop::<Self>();
            const IS_ZERO_SIZED: bool = core::mem::size_of::<Self>() == 0;
        }
        impl<T> SizedTypeProperties for T {}
        pub struct Bucket;
        impl Bucket {
            pub fn drop_elem<T>(&self) {
                if T::NEEDS_DROP {
                    let _ = T::IS_ZERO_SIZED;
                }
            }
        }
        "#,
    );
    assert!(
        out.contains("rusty::mem::needs_drop<T>()"),
        "T::NEEDS_DROP must lower to the default body mem::needs_drop::<T>()\nGot: {out}"
    );
    assert!(
        out.contains("rusty::mem::size_of<T>() == 0"),
        "T::IS_ZERO_SIZED must lower to mem::size_of::<T>() == 0\nGot: {out}"
    );
    assert!(
        !out.contains("T::NEEDS_DROP"),
        "the bogus member access must be gone\nGot: {out}"
    );
}

#[test]
fn test_drop_in_place_method_on_raw_pointer_lowers_to_free_fn() {
    // `<*mut T>::drop_in_place()` as a method on a raw-pointer receiver has no C++
    // member form — lower to the free function `rusty::ptr::drop_in_place(ptr)`.
    let out = transpile_str(
        r#"
        pub struct Bucket<T> { ptr: core::ptr::NonNull<T> }
        impl<T> Bucket<T> {
            pub fn as_ptr(&self) -> *mut T { self.ptr.as_ptr() }
            pub unsafe fn drop_it(&self) {
                self.as_ptr().drop_in_place();
            }
        }
        "#,
    );
    assert!(
        out.contains("rusty::ptr::drop_in_place("),
        "drop_in_place on a raw pointer must lower to the free fn\nGot: {out}"
    );
    assert!(
        !out.contains("->drop_in_place()"),
        "the bogus member call must be gone\nGot: {out}"
    );
}

#[test]
fn test_leaf41542_field_name_collision_with_method_is_renamed() {
    let out = transpile_str(
        r#"
        struct S {
            len: usize,
        }
        impl S {
            fn len(&self) -> usize { self.len }
        }
    "#,
    );
    assert!(out.contains("size_t len_field;"));
    assert!(out.contains("size_t len() const"));
    assert!(out.contains("return this->len_field;"));
    assert!(!out.contains("size_t len;"));
}

#[test]
fn test_leaf10530_nonself_field_access_uses_renamed_member_for_ref_typed_receiver() {
    let out = transpile_str(
        r#"
        struct CapacityError<T> {
            element: T,
        }
        impl<T: Copy + PartialEq> CapacityError<T> {
            fn element(&self) -> T { self.element }
            fn eq_with(&self, other: &CapacityError<T>) -> bool {
                self.element == other.element
            }
        }
    "#,
    );
    assert!(out.contains("T element_field;"));
    assert!(out.contains("T element() const"));
    // Comparison operands may be bare or wrapped via `deref_if_pointer_like`.
    assert!(
        out.contains("return this->element_field == other.element_field;")
            || out.contains(
                "return rusty::detail::deref_if_pointer_like(this->element_field) == rusty::detail::deref_if_pointer_like(other.element_field);"
            ),
        "{out}"
    );
    assert!(!out.contains("other.element;"));
}

#[test]
fn test_leaf41542_merged_impl_assoc_items_are_deduplicated() {
    let out = transpile_str(
        r#"
        struct S {}
        impl S {
            const CAPACITY: usize = 1;
            type Item = i32;
        }
        impl S {
            const CAPACITY: usize = 1;
            type Item = i32;
        }
    "#,
    );
    // Literal `1` is emitted as `static_cast<size_t>(1)` because the
    // RHS is type-coerced through the const's declared type. Match the
    // literal-bearing shape to keep the dedup-count assertion focused.
    assert_eq!(
        out.matches("static constexpr size_t CAPACITY =").count(),
        1,
        "{out}"
    );
    assert_eq!(out.matches("using Item = int32_t;").count(), 1, "{out}");
}

#[test]
fn test_leaf41542_local_generic_type_position_recovers_template_args() {
    let out = transpile_str(
        r#"
        mod errors {
            pub struct CapacityError<T> {
                value: T,
            }
        }
        struct Wrap<T> {
            value: T,
        }
        trait Tryish {
            type Error;
        }
        impl<T> Tryish for Wrap<T> {
            type Error = errors::CapacityError;
        }
        impl<T> Wrap<T> {
            fn f(&self) -> Result<(), errors::CapacityError> {
                Ok(())
            }
        }
    "#,
    );
    // Path may be locally qualified or globally anchored with `::`.
    assert!(
        out.contains("using Error = errors::CapacityError<T>;")
            || out.contains("using Error = ::errors::CapacityError<T>;"),
        "{out}"
    );
    assert!(
        out.contains("rusty::Result<std::tuple<>, errors::CapacityError<T>> f() const")
            || out.contains(
                "rusty::Result<std::tuple<>, ::errors::CapacityError<T>> f() const"
            ),
        "{out}"
    );
}

