#[test]
fn test_nested_fn_to_lambda() {
    let out = transpile_str("fn outer() { fn inner(x: i32) -> i32 { x + 1 } inner(1); }");
    assert!(
        out.contains(
            "const rusty::SafeFn<int32_t(int32_t)> inner = +[](int32_t x) -> int32_t {"
        ),
        "{out}"
    );
    // Body may wrap operands with deref_if_pointer_like and static_cast.
    assert!(
        out.contains("return x + 1;")
            || out.contains(
                "return rusty::detail::deref_if_pointer_like(x) + static_cast<int32_t>(1);"
            ),
        "{out}"
    );
    // Inner-call arg may be wrapped in static_cast for type pinning.
    assert!(
        out.contains("inner(1);") || out.contains("inner(static_cast<int32_t>(1));"),
        "{out}"
    );
}

