#[test]
fn test_leaf41543333333327341_string_backed_hash_method_lowers_to_runtime_helper() {
    let out = transpile_str(
        r#"
        use std::ops::Deref;

        struct S;
        impl Deref for S {
            type Target = str;
            fn deref(&self) -> &str { "x" }
        }

        impl S {
            fn do_hash(&self, h: &mut usize) {
                (**self).hash(h);
            }
        }
        "#,
    );
    assert!(out.contains("rusty::hash::hash("));
    // Deref may be raw `*(*this)` or wrapped via the runtime helper.
    assert!(
        out.contains("rusty::hash::hash((*(*this)), h);")
            || out.contains(
                "rusty::hash::hash(((rusty::detail::deref_if_pointer_like((*this)))), h);"
            )
            || out.contains(
                "rusty::hash::hash((rusty::detail::deref_if_pointer_like((*this))), h);"
            ),
        "{out}"
    );
    assert!(!out.contains("(*(*this)).hash(h);"));
}

