#[test]
fn test_leaf10527_alloc_local_pointer_add_lowers_to_runtime_helper() {
    let out = transpile_str(
        r#"
        use std::alloc::{alloc, Layout};

        fn f(len: usize) {
            unsafe {
                let layout = Layout::from_size_align_unchecked(len + 1, 1);
                let ptr = alloc(layout);
                let mut write = ptr;
                write = write.add(1);
                write.write(0);
            }
        }
        "#,
    );
    // `write` is a C++/POSIX identifier collision and gets escaped to
    // `write_`. Accept either spelling.
    assert!(
        out.contains("write = rusty::ptr::add(write, 1);")
            || out.contains("write_ = rusty::ptr::add(write_, 1);"),
        "{out}"
    );
    assert!(out.contains("rusty::ptr::write("), "{out}");
    assert!(
        !out.contains("write = write.add(1);")
            && !out.contains("write_ = write_.add(1);"),
        "{out}"
    );
}

