#[test]
fn test_leaf41543333333327211_typed_mut_ptr_local_keeps_writable_pointee_shape() {
    let out = transpile_str(
        r#"
        fn f(buf: &mut [i32; 8], index: usize, len: usize, value: i32) {
            unsafe {
                let p: *mut _ = buf.as_mut_ptr().add(index);
                std::ptr::copy(p, p.offset(1), len - index);
                std::ptr::write(p, value);
            }
        }
        "#,
    );
    assert!(out.contains("auto* const p = rusty::ptr::add("), "{out}");
    // Pointer arg may be wrapped in std::move or passed directly.
    assert!(
        out.contains("rusty::ptr::copy(std::move(p), rusty::ptr::offset(p, 1),")
            || out.contains("rusty::ptr::copy(p, rusty::ptr::offset(p, 1),"),
        "{out}"
    );
    assert!(
        out.contains("rusty::ptr::write(std::move(p),")
            || out.contains("rusty::ptr::write(p,"),
        "{out}"
    );
    assert!(!out.contains("const auto* p ="), "{out}");
}

