#[test]
fn test_leaf10533_deref_ref_to_pointer_cast_preserves_address_of_expression() {
    let out = transpile_str(
        r#"
        use std::mem::{self, MaybeUninit};
        fn f<T, const N: usize>(array: [T; N], dst: *mut [MaybeUninit<T>; N]) {
            let array = mem::ManuallyDrop::new(array);
            unsafe {
                (&*array as *const [T; N] as *const [MaybeUninit<T>; N]).copy_to_nonoverlapping(dst, 1);
            }
        }
        "#,
    );
    // Cast may use `static_cast` (legacy) or `reinterpret_cast` (current),
    // and inner expression may be `&*array_shadow1` (legacy) or
    // `rusty::addr_of_temp(array_shadow1)` (current).
    let array_ref = out.contains(
        "static_cast<std::add_pointer_t<std::add_const_t<std::array<T, rusty::sanitize_array_capacity<N>()>>>>(&*array_shadow1)"
    ) || out.contains(
        "reinterpret_cast<std::add_pointer_t<std::add_const_t<std::array<T, rusty::sanitize_array_capacity<N>()>>>>(rusty::addr_of_temp(array_shadow1))"
    );
    assert!(array_ref, "{out}");
    assert!(!out.contains(
        "static_cast<std::add_pointer_t<std::add_const_t<std::array<T, rusty::sanitize_array_capacity<N>()>>>>(*array_shadow1)"
    ));
}

#[test]
fn test_leaf10534_deref_view_target_methods_return_value_not_target_reference() {
    let out = transpile_str(
        r#"
        use std::ops::{Deref, DerefMut};
        struct Buf {
            xs: [i32; 2],
        }
        impl Deref for Buf {
            type Target = [i32];
            fn deref(&self) -> &Self::Target {
                &self.xs
            }
        }
        impl DerefMut for Buf {
            fn deref_mut(&mut self) -> &mut Self::Target {
                &mut self.xs
            }
        }
        "#,
    );
    // Operator may be inline (`std::span<const int32_t> operator*() const {`)
    // or out-of-line (`std::span<const int32_t> Buf::operator*() const {`).
    assert!(
        out.contains("std::span<const int32_t> operator*() const {")
            || out.contains("std::span<const int32_t> Buf::operator*() const {"),
        "{out}"
    );
    assert!(!out.contains("Target& operator*() const"));
    // DerefMut may emit `deref_mut()` (legacy) or `operator*()` non-const overload.
    assert!(
        out.contains("std::span<int32_t> deref_mut() {")
            || out.contains("std::span<int32_t> operator*() {")
            || out.contains("std::span<int32_t> Buf::operator*() {"),
        "{out}"
    );
    assert!(!out.contains("Target& deref_mut()"));
}

