#[test]
fn test_leaf10519_if_let_tuple_result_assigns_multistmt_tail_value() {
    let out = transpile_str(
        r#"
        fn wildcard(text: &str) -> Option<(char, &str)> { None }
        fn numeric_identifier(text: &str) -> Result<(u64, &str), i32> {
            Ok((1, text))
        }
        fn parse_minor(text: &str) -> Result<(Option<u64>, &str), i32> {
            let (minor, text) = if let Some(text) = text.strip_prefix('.') {
                if let Some((_, text)) = wildcard(text) {
                    (None, text)
                } else {
                    let (minor, text) = numeric_identifier(text)?;
                    (Some(minor), text)
                }
            } else {
                (None, text)
            };
            if minor.is_some() {
                Ok((minor, text))
            } else {
                Ok((None, text))
            }
        }
        "#,
    );
    // The Some-construction wrapper may be `std::make_optional(minor)`
    // (legacy) or `rusty::Option<uint64_t>(std::move(minor))` (current).
    let legacy_some = out.contains("std::make_optional(minor)");
    let rusty_some = out.contains("rusty::Option<uint64_t>(std::move(minor))")
        || out.contains("rusty::Option<uint64_t>(minor)");
    assert!(
        out.contains("_iflet_result0 = ") && (legacy_some || rusty_some),
        "multi-statement branch tail should assign tuple value into result temp, got:\n{}",
        out
    );
    // The codegen must not leave the tuple as a bare expression
    // statement preceding the assignment.
    assert!(
        !out.contains("\n                std::make_tuple(std::make_optional("),
        "multi-statement branch tail must not emit a bare tuple expression statement, got:\n{}",
        out
    );
}

