#[test]
fn test_leaf41543333333327181_drop_marks_immutable_local_as_consumed() {
    let out = transpile_str(
        r#"
        fn f() {
            let v = Vec::<i32>::new();
            drop(v);
        }
        "#,
    );
    // Local may be declared with `auto` and inferred type (`auto v =
    // rusty::Vec::new_();`), `auto` + explicit-turbofish RHS, or with
    // explicit type on the LHS (`rusty::Vec<int32_t> v = …`).
    assert!(
        out.contains("auto v = rusty::Vec::new_();")
            || out.contains("auto v = rusty::Vec<int32_t>::new_();")
            || out.contains("rusty::Vec<int32_t> v = rusty::Vec<int32_t>::new_();"),
        "{out}"
    );
    assert!(!out.contains("const auto v ="), "{out}");
    assert!(out.contains("rusty::mem::drop(std::move(v));"), "{out}");
}

