#[test]
fn test_leaf515_non_recursive_data_enum_forward_decl_uses_variant_alias_not_struct() {
    let out = transpile_str(
        r#"
        mod error {
            pub enum ErrorKind {
                Empty,
                Unexpected(char),
            }
        }
        mod parse {
            use crate::error::ErrorKind;
            pub fn parse_kind() -> ErrorKind {
                ErrorKind::Empty
            }
        }
        "#,
    );

    let alias = "using ErrorKind = std::variant<ErrorKind_Empty, ErrorKind_Unexpected>;";
    assert!(
        out.contains(alias),
        "expected data-enum alias forward declaration for ErrorKind, got:\n{}",
        out
    );
    assert!(
        out.contains("struct ErrorKind_Empty;"),
        "expected variant forward declaration for ErrorKind_Empty, got:\n{}",
        out
    );
    assert!(
        out.contains("struct ErrorKind_Unexpected;"),
        "expected variant forward declaration for ErrorKind_Unexpected, got:\n{}",
        out
    );
    assert!(
        !out.contains("struct ErrorKind;"),
        "unexpected struct forward declaration conflicts with alias-based enum emission:\n{}",
        out
    );
    let alias_pos = out
        .find(alias)
        .expect("missing ErrorKind alias forward declaration");
    let sig_pos = out
        .find("::error::ErrorKind parse_kind();")
        .expect("missing parse_kind forward declaration");
    assert!(
        alias_pos < sig_pos,
        "ErrorKind alias forward declaration must precede parse_kind signature:\n{}",
        out
    );
}

#[test]
fn test_leaf517_split_parent_module_defers_nested_function_definitions_recursively() {
    let out = transpile_str(
        r#"
        mod outer {
            pub struct Local(pub i32);
            pub mod inner {
                pub fn nested_uses_my_type() -> super::super::MyType {
                    super::super::MyType::new()
                }
            }
            pub fn uses_my_type() -> super::super::MyType {
                super::super::MyType::new()
            }
        }
        pub struct MyType {
            pub value: i32,
        }
        impl MyType {
            pub fn new() -> MyType {
                MyType { value: 1 }
            }
        }
        "#,
    );

    let nested_def_count = out.matches("nested_uses_my_type() {").count();
    assert_eq!(
        nested_def_count, 1,
        "nested function definition should be emitted exactly once:\n{}",
        out
    );
    let my_type_def_pos = out
        .find("struct MyType {")
        .expect("missing MyType struct definition");
    let nested_def_pos = out
        .find("nested_uses_my_type() {")
        .expect("missing nested_uses_my_type definition");
    assert!(
        my_type_def_pos < nested_def_pos,
        "nested function definition should be deferred until after MyType definition:\n{}",
        out
    );
}

#[test]
fn test_leaf513_nested_private_module_forward_decls_precede_aliases() {
    let out = transpile_str(
        r#"
        mod duplicates_impl {
            pub type DuplicatesBy<I, V, F> = private_::DuplicatesBy<I, V, private_::ByFn<F>>;
            pub fn duplicates_by<I, V, F>(iter: I, f: F) -> DuplicatesBy<I, V, F> {
                let _ = (iter, f);
                todo!()
            }
            mod private_ {
                pub struct DuplicatesBy<I, V, F>(I, V, F);
                pub struct ByFn<F>(F);
            }
        }
        "#,
    );

    let nested_ns = "namespace private_ {";
    // Alias may be unqualified or use the fully-anchored path through
    // `::duplicates_impl::private_`.
    let alias_short = "using DuplicatesBy = private_::DuplicatesBy<I, V, private_::ByFn<F>>;";
    let alias_anchored = "using DuplicatesBy = ::duplicates_impl::private_::DuplicatesBy<I, V, ::duplicates_impl::private_::ByFn<F>>;";
    assert!(
        out.contains(nested_ns),
        "expected nested private_ namespace forward declarations, got:\n{}",
        out
    );
    assert!(
        out.contains(alias_short) || out.contains(alias_anchored),
        "expected alias to nested private_ type, got:\n{}",
        out
    );
    let ns_pos = out
        .find(nested_ns)
        .expect("missing private_ namespace forward declarations");
    let alias_pos = out
        .find(alias_short)
        .or_else(|| out.find(alias_anchored))
        .expect("missing DuplicatesBy alias");
    assert!(
        ns_pos < alias_pos,
        "nested module forward declarations must precede alias use:\n{}",
        out
    );
}

