#[test]
fn test_leaf415447_switch_match_tuple_casts_unsuffixed_int_literals_from_peer_type() {
    let out = transpile_str(
        r#"
        use core::fmt::Alignment;
        fn split(align: Alignment, padding: usize) -> (usize, usize) {
            match align {
                Alignment::Left => (0, padding),
                Alignment::Right => (padding, 0),
                Alignment::Center => (padding / 2, (padding + 1) / 2),
            }
        }
        "#,
    );
    // The decltype-cast may reference `std::move(padding)` or the
    // deref-wrapped peer expression in the new accumulator lowering.
    assert!(
        out.contains("static_cast<std::remove_cvref_t<decltype((std::move(padding)))>>(0)")
            || out.contains(
                "static_cast<std::remove_cvref_t<decltype((rusty::detail::deref_if_pointer_like(padding) / 2))>>(0)"
            ),
        "{out}"
    );
    // Path may be globally qualified `rusty::fmt::Alignment::Left` or
    // unqualified `Alignment::Left` (relying on a `using` declaration).
    assert!(
        out.contains("== rusty::fmt::Alignment::Left")
            || out.contains("== Alignment::Left"),
        "{out}"
    );
    assert!(!out.contains("std::holds_alternative<rusty::fmt::Alignment_Left>"));
}

