#[test]
fn test_leaf10534_match_expr_struct_arms_emit_typed_visit_lambdas() {
    let out = transpile_str(
        r#"
        enum ParseKind {
            EmptyFlag,
            InvalidNamedFlag { got: () },
            InvalidHexFlag { got: () },
        }

        impl core::fmt::Debug for ParseKind {
            fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
                match self {
                    ParseKind::EmptyFlag => core::fmt::Formatter::write_str(f, "EmptyFlag"),
                    ParseKind::InvalidNamedFlag { got: __self_0 } => {
                        core::fmt::Formatter::debug_struct_field1_finish(
                            f,
                            "InvalidNamedFlag",
                            "got",
                            __self_0,
                        )
                    }
                    ParseKind::InvalidHexFlag { got: __self_0 } => {
                        core::fmt::Formatter::debug_struct_field1_finish(
                            f,
                            "InvalidHexFlag",
                            "got",
                            __self_0,
                        )
                    }
                }
            }
        }
        "#,
    );
    // Struct-variant arms may lower as typed std::visit lambdas or as
    // index-dispatch (`variant_index(_m) == N`) with method-style calls on `f`.
    assert!(
        out.contains("[&](const ParseKind_EmptyFlag&) { return f.write_str(\"EmptyFlag\"); }")
            || (out.contains("variant_index(_m) == 0")
                && out.contains("return f.write_str(\"EmptyFlag\");"))
            || (out.contains("rusty::detail::variant_index(rusty::detail::deref_if_pointer(_m)) == 0")
                && out.contains("return f.write_str(\"EmptyFlag\");")),
        "{out}"
    );
    assert!(
        out.contains("[&](const ParseKind_InvalidNamedFlag& _v) {")
            || out.contains("variant_index(_m) == 1")
            || out.contains("rusty::detail::variant_index(rusty::detail::deref_if_pointer(_m)) == 1"),
        "{out}"
    );
    // Field binding may come from `_v.got` (typed lambda) or
    // `std::get<N>(_m).got` (index dispatch), optionally through
    // `deref_if_pointer` wrappers.
    assert!(
        out.contains("__self_0 = _v.got;")
            || out.contains("__self_0 = std::get<1>(_m).got")
            || out.contains("auto&& __self_0 = rusty::detail::deref_if_pointer(std::get<1>(_m).got)")
            || out.contains(
                "__self_0 = rusty::detail::deref_if_pointer(std::get<1>(rusty::detail::deref_if_pointer(_m)).got)"
            ),
        "{out}"
    );
    assert!(
        out.contains(
            "return rusty::fmt::Formatter::debug_struct_field1_finish(f, \"InvalidNamedFlag\", \"got\""
        ) || out.contains(
            "return f.debug_struct_field1_finish(\"InvalidNamedFlag\", \"got\""
        ),
        "{out}"
    );
    assert!(
        out.contains("[&](const ParseKind_InvalidHexFlag& _v) {")
            || out.contains("variant_index(_m) == 2")
            || out.contains("rusty::detail::variant_index(rusty::detail::deref_if_pointer(_m)) == 2"),
        "{out}"
    );
    assert!(
        out.contains(
            "return rusty::fmt::Formatter::debug_struct_field1_finish(f, \"InvalidHexFlag\", \"got\""
        ) || out.contains(
            "return f.debug_struct_field1_finish(\"InvalidHexFlag\", \"got\""
        ),
        "{out}"
    );
    assert!(
        !out.contains(
            "[&](const auto&) { return [&]() -> rusty::fmt::Result { rusty::intrinsics::unreachable(); }(); }"
        ),
        "struct-variant debug arms should lower to typed lambdas, got:\n{}",
        out
    );
}

