#[test]
fn test_unannotated_let_from_field_records_type_for_pointer_method() {
    // `let x = s.p;` (un-annotated, field-access init) must record x's concrete
    // pointer type so a later raw-pointer method on x lowers via rusty::ptr::*
    // instead of becoming a `(*x).wrapping_offset(...)` member call on a non-struct.
    let out = transpile_str(
        r#"
        struct S { p: *mut u8 }
        fn f(s: S) -> *mut u8 {
            let x = s.p;
            x.wrapping_offset(1)
        }
        "#,
    );
    // x is recorded as `*mut u8`, so the raw-pointer method lowers to a
    // rusty::ptr::* free call (offset/wrapping_offset) on the pointer x — not a
    // `(*x).wrapping_offset(...)` / `x.wrapping_offset(...)` member call.
    assert!(out.contains("rusty::ptr::") && out.contains("(x, "), "{out}");
    assert!(!out.contains("x.wrapping_offset"), "{out}");
}

#[test]
fn test_user_deref_field_access_on_call_result() {
    // `flush().fail` where flush() returns a `Success` that Derefs to `Failure`
    // (which owns `fail`). The base is a CALL, whose return type general infer
    // doesn't resolve for a struct return — so it must fall back to the callee's
    // declared return type, then deref-coerce: `(*flush()).fail`.
    let out = transpile_str(
        r#"
        use std::ops::Deref;
        pub struct Failure { pub fail: bool }
        pub struct Success;
        impl Deref for Success {
            type Target = Failure;
            fn deref(&self) -> &Failure { todo!() }
        }
        pub fn flush() -> Success { Success }
        pub fn check() -> bool { flush().fail }
        "#,
    );
    // Deref-coerced: `(*<call>).fail`, not a bare `<call>.fail` member access.
    assert!(out.contains("flush())).fail"), "{out}");
    assert!(out.contains("(*"), "{out}");
}

#[test]
fn test_primitive_assoc_const_under_core_primitive_prefix() {
    // c2rust imports primitives via `core::primitive`, so integer assoc consts
    // arrive as 4-segment paths `std::primitive::i32::MAX`. These must map to
    // `std::numeric_limits<int32_t>::max()`, not the invalid `int32_t::MAX`.
    let out = transpile_str(r#"fn f() -> i32 { std::primitive::i32::MAX }"#);
    assert!(out.contains("std::numeric_limits<int32_t>::max()"), "{out}");
    assert!(!out.contains("int32_t::MAX"), "{out}");
}

#[test]
fn test_nested_never_returning_fn_strips_noreturn_in_safefn() {
    // A nested `fn() -> !` is emitted as a `rusty::SafeFn` closure. The `!`
    // return maps to `[[noreturn]] void`, which is ill-formed both in the SafeFn
    // template argument and the lambda trailing-return-type. The attribute must
    // be stripped there (it stays valid on real top-level fn declarations).
    let out = transpile_str(
        r#"
        pub fn outer() {
            fn diverge() -> ! { loop {} }
            diverge();
        }
        "#,
    );
    assert!(!out.contains("SafeFn<[[noreturn]]"), "{out}");
    assert!(!out.contains("-> [[noreturn]] void"), "{out}");
}

#[test]
fn test_raw_addr_of_binding_types_local_for_pointer_method() {
    // c2rust's `addr_of_mut!(x)` -> `&raw mut x` (Expr::RawAddr). The binding
    // must record its pointer type so a later deref + raw-pointer method lowers
    // to rusty::ptr::* instead of a `(*p).wrapping_offset(...)` member call.
    let out = transpile_str(
        r#"
        pub unsafe fn f(mut x: *mut u8) -> *mut u8 {
            let pp = &raw mut x;
            let p = *pp;
            p.wrapping_offset(1)
        }
        "#,
    );
    assert!(out.contains("rusty::ptr::"), "{out}");
    assert!(!out.contains("p.wrapping_offset"), "{out}");
}

#[test]
fn test_enum_variant_imported_via_module_binds_to_scoped_owner() {
    // c2rust re-exports c-like enum variants through their MODULE:
    // `use crate::yaml::YAML_ALIAS_EVENT`. The variant is NOT a namespace member,
    // so `using yaml::YAML_ALIAS_EVENT;` is invalid — bind a constant to the
    // scoped `Owner::VARIANT`, resolving the owning enum from the variant name.
    let out = transpile_str(
        r#"
        pub mod yaml {
            pub enum yaml_event_type_t { YAML_ALIAS_EVENT, YAML_SCALAR_EVENT }
        }
        pub mod user {
            use crate::yaml::YAML_ALIAS_EVENT;
            pub fn pick() -> crate::yaml::yaml_event_type_t { YAML_ALIAS_EVENT }
        }
        "#,
    );
    assert!(
        out.contains("yaml_event_type_t::YAML_ALIAS_EVENT"),
        "{out}"
    );
    assert!(!out.contains("using yaml::YAML_ALIAS_EVENT"), "{out}");
}

#[test]
fn test_deref_of_multistmt_block_with_generic_field_types_local() {
    // c2rust's `POP!` expands to `*{ stack.top = …; stack.top }`. Two inference
    // pieces must combine: (a) the deref's operand is a MULTI-statement block —
    // infer its tail; (b) `Stack<Item>.top` is declared `*mut T` — substitute the
    // generic arg so it resolves to `*mut Item`. The deref then types the local,
    // so a later `it.handle as usize` reinterprets (ptr->int) instead of the
    // ill-formed `static_cast<uintptr_t>(ptr)`.
    let out = transpile_str(
        r#"
        pub struct Stack<T> { pub top: *mut T }
        pub struct Item { pub handle: *mut u8 }
        pub unsafe fn f(s: Stack<Item>) -> usize {
            let it = *{ let _k = 0; s.top };
            it.handle as usize
        }
        "#,
    );
    assert!(out.contains("reinterpret_cast<std::uintptr_t>"), "{out}");
}

#[test]
fn test_rust_union_emitted_as_cpp_union_and_ordered_before_user() {
    // c2rust C ports use real Rust `union`s. They must emit as C++ `union`
    // (previously dropped as "unhandled item kind") and be topologically ordered
    // BEFORE a struct that holds one by value (else the union member is an
    // incomplete type).
    let out = transpile_str(
        r#"
        pub struct Holder { pub data: Payload }
        pub union Payload { pub as_int: u64, pub as_ptr: *mut u8 }
        "#,
    );
    assert!(out.contains("union Payload {"), "{out}");
    let upos = out.find("union Payload {").unwrap();
    let hpos = out.find("struct Holder {").unwrap();
    assert!(upos < hpos, "union must precede the struct that holds it\n{out}");
}

#[test]
fn test_module_union_clone_impl_not_routed_to_extension_free_function() {
    // c2rust ports `#[derive(Copy, Clone)]` a union; after macro expansion that
    // becomes an explicit `impl Clone for <union>`. The union must be recorded as
    // a local declared type (like structs/enums) so this inherent-ish impl is
    // NOT routed to a `rusty_ext` extension-trait free function — which named the
    // union BARE at a foreign namespace (`core::clone::rusty_ext`), yielding
    // "unknown type name '<union>'" since the union lives in its own module.
    let out = transpile_str(
        r#"
        pub mod yaml {
            #[repr(C)]
            pub union Payload { pub as_int: u64, pub as_ptr: *mut u8 }
            impl Clone for Payload {
                fn clone(&self) -> Self { *self }
            }
            impl Copy for Payload {}
        }
        "#,
    );
    assert!(out.contains("union Payload"), "union must be emitted\n{out}");
    // The bug: a free-function clone decl `Payload clone(const Payload& self_)`
    // emitted under the trait's namespace, naming the union bare. A union has no
    // member clone (emit_union emits a plain union), so a `clone(const Payload`
    // signature can ONLY be the spurious extension free function.
    assert!(
        !out.contains("clone(const Payload"),
        "union Clone impl must not become a rusty_ext free function\n{out}"
    );
}

#[test]
fn test_reexport_of_core_ffi_c_void_binds_runtime_alias() {
    // c2rust ports define `mod libc { pub use core::ffi::c_void; ... }` and then
    // spell types as `libc::c_void`. The re-export must bring the runtime alias
    // into the module (`using rusty::ffi::c_void;`) rather than being dropped as
    // a Rust-only comment — otherwise `libc::c_void` is an undeclared type.
    let out = transpile_str(
        r#"
        pub mod libc {
            pub use core::ffi::c_void;
        }
        pub unsafe fn alloc(n: usize) -> *mut libc::c_void {
            core::ptr::null_mut()
        }
        "#,
    );
    assert!(
        out.contains("using rusty::ffi::c_void"),
        "c_void re-export must bind the runtime alias, not a Rust-only comment\n{out}"
    );
    assert!(
        !out.contains("// Rust-only: using core::ffi::c_void"),
        "c_void re-export must not be dropped as Rust-only\n{out}"
    );
}

#[test]
fn test_noreturn_panic_in_never_context_strips_attr_from_iife_return_type() {
    // A diverging panic in a `!`-typed position (e.g. the body of a
    // `-> !` fn) lowers to an IIFE `[&]() -> <expected> { panic(); }()`.
    // The expected type is `!` -> `map_type` yields `[[noreturn]] void`, but
    // `[[noreturn]]` is a decl attribute, illegal as a lambda trailing return
    // type ("an attribute list cannot appear here"). It must be stripped to
    // plain `void` on the lambda while the real fn decl keeps the attribute.
    let out = transpile_str(
        r#"
        pub fn do_die() -> ! {
            core::panicking::panic("arithmetic overflow");
        }
        "#,
    );
    assert!(
        out.contains("[&]() -> void {"),
        "diverging IIFE must use plain `void` return type\n{out}"
    );
    assert!(
        !out.contains("[&]() -> [[noreturn]]"),
        "lambda trailing return type must not carry [[noreturn]]\n{out}"
    );
    // The real function declaration legitimately keeps the attribute.
    assert!(
        out.contains("[[noreturn]] void do_die()"),
        "the actual fn decl should still carry [[noreturn]]\n{out}"
    );
}

#[test]
fn test_deref_idiom_raw_addr_cast_targets_reference_return_pointee() {
    // c2rust Deref impls use `&*(&raw const *self).cast()` (or addr_of! form):
    // a `.cast()` on a `*const Self` whose target is inferred from the `-> &T`
    // return. The `&*` wrapper doesn't propagate a pointer expected type, so the
    // cast target pointee must be recovered from the fn's reference return type,
    // and const-ness preserved from the `&raw const` receiver (else the
    // reinterpret_cast strips qualifiers).
    let out = transpile_str(
        r#"
        use core::ops::Deref;
        pub struct Outer { pub a: u64, pub b: u64 }
        pub struct Inner { pub a: u64 }
        impl Deref for Outer {
            type Target = Inner;
            fn deref(&self) -> &Self::Target {
                unsafe { &*(&raw const *self).cast() }
            }
        }
        "#,
    );
    assert!(
        out.contains("std::add_pointer_t<std::add_const_t<Inner>>"),
        "deref-idiom cast must target `const Inner*` from the reference return\n{out}"
    );
    assert!(
        !out.contains("->cast()") && !out.contains(".cast()"),
        "the raw-pointer `.cast()` must be lowered, not emitted verbatim\n{out}"
    );
}

#[test]
fn test_aggregate_typed_const_definition_follows_its_struct() {
    // c2rust `pub const OK: Success = Success { .. }` precedes `pub struct Success`
    // in source. The const-forward pass only emits an `extern const` decl for an
    // aggregate-literal initializer, so the real `constexpr Success OK = ..` lands
    // in body order — which must follow the struct definition, else the const is
    // defined against an incomplete (and non-literal) type.
    let out = transpile_str(
        r#"
        pub mod success {
            pub const OK: Success = Success { ok: true };
            pub const FAIL: Success = Success { ok: false };
            pub struct Success { pub ok: bool }
        }
        "#,
    );
    let struct_pos = out
        .find("struct Success {")
        .expect("struct Success definition must be emitted");
    let const_pos = out
        .find("constexpr Success OK =")
        .expect("constexpr OK definition must be emitted");
    assert!(
        struct_pos < const_pos,
        "aggregate-typed const definition must follow its struct\n{out}"
    );
}

#[test]
fn test_user_deref_field_access_on_if_expr_base_with_const_branches() {
    // c2rust `STACK_LIMIT!(...)` expands to `if .. { OK } else { ..; FAIL }` of
    // type Success, then `.fail` (a Failure field reached via `impl Deref for
    // Success`). The if-expr base's type must be recovered from a branch tail's
    // const type (`OK`/`FAIL` are `const Success`) so the field access lowers to
    // `(*base).fail`, not a bare `.fail` on Success.
    let out = transpile_str(
        r#"
        pub struct Success { pub ok: bool }
        pub struct Failure { pub fail: bool }
        impl core::ops::Deref for Success {
            type Target = Failure;
            fn deref(&self) -> &Failure {
                if self.ok { &Failure { fail: false } } else { &Failure { fail: true } }
            }
        }
        pub const OK: Success = Success { ok: true };
        pub const FAIL: Success = Success { ok: false };
        pub unsafe fn check(n: i64) -> i32 {
            if (if n < 10 { OK } else { FAIL }).fail { return 1; }
            0
        }
        "#,
    );
    // The `.fail` access must be deref-coerced: `(*<if-expr>).fail`.
    assert!(
        out.contains(")).fail"),
        "user-Deref field access on an if-expr base must emit `(*base).fail`\n{out}"
    );
}

#[test]
fn test_match_arm_calling_user_never_fn_is_diverging_not_returned() {
    // A match arm that calls a user `-> !` fn (c2rust's `__assert_fail`) in a
    // value-position match must NOT be wrapped in `return <call>;` — the call is
    // `[[noreturn]] void`, so returning it from a non-void match IIFE is a "no
    // viable conversion from void" error. is_expr_diverging must recognize the
    // callee's Never return type so the arm emits a bare statement.
    let out = transpile_str(
        r#"
        pub fn bail() -> ! { loop {} }
        pub enum Kind { A, B, C }
        pub fn pick(k: Kind) -> i32 {
            match k {
                Kind::A => 1,
                Kind::B => 2,
                _ => bail(),
            }
        }
        "#,
    );
    assert!(
        !out.contains("return ::bail()") && !out.contains("return bail()"),
        "a diverging user `-> !` arm must not be `return`ed\n{out}"
    );
    assert!(
        out.contains("bail();"),
        "the diverging arm should emit the call as a bare statement\n{out}"
    );
}

#[test]
fn test_external_fmt_path_not_attributed_to_local_mod_fmt() {
    // A crate with `mod fmt` plus macro-expanded `#[derive(Debug)]` impls that
    // spell `::core::fmt::Formatter` must NOT have those external references
    // attributed to the local `mod fmt`: doing so fabricates a phantom module
    // dependency edge and a false ordering cycle (the unsafe-libyaml fmt<->yaml
    // bug, where yaml's Debug impls created a spurious yaml->fmt edge).
    use std::collections::{HashMap, HashSet};
    let cg = CodeGen::new();
    let mut known_modules: HashSet<String> = HashSet::new();
    known_modules.insert("fmt".to_string());
    known_modules.insert("data".to_string());
    let fwd: HashMap<String, HashSet<String>> = HashMap::new();
    let imports: HashMap<String, String> = HashMap::new();

    // `::core::fmt::Formatter` (leading colon) must not yield a local `fmt` dep.
    let external_leading: syn::Type = syn::parse_quote!(::core::fmt::Formatter<'a>);
    let mut out = HashSet::new();
    cg.collect_type_module_dependencies(
        &external_leading,
        &known_modules,
        &fwd,
        &imports,
        false,
        &mut out,
    );
    assert!(
        !out.contains("fmt"),
        "::core::fmt must not attribute to local `mod fmt`; got {out:?}"
    );

    // `std::fmt::Result` (external crate root, no leading colon) likewise.
    let external_root: syn::Type = syn::parse_quote!(std::fmt::Result);
    let mut out2 = HashSet::new();
    cg.collect_type_module_dependencies(
        &external_root,
        &known_modules,
        &fwd,
        &imports,
        false,
        &mut out2,
    );
    assert!(
        !out2.contains("fmt"),
        "std::fmt must not attribute to local `mod fmt`; got {out2:?}"
    );

    // A genuine local sibling reference must STILL be detected.
    let local_ref: syn::Type = syn::parse_quote!(crate::data::Glyph);
    let mut out3 = HashSet::new();
    cg.collect_type_module_dependencies(
        &local_ref,
        &known_modules,
        &fwd,
        &imports,
        false,
        &mut out3,
    );
    assert!(
        out3.contains("data"),
        "genuine local sibling reference must still be detected; got {out3:?}"
    );
}

#[test]
fn test_std_type_import_not_hijacked_as_clike_enum_variant() {
    // `use std::string::String` maps to the runtime type `rusty::String`. It must
    // NOT be rewritten as a c-like-enum variant import just because a local enum
    // (serde's `Unsupported`) happens to declare a `String` variant — that emitted
    // a bogus `constexpr auto String = rusty::Unsupported::String;` (Unsupported is
    // not in `rusty::`, and it's the wrong meaning of `String`).
    let out = transpile_str(
        r#"
        pub mod ser {
            #[derive(Clone, Copy)]
            pub enum Unsupported { Boolean, String, Integer }
            pub use std::string::String;
            pub fn name() -> String { String::new() }
        }
        "#,
    );
    assert!(
        out.contains("using rusty::String"),
        "std String import must map to the runtime type\n{out}"
    );
    assert!(
        !out.contains("constexpr auto String ="),
        "std String import must not be hijacked as the Unsupported::String variant\n{out}"
    );
}

#[test]
fn test_ptr_returning_call_result_cast_to_int_uses_reinterpret() {
    // A call to a raw-pointer-returning fn imported from another module, cast to
    // an integer, must reinterpret (ptr->int): `static_cast<uintptr_t>(ptr)` is
    // ill-formed. The callee's return type is recovered via the import-aware
    // unique-leaf fallback even though the call site is in a different module.
    let out = transpile_str(
        r#"
        pub mod api { pub unsafe fn yaml_alloc(n: usize) -> *mut u8 { core::ptr::null_mut() } }
        pub mod user {
            use crate::api::yaml_alloc;
            pub unsafe fn f() -> usize { yaml_alloc(1) as usize }
        }
        "#,
    );
    assert!(out.contains("reinterpret_cast<std::uintptr_t>"), "{out}");
}

#[test]
fn test_forward_decl_qualifies_cross_namespace_type_through_fnptr_fallback() {
    // A free fn in one module taking a struct param from another module PLUS a
    // function-pointer-typedef param: the fn-ptr triggers the unresolved-path
    // fallback that drops cross-namespace qualification. The bare cross-namespace
    // struct type must still be namespace-qualified (not left bare/undeclared).
    let out = transpile_str(
        r#"
        pub mod yaml {
            pub struct yaml_emitter_t { pub x: i32 }
            pub type yaml_write_handler_t = unsafe fn(data: *mut core::ffi::c_void) -> i32;
        }
        pub mod api {
            pub unsafe fn yaml_emitter_set_output(
                emitter: *mut crate::yaml::yaml_emitter_t,
                handler: crate::yaml::yaml_write_handler_t,
            ) {}
        }
        "#,
    );
    // The emitter param must be qualified (::yaml:: or yaml::), never bare.
    assert!(
        out.contains("yaml::yaml_emitter_t* emitter"),
        "{out}"
    );
    assert!(!out.contains("(yaml_emitter_t* emitter"), "{out}");
}

#[test]
fn test_force_add_mul_lower_to_arithmetic() {
    // c2rust's `ops::ForceAdd::force_add` / `ForceMul::force_mul` (crate-declared
    // trait methods) must lower to parenthesized arithmetic, intercepted BEFORE
    // the UFCS trait dispatch (which would leave a `x.force_add(y)` member call
    // on a scalar). Operands parenthesized to preserve precedence.
    let out = transpile_str(
        r#"
        trait ForceAdd { fn force_add(self, rhs: Self) -> Self; }
        impl ForceAdd for u64 { fn force_add(self, rhs: u64) -> u64 { self + rhs } }
        fn f(a: u64, b: u64) -> u64 { a.force_add(b) }
        "#,
    );
    assert!(out.contains("((a) + (b))"), "{out}");
    assert!(!out.contains("a.force_add"), "{out}");
}

#[test]
fn test_c_like_enum_bare_variant_qualifies_to_scoped_form() {
    // A C-like enum whose name AND variants contain underscores, with variants
    // used bare (c2rust `use Enum::*` style). The match must compare against the
    // scoped `Enum::VARIANT` — C++20 enum-class variants are not flattened into
    // scope — and the owner lookup must not mis-split on the wrong underscore.
    let out = transpile_str(
        r#"
        pub enum yaml_parser_state_t {
            YAML_PARSE_STREAM_START_STATE = 0,
            YAML_PARSE_DOCUMENT_START_STATE = 1,
        }
        use yaml_parser_state_t::*;
        fn step(s: yaml_parser_state_t) -> i32 {
            match s {
                YAML_PARSE_STREAM_START_STATE => 1,
                YAML_PARSE_DOCUMENT_START_STATE => 2,
            }
        }
        "#,
    );
    assert!(
        out.contains("yaml_parser_state_t::YAML_PARSE_STREAM_START_STATE"),
        "{out}"
    );
    assert!(!out.contains("== YAML_PARSE_STREAM_START_STATE"), "{out}");
}

#[test]
fn test_c_offset_from_lowers_to_ptr_offset_from() {
    // c2rust's raw-pointer `PointerExt::c_offset_from(origin)` must lower to the
    // pointer-arithmetic helper with the receiver kept as a pointer — NOT to a
    // `(*ptr).c_offset_from(...)` member call (which fails: ptr isn't a struct),
    // and NOT to the winnow string/span `rusty::offset_from`.
    let out = transpile_str(
        r#"fn f(end: *const u8, start: *const u8) -> isize { end.c_offset_from(start) }"#,
    );
    assert!(out.contains("rusty::ptr::offset_from(end, start)"), "{out}");
    assert!(!out.contains("(*end).c_offset_from"), "{out}");
}

#[test]
fn test_byte_string_literal_cast_to_pointer_decays_to_static() {
    // In Rust `b"..."` is `&'static [u8; N]`; casting it to a raw pointer must
    // decay to static storage, NOT route the array value through
    // `static_cast<std::uintptr_t>(...)` (ill-formed: an array is not an integer).
    let out = transpile_str(r#"fn f() { let p = b"hi" as *const u8; }"#);
    assert!(out.contains("static const uint8_t _bs[]"), "{out}");
    assert!(
        !out.contains("static_cast<std::uintptr_t>(std::array"),
        "{out}"
    );
    assert!(out.contains("0x68")); // 'h'
}

