#[test]
fn test_leaf_smallvec_box_bool_deref_assignment_is_preserved() {
    let out = transpile_str(
        r#"
        struct PanicOnDoubleDrop { dropped: Box<bool> }
        impl Drop for PanicOnDoubleDrop {
            fn drop(&mut self) {
                if !!*self.dropped {
                    panic!("already dropped");
                }
                *self.dropped = true;
            }
        }
        "#,
    );
    // Deref of pointer-like fields may be emitted as `*x` or via the
    // helper `rusty::detail::deref_if_pointer_like(x)`.
    assert!(
        out.contains("if (!!*this->dropped)")
            || out.contains("if (!!(*this->dropped))")
            || out.contains("if (!!rusty::detail::deref_if_pointer_like(this->dropped))"),
        "{out}"
    );
    assert!(
        out.contains("*this->dropped = true;")
            || out.contains("rusty::detail::deref_if_pointer_like(this->dropped) = true;"),
        "{out}"
    );
    assert!(!out.contains("\n        this->dropped = true;"), "{out}");
}

