#[test]
fn test_leaf415_nested_tuple_variant_pattern_emits_bindings() {
    let out = transpile_str(
        r#"
        enum Either<L, R> { Left(L), Right(R) }
        impl<T, L, R> Either<(T, L), (T, R)> {
            fn factor_first(self) -> (T, Either<L, R>) {
                match self {
                    Left((t, l)) => (t, Left(l)),
                    Right((t, r)) => (t, Right(r)),
                }
            }
        }
        impl<T, L, R> Either<(L, T), (R, T)> {
            fn factor_second(self) -> (Either<L, R>, T) {
                match self {
                    Left((l, t)) => (Left(l), t),
                    Right((r, t)) => (Right(r), t),
                }
            }
        }
    "#,
    );

    // Tuple-variant bindings may use legacy `auto&& t = std::get<0>(_v._0);`
    // form or current index-based dispatch with `rusty::detail::deref_if_pointer`
    // wrappers.
    let legacy = out.contains("auto&& t = std::get<0>(_v._0);")
        && out.contains("auto&& l = std::get<1>(_v._0);")
        && out.contains("auto&& r = std::get<1>(_v._0);")
        && out.contains("auto&& l = std::get<0>(_v._0);")
        && out.contains("auto&& t = std::get<1>(_v._0);")
        && out.contains("auto&& r = std::get<0>(_v._0);");
    let new_form = out.contains("auto&& t = rusty::detail::deref_if_pointer(std::get<0>(")
        && out.contains("auto&& l = rusty::detail::deref_if_pointer(std::get<1>(")
        && out.contains("auto&& r = rusty::detail::deref_if_pointer(std::get<1>(");
    assert!(legacy || new_form, "{out}");
}

