#[test]
fn test_leaf4154333333332751_tuple_reference_string_view_coercion_materializes_temp() {
    let out = transpile_str(
        r#"
        struct ArrayString<const CAP: usize>;
        impl<const CAP: usize> ArrayString<CAP> {
            fn as_str(&self) -> &str { "" }
        }
        fn f(tmut: ArrayString<3>) {
            match (&"abc", &tmut) {
                (left, right) => {
                    let _ = left;
                    let _ = right;
                }
            };
        }
    "#,
    );
    // Coercion may produce `std::string_view(tmut.as_str())` materialized
    // into a temp, or the by-reference form `auto _m1 = &tmut;` where
    // the `ArrayString` is bound directly (no eager coercion).
    let coerced = out.contains("std::string_view(tmut.as_str())")
        && out.contains("_tmp = std::string_view(tmut.as_str());");
    let by_reference =
        out.contains("auto _m1 = &tmut;") || out.contains("auto&& _m1 = &tmut;");
    assert!(coerced || by_reference, "{out}");
    assert!(
        !out.contains(" = &std::string_view("),
        "must not take address of temporary string_view expression, output:\n{}",
        out
    );
}

