#[test]
fn test_leaf4160_self_assoc_alias_shadowed_into_iter_generic_path_elides_template_args() {
    let out = transpile_str(
        r#"
        trait IntoIterLike {
            type IntoIter;
            fn into_iter(self) -> Self::IntoIter;
        }
        struct IntoIter<T, const CAP: usize>(usize, ArrayVec<T, CAP>);
        struct ArrayVec<T, const CAP: usize>;
        impl<T, const CAP: usize> IntoIterLike for ArrayVec<T, CAP> {
            type IntoIter = IntoIter<T, CAP>;
            fn into_iter(self) -> IntoIter<T, CAP> {
                IntoIter(0, self)
            }
        }
        "#,
    );
    assert!(
        out.contains("using IntoIter = IntoIter<T, CAP>;")
            || out.contains("using IntoIter = ::IntoIter<T, CAP>;"),
        "{out}"
    );
    assert!(
        out.contains("IntoIter into_iter(")
            || out.contains("typename ArrayVec::IntoIter into_iter("),
        "{out}"
    );
    // The inherent struct method (no-arg `into_iter()`) must elide the template args.
    // Note: the UFCS free function legitimately uses the fully-qualified
    // `IntoIter<T, CAP> into_iter(ArrayVec<T, CAP> self_)` form (no struct alias in scope),
    // so we scope the absence check to the no-arg method form `into_iter()`.
    assert!(
        !out.contains("IntoIter<T, CAP> into_iter()")
            && !out.contains("typename ArrayVec::IntoIter<T, CAP> into_iter()"),
        "{out}"
    );
    // First arg may be bare `0` or wrapped in `static_cast<size_t>(0)`.
    assert!(
        out.contains("return IntoIter(0, std::move((*this)))")
            || out.contains("return typename ArrayVec::IntoIter(0, std::move((*this)))")
            || out.contains(
                "return IntoIter(static_cast<size_t>(0), std::move((*this)))"
            )
            || out.contains(
                "return typename ArrayVec::IntoIter(static_cast<size_t>(0), std::move((*this)))"
            ),
        "{out}"
    );
    assert!(
        !out.contains("return IntoIter<T, CAP>(0, std::move((*this)))")
            && !out
                .contains("return typename ArrayVec::IntoIter<T, CAP>(0, std::move((*this)))"),
        "{out}"
    );
}

