#[test]
fn test_char_classifier_methods_use_runtime_helpers() {
    // C++ char32_t is a primitive with no methods, so every Rust `char`
    // classifier must lower to a `char_runtime` free function.
    let cases = [
        ("is_alphabetic", "is_alphabetic"),
        ("is_alphanumeric", "is_alphanumeric"),
        ("is_numeric", "is_numeric"),
        ("is_uppercase", "is_uppercase"),
        ("is_lowercase", "is_lowercase"),
        ("is_control", "is_control"),
        ("is_ascii_alphanumeric", "is_ascii_alphanumeric"),
        ("is_ascii_uppercase", "is_ascii_uppercase"),
        ("is_ascii_hexdigit", "is_ascii_hexdigit"),
        ("to_ascii_uppercase", "to_ascii_uppercase"),
        ("to_ascii_lowercase", "to_ascii_lowercase"),
    ];
    for (method, helper) in cases {
        let src = format!("fn f(ch: char) -> bool {{ ch.{method}(); true }}");
        let out = transpile_str(&src);
        assert!(
            out.contains(&format!("rusty::char_runtime::{helper}(ch)")),
            "method {method}: {out}"
        );
        assert!(!out.contains(&format!("ch.{method}()")), "method {method}: {out}");
    }
}

#[test]
fn test_char_classifier_alone_emits_char_runtime_block() {
    // Regression: a module that uses a char classifier WITHOUT is_whitespace
    // must still emit the `char_runtime` helper block. A per-fn marker list
    // previously only recognized from_u32/len_utf8/encode_utf8/is_whitespace,
    // so `is_alphabetic` alone referenced an undefined `char_runtime::`.
    let out = transpile_str_module(
        "pub fn only_alpha(c: char) -> bool { c.is_alphabetic() }",
        "charmod",
    );
    assert!(
        out.contains("rusty::char_runtime::is_alphabetic("),
        "routing: {out}"
    );
    assert!(
        out.contains("namespace char_runtime {"),
        "char_runtime block must be emitted: {out}"
    );
}

#[test]
fn test_float_total_cmp_lowers_to_bit_ordering() {
    let out = transpile_str("pub fn f(x: f64, y: f64) -> std::cmp::Ordering { x.total_cmp(&y) }");
    assert!(out.contains("std::bit_cast<__I>"), "bit trick: {out}");
    assert!(out.contains("rusty::cmp::Ordering::Less"), "Ordering: {out}");
    assert!(!out.contains("x.total_cmp("), "no member call: {out}");
}

#[test]
fn test_format_arg_cast_lowers_via_smart_path() {
    // A cast arg (`v as f64`) must route to the smart format lowering so it
    // becomes static_cast, not the dumb pass-through that leaves Rust `as`
    // syntax (a C++ syntax error). Covers both plain `{}` and spec `{:e}`.
    for src in [
        "pub fn f(v: i32) -> String { format!(\"{}\", v as f64) }",
        "pub fn f(v: i32) -> String { format!(\"{:e}\", v as f64) }",
    ] {
        let out = transpile_str(src);
        assert!(out.contains("static_cast<double>(v)"), "cast lowered: {out}");
        assert!(!out.contains("v as f64"), "no raw Rust cast: {out}");
    }
    // `.as_str()` is NOT a cast — must not falsely trip the cast detector into
    // a behavior change (still lowers correctly either way).
    let s = transpile_str("pub fn f(x: &str) -> String { format!(\"{}\", x) }");
    assert!(s.contains("std::format"), "plain arg still formats: {s}");
    // Method-call arg (`v.len()`) must be lowered (rusty::len), not left as a
    // raw member call on a std::span (which has no `len`).
    let m = transpile_str("pub fn f(v: &[i32]) -> String { format!(\"{}\", v.len()) }");
    assert!(m.contains("rusty::len(v)"), "method-call arg lowered: {m}");
    assert!(!m.contains("v . len"), "no dumb pass-through: {m}");
    // Reference arg (`&x`) must not format a pointer — the smart path peels it.
    let r = transpile_str("pub fn f(x: i32) -> String { format!(\"{}\", &x) }");
    assert!(!r.contains("\" , & x"), "reference not passed as pointer: {r}");
    // if-expr arg must lower to a ternary, not leak Rust `if { } else { }`.
    let i = transpile_str(
        "pub fn f(x: i32) -> String { format!(\"{}\", if x > 0 { \"p\" } else { \"n\" }) }",
    );
    assert!(i.contains("? \"p\" : \"n\""), "if-expr lowered to ternary: {i}");
    assert!(!i.contains("if x > 0 {"), "no raw Rust if-expr: {i}");
}

#[test]
fn test_slice_rest_binding_binds_span_by_value() {
    // `[head, rest @ ..]` produces a rusty::slice(...) prvalue; binding it
    // through deref_if_pointer dangled (ASan stack-use-after-scope). The
    // subslice must bind BY VALUE.
    let out = transpile_str(
        "pub fn f(v: &[i32]) -> i32 { match v { [_h, rest @ ..] => rest.iter().sum(), [] => -1 } }",
    );
    assert!(out.contains("auto rest = rusty::slice("), "by-value span bind: {out}");
    assert!(
        !out.contains("deref_if_pointer(rusty::slice("),
        "no dangling deref wrap: {out}"
    );
}

#[test]
fn test_char_indices_prelude_advances_by_utf8_len() {
    // Rust char_indices yields BYTE offsets; the prelude iterator must
    // advance by each char's UTF-8 length, not by one per char.
    let out = transpile_str(
        "pub fn f(s: &str) -> usize { s.char_indices().count() }",
    );
    assert!(
        out.contains("code < 0x80 ? 1 : code < 0x800 ? 2 : code < 0x10000 ? 3 : 4"),
        "byte-length advance present in prelude: {out}"
    );
}

#[test]
fn test_ordering_combinators_route_to_cmp_free_fns() {
    // Ordering is a prelude enum class with no members — the combinators
    // must lower to rusty::cmp:: free fns.
    let t = transpile_str(
        "pub fn f(a: i32, b: i32, c: i32, d: i32) -> bool { a.cmp(&b).then(c.cmp(&d)).is_lt() }",
    );
    assert!(t.contains("rusty::cmp::then("), "then routed: {t}");
    assert!(t.contains("rusty::cmp::is_lt("), "is_lt routed: {t}");
    let r = transpile_str("pub fn f(a: i32, b: i32) -> bool { a.cmp(&b).reverse().is_ge() }");
    assert!(r.contains("rusty::cmp::reverse("), "reverse routed: {r}");
    // Slice .reverse() is NOT hijacked (non-Ordering receiver).
    let s = transpile_str("pub fn f(v: &mut [i32]) { v.reverse(); }");
    assert!(!s.contains("rusty::cmp::reverse"), "slice reverse untouched: {s}");
}

#[test]
fn test_u128_checked_and_bit_ops_transpile() {
    // 128-bit receivers route through the same helpers as narrower ints
    // (num.hpp now covers __int128: relaxed checked_* constraints + hi/lo
    // split bit-count overloads).
    let c = transpile_str("pub fn f(y: i128) -> Option<i128> { y.checked_mul(2) }");
    assert!(c.contains("rusty::checked_mul("), "checked_mul routed: {c}");
    let l = transpile_str("pub fn f(x: u128) -> u32 { x.leading_zeros() }");
    assert!(l.contains("rusty::leading_zeros(x)"), "leading_zeros routed: {l}");
}

#[test]
fn test_wrapping_ops_route_to_width_correct_helpers() {
    // wrapping_* must compute in the receiver's own width — the old size_t
    // detour truncated u128 and failed to wrap narrow types.
    let out = transpile_str("pub fn f(x: u8) -> u8 { x.wrapping_add(1) }");
    assert!(out.contains("rusty::wrapping_add(x,"), "helper routed: {out}");
    assert!(!out.contains("static_cast<size_t>(x) +"), "no size_t detour: {out}");
    let m = transpile_str("pub fn f(x: u128) -> u128 { x.wrapping_mul(3) }");
    assert!(m.contains("rusty::wrapping_mul(x,"), "u128 helper: {m}");
}

#[test]
fn test_string_pop_option_chain_transpiles() {
    // String::pop now returns Option<char>, so Rust's idiomatic
    // `.pop().map(..)`/`unwrap_or` chains type-check against the runtime.
    let out = transpile_str(
        "pub fn f(s: &mut String) -> u32 { s.pop().map(|c| c as u32).unwrap_or(0) }",
    );
    assert!(out.contains(".pop()"), "pop member: {out}");
    assert!(out.contains(".unwrap_or("), "option chain: {out}");
}

#[test]
fn test_char_from_digit_routes() {
    // char::from_digit was mis-lowered to `char_::from_digit` (bogus owner
    // from the keyword escape); it now routes to the char_runtime helper.
    let out = transpile_str(
        "pub fn f(d: u32) -> char { char::from_digit(d, 10).unwrap_or('?') }",
    );
    assert!(out.contains("rusty::char_runtime::from_digit("), "from_digit: {out}");
    assert!(!out.contains("char_::from_digit"), "no bogus owner: {out}");
}

#[test]
fn test_iter_constructors_and_mem_take_route() {
    // Terminals on call-form iterator constructors route to the rusty::
    // free fns (the constructors are recognized as iterator receivers).
    let o = transpile_str("pub fn f() -> i32 { std::iter::once(5).sum() }");
    assert!(o.contains("rusty::sum(rusty::once(5))"), "once+sum: {o}");
    let s = transpile_str(
        "pub fn f() -> i32 { std::iter::successors(Some(1), |&x| if x < 8 { Some(x * 2) } else { None }).sum() }",
    );
    assert!(s.contains("rusty::sum(rusty::successors(rusty::Option<int32_t>(1),"), "successors: {s}");
    let t = transpile_str("pub fn f(y: &mut i32) -> i32 { std::mem::take(y) }");
    assert!(t.contains("rusty::mem::take(y)"), "mem::take: {t}");
    assert!(!t.contains("std::mem::take"), "no verbatim std::mem: {t}");
}

#[test]
fn test_option_replace_insert_array_rotate() {
    // Array-literal locals with unambiguous element types are typed [T; N],
    // so fixed-array routing (rotate_left -> rusty::rotate_left) sees
    // through the binding. (Unsuffixed numeric literals stay untyped — the
    // usage-hint machinery owns their element type.)
    let r = transpile_str(
        "pub fn f() -> i32 { let mut w = [1i32, 2, 3, 4]; w.rotate_left(1); w[0] }",
    );
    assert!(r.contains("rusty::rotate_left(w, 1)"), "rotate routed: {r}");
    assert!(!r.contains("w.rotate_left("), "no member call: {r}");
    // get_or_insert_default binds as a REFERENCE so mutation reaches the
    // Option (a value binding would silently mutate a copy).
    let g = transpile_str(
        "pub fn f() -> i32 { let mut o: Option<i32> = None; let b = o.get_or_insert_default(); *b += 9; o.unwrap_or(0) }",
    );
    assert!(g.contains("auto& b = o.get_or_insert_default()"), "ref binding: {g}");
}

#[test]
fn test_inspect_fuse_position_find_closure_route() {
    let i = transpile_str("pub fn f(v: &[i32]) -> usize { v.iter().inspect(|_| {}).count() }");
    assert!(i.contains("rusty::inspect(rusty::iter(v),"), "inspect: {i}");
    assert!(i.contains("rusty::count("), "count after inspect: {i}");
    let fu = transpile_str("pub fn f(v: &[i32]) -> usize { v.iter().fuse().count() }");
    assert!(fu.contains("rusty::fuse(rusty::iter(v))"), "fuse: {fu}");
    // Option::inspect keeps the member call (not hijacked by the iterator route).
    let oi = transpile_str("pub fn f(o: Option<i32>) -> Option<i32> { o.inspect(|_| {}) }");
    assert!(oi.contains("o.inspect("), "Option::inspect member: {oi}");
    // position on a non-slice iterator routes to the member-first free fn.
    let p = transpile_str("pub fn f(s: &str) -> Option<usize> { s.chars().position(|c| c == 'x') }");
    assert!(p.contains("rusty::iter_position("), "position free fn: {p}");
    // str::find with a char predicate routes to the predicate overload.
    let fc = transpile_str("pub fn f(s: &str) -> Option<usize> { s.find(|c: char| c.is_ascii_digit()) }");
    assert!(fc.contains("rusty::str_runtime::find(s,"), "find-closure: {fc}");
}

#[test]
fn test_slice_ends_with_and_contains_ptr_guard() {
    // .ends_with routes to the rusty::ends_with dispatcher (member-first, so
    // string receivers keep their member behavior).
    let ew = transpile_str("pub fn f(v: &[i32]) -> bool { v.ends_with(&[5]) }");
    assert!(ew.contains("rusty::ends_with(v,"), "ends_with routed: {ew}");
    // The slice-contains IIFE gates its raw comparison arms on matching
    // pointer-ness so an addr_of_temp needle (int*) can't hit clang's
    // pointer-vs-integer requires quirk against int items.
    let ct = transpile_str("pub fn f(v: &[i32]) -> bool { v.contains(&3) }");
    assert!(ct.contains("_ptr_match"), "ptr guard present: {ct}");
}

#[test]
fn test_split_terminator_rsplitn_route() {
    let st = transpile_str("pub fn f(s: &str) -> usize { s.split_terminator(',').count() }");
    assert!(st.contains("rusty::str_runtime::split_terminator(s,"), "split_terminator: {st}");
    assert!(st.contains("rusty::count("), "iterator recognition: {st}");
    let rn = transpile_str("pub fn f(s: &str) -> usize { s.rsplitn(2, '.').count() }");
    assert!(rn.contains("rusty::str_runtime::rsplitn(s, 2,"), "rsplitn: {rn}");
    assert!(rn.contains("rusty::count("), "iterator recognition: {rn}");
}

#[test]
fn test_windows_chunks_peekable_route_to_free_fns() {
    // Slice windows/chunks -> rusty:: range helpers; recognized as iterators
    // so .count() wraps in rusty::count.
    for (src, marker) in [
        ("pub fn f(v: &[i32]) -> usize { v.windows(2).count() }", "rusty::windows(v, 2)"),
        ("pub fn f(v: &[i32]) -> usize { v.chunks(3).count() }", "rusty::chunks(v, 3)"),
    ] {
        let out = transpile_str(src);
        assert!(out.contains(marker), "marker {marker}: {out}");
        assert!(out.contains("rusty::count("), "iterator recognition: {out}");
    }
    // .peekable() on an iterator -> rusty::peekable free fn (constructs
    // iter_adapters::Peekable), not a bogus member call.
    let p = transpile_str("pub fn f(v: &[i32]) -> usize { v.iter().peekable().count() }");
    assert!(p.contains("rusty::peekable(rusty::iter(v))"), "peekable: {p}");
    assert!(!p.contains(").peekable()"), "no member call: {p}");
}

#[test]
fn test_iter_terminal_family_routes_to_free_fns() {
    // Item-Option terminals -> rusty::iter_* free fns (no bogus member calls
    // on the slice iterator type).
    for (src, marker, forbidden) in [
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().max() }", "rusty::iter_max(rusty::iter(v))", ".max()"),
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().min() }", "rusty::iter_min(rusty::iter(v))", ".min()"),
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().last() }", "rusty::iter_last(rusty::iter(v))", ".last()"),
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().nth(2) }", "rusty::iter_nth(rusty::iter(v), 2)", ".nth("),
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().max_by_key(|&&x| x) }", "rusty::iter_max_by_key(rusty::iter(v),", ".max_by_key("),
        ("pub fn f(v: &[i32]) -> Option<&i32> { v.iter().min_by_key(|&&x| x) }", "rusty::iter_min_by_key(rusty::iter(v),", ".min_by_key("),
        ("pub fn f(v: &[i32]) -> Option<i32> { v.iter().copied().reduce(|a, b| a + b) }", "rusty::iter_reduce(", ".reduce("),
    ] {
        let out = transpile_str(src);
        assert!(out.contains(marker), "marker {marker}: {out}");
        assert!(!out.contains(forbidden), "member call {forbidden}: {out}");
    }
    // Lazy predicate adapters route to free fns AND are recognized as
    // iterators (so .count() wraps in rusty::count).
    for (src, marker) in [
        ("pub fn f(v: &[i32]) -> usize { v.iter().skip_while(|&&x| x < 0).count() }", "rusty::skip_while(rusty::iter(v),"),
        ("pub fn f(v: &[i32]) -> usize { v.iter().take_while(|&&x| x > 0).count() }", "rusty::take_while(rusty::iter(v),"),
    ] {
        let out = transpile_str(src);
        assert!(out.contains(marker), "adapter {marker}: {out}");
        assert!(out.contains("rusty::count("), "iterator recognition: {out}");
    }
}

#[test]
fn test_iter_product_routes_to_free_fn() {
    // `.product()` must route to rusty::product like `.sum()` -> rusty::sum,
    // not a bogus member call on the slice iterator type.
    let p = transpile_str("pub fn f(v: &[i32]) -> i32 { v.iter().product() }");
    assert!(p.contains("rusty::product(rusty::iter(v))"), "product free fn: {p}");
    assert!(!p.contains(".product()"), "no member call: {p}");
    // Still works through an adapter chain.
    let m = transpile_str("pub fn f(v: &[i32]) -> i32 { v.iter().map(|x| x * 2).product() }");
    assert!(m.contains("rusty::product(rusty::map("), "product after map: {m}");
}

#[test]
fn test_str_rfind_rsplit_trim_matches_route() {
    // rfind -> str_runtime::rfind returning Option (parallel to find). The
    // negative patterns target the broken member-call-with-char-literal form
    // (`s.rfind(U'.')`) — the str_runtime prelude legitimately uses `s.rfind`
    // internally, so a bare substring check would false-positive on it.
    let rf = transpile_str("pub fn f(s: &str) -> Option<usize> { s.rfind('.') }");
    assert!(rf.contains("rusty::str_runtime::rfind(s,"), "rfind: {rf}");
    assert!(!rf.contains("s.rfind(U'"), "no member rfind: {rf}");
    // trim_matches -> str_runtime::trim_matches.
    let tm = transpile_str("pub fn f(s: &str) -> &str { s.trim_matches('x') }");
    assert!(tm.contains("rusty::str_runtime::trim_matches(s,"), "trim_matches: {tm}");
    assert!(!tm.contains("s.trim_matches(U'"), "no member trim_matches: {tm}");
    // rsplit -> str_runtime::rsplit iterator; .count() routes to rusty::count.
    let rs = transpile_str("pub fn f(s: &str) -> usize { s.rsplit('.').count() }");
    assert!(rs.contains("rusty::str_runtime::rsplit(s,"), "rsplit: {rs}");
    assert!(rs.contains("rusty::count("), "rsplit is an iterator: {rs}");
    assert!(!rs.contains("s.rsplit(U'"), "no member rsplit: {rs}");
    // char_indices is now recognized as an iterator, so .count() wraps in
    // rusty::count instead of calling a nonexistent CharIndices::count member.
    let ci = transpile_str("pub fn f(s: &str) -> usize { s.char_indices().count() }");
    assert!(ci.contains("rusty::count(rusty::str_runtime::char_indices(s))"), "char_indices iterator: {ci}");
    assert!(!ci.contains("char_indices(s).count()"), "no member count on CharIndices: {ci}");
}

#[test]
fn test_option_zip_routes_to_member_not_iterator_adapter() {
    // On an Option receiver, `.zip(other)` is the Option member returning
    // Option<(T,U)>, NOT the iterator adapter rusty::zip.
    let out = transpile_str(
        "pub fn f(a: Option<i32>, b: Option<i32>) -> Option<(i32, i32)> { a.zip(b) }",
    );
    assert!(out.contains("a.zip("), "member call: {out}");
    assert!(!out.contains("rusty::zip(a"), "must not route Option to rusty::zip: {out}");
}

#[test]
fn test_float_rest_and_int_bytes_lower() {
    // Float methods with no <cmath> counterpart.
    for (src, marker, call) in [
        ("pub fn f(x: f64) -> f64 { x.next_up() }", "std::nextafter(__v, std::numeric_limits", "x.next_up()"),
        ("pub fn f(x: f64) -> f64 { x.next_down() }", "-std::numeric_limits", "x.next_down()"),
        ("pub fn f(x: f64) -> f64 { x.abs_sub(1.0) }", "std::fdim(x, 1.0)", "x.abs_sub("),
    ] {
        let out = transpile_str(src);
        assert!(out.contains(marker), "marker {marker}: {out}");
        assert!(!out.contains(call), "member call {call}: {out}");
    }
    // to_int_unchecked::<I>() -> a plain cast to the turbofish target.
    let ti = transpile_str("pub fn f(x: f64) -> i32 { unsafe { x.to_int_unchecked::<i32>() } }");
    assert!(ti.contains("static_cast<int32_t>(x)"), "to_int_unchecked: {ti}");
    assert!(!ti.contains("to_int_unchecked<"), "no member call: {ti}");

    // Integer byte-array conversions + ilog(base) + checked_next_multiple_of.
    for (src, marker, call) in [
        ("pub fn f(x: u32) -> [u8; 4] { x.to_ne_bytes() }", "std::bit_cast<std::array<uint8_t, sizeof(__v)>>(__v)", "x.to_ne_bytes()"),
        ("pub fn f(x: u32) -> [u8; 4] { x.to_le_bytes() }", "std::endian::little", "x.to_le_bytes()"),
        ("pub fn f(x: u32) -> [u8; 4] { x.to_be_bytes() }", "std::endian::big", "x.to_be_bytes()"),
        ("pub fn f(x: u32) -> u32 { x.ilog(3) }", "__v /= __base", "x.ilog("),
        ("pub fn f(x: u32) -> Option<u32> { x.checked_next_multiple_of(8) }", "rusty::checked_next_multiple_of(x,", "x.checked_next_multiple_of("),
    ] {
        let out = transpile_str(src);
        assert!(out.contains(marker), "marker {marker}: {out}");
        assert!(!out.contains(call), "member call {call}: {out}");
    }
}

#[test]
fn test_bool_then_int_midpoint_u8_ascii_lower() {
    let ts = transpile_str("pub fn f(b: bool) -> Option<i32> { b.then_some(7) }");
    assert!(ts.contains("rusty::Option<__T>(__tv)") && !ts.contains("b.then_some("), "then_some: {ts}");
    let th = transpile_str("pub fn f(c: bool) -> Option<i32> { c.then(|| 5) }");
    assert!(th.contains("rusty::Option<__T>") && !th.contains("c.then("), "then: {th}");
    let mp = transpile_str("pub fn f(x: u32) -> u32 { x.midpoint(10) }");
    assert!(mp.contains("(__a & __b)") && !mp.contains("x.midpoint("), "midpoint: {mp}");
    let ia = transpile_str("pub fn f(x: u8) -> bool { x.is_ascii() }");
    assert!(ia.contains("<= 0x7F") && !ia.contains("x.is_ascii()"), "is_ascii: {ia}");
    let iu = transpile_str("pub fn f(x: u8) -> bool { x.is_ascii_uppercase() }");
    assert!(iu.contains("rusty::char_runtime::is_ascii_uppercase") && !iu.contains("x.is_ascii_uppercase()"), "u8 is_ascii_uppercase: {iu}");
    let tu = transpile_str("pub fn f(x: u8) -> u8 { x.to_ascii_uppercase() }");
    assert!(tu.contains("__c - 32") && !tu.contains("x.to_ascii_uppercase()"), "u8 to_ascii_uppercase: {tu}");
}

