#[test]
fn test_str_case_and_repeat_methods_materialize_string() {
    // &str is std::string_view in C++ and lacks these members; materialize a
    // rusty::String (which has them).
    let up = transpile_str("pub fn f(s: &str) -> String { s.to_uppercase() }");
    assert!(up.contains("rusty::String::from(s).to_uppercase()"), "{up}");
    let lo = transpile_str("pub fn f(s: &str) -> String { s.to_lowercase() }");
    assert!(lo.contains("rusty::String::from(s).to_lowercase()"), "{lo}");
    let rep = transpile_str("pub fn f(s: &str) -> String { s.repeat(3) }");
    assert!(rep.contains("rusty::String::from(s).repeat(3)"), "{rep}");
    for call in ["s.to_uppercase()", "s.to_lowercase()", "s.repeat(3)"] {
        assert!(!up.contains(call) || !lo.contains(call) || !rep.contains(call));
    }
}

#[test]
fn test_more_numeric_methods_lower_without_member_calls() {
    // clamp → std::clamp with a unified template arg.
    let clamp = transpile_str("pub fn f(x: i64) -> i64 { x.clamp(0, 100) }");
    assert!(clamp.contains("std::clamp<std::remove_cvref_t<decltype(x)>>(x, 0, 100)"), "{clamp}");

    // Float specials.
    let recip = transpile_str("pub fn f(x: f64) -> f64 { x.recip() }");
    assert!(recip.contains("(1.0 / x)"), "recip: {recip}");
    let deg = transpile_str("pub fn f(x: f64) -> f64 { x.to_degrees() }");
    assert!(deg.contains("180.0 / 3.14159"), "to_degrees: {deg}");
    let mul_add = transpile_str("pub fn f(x: f64) -> f64 { x.mul_add(2.0, 1.0) }");
    assert!(mul_add.contains("std::fma(x, 2.0, 1.0)"), "mul_add: {mul_add}");
    let fract = transpile_str("pub fn f(x: f64) -> f64 { x.fract() }");
    assert!(fract.contains("std::trunc(__v)"), "fract: {fract}");

    // signum / rem_euclid / div_euclid must not stay member calls.
    for (m, call) in [
        ("signum", "x.signum()"),
        ("rem_euclid", "x.rem_euclid(3)"),
        ("div_euclid", "x.div_euclid(3)"),
    ] {
        let out = transpile_str(&format!("pub fn f(x: i32) -> i32 {{ {call} }}"));
        assert!(!out.contains(call), "method {m} still a member call: {out}");
    }
}

#[test]
fn test_dbg_macro_preserves_value_and_handles_empty() {
    // Expression position: `dbg!(e)` returns the value (was dropped as a comment).
    let expr = transpile_str("pub fn f() -> i32 { let y = dbg!(21 + 21); y }");
    assert!(expr.contains("auto y = (21 + 21)"), "value preserved: {expr}");
    assert!(!expr.contains("/* dbg!"), "no comment: {expr}");
    // Statement position: `dbg!()` must not emit a malformed trailing-comma call.
    let empty = transpile_str("pub fn g() { dbg!(); }");
    assert!(
        !empty.contains(r#"std::println(stderr, "{}", )"#),
        "no malformed empty dbg: {empty}"
    );
}

#[test]
fn test_float_math_methods_lower_to_cmath() {
    // C++ double/float are primitives — Rust float math methods must lower to
    // <cmath> free functions. Gated on a statically-known float receiver.
    let cases = [
        ("sqrt", "std::sqrt(x)"),
        ("sin", "std::sin(x)"),
        ("cos", "std::cos(x)"),
        ("floor", "std::floor(x)"),
        ("ceil", "std::ceil(x)"),
        ("round", "std::round(x)"),
        ("trunc", "std::trunc(x)"),
        ("abs", "std::fabs(x)"),
        ("ln", "std::log(x)"),
        ("exp", "std::exp(x)"),
        ("log10", "std::log10(x)"),
    ];
    for (method, expected) in cases {
        let src = format!("pub fn f(x: f64) -> f64 {{ x.{method}() }}");
        let out = transpile_str(&src);
        assert!(out.contains(expected), "method {method}: {out}");
        assert!(!out.contains(&format!("x.{method}()")), "method {method}: {out}");
    }
    // Binary-arg forms.
    let powi = transpile_str("pub fn f(x: f64) -> f64 { x.powi(2) }");
    assert!(powi.contains("std::pow(x, 2)"), "powi: {powi}");
    let powf = transpile_str("pub fn f(x: f64) -> f64 { x.powf(2.5) }");
    assert!(powf.contains("std::pow(x, 2.5)"), "powf: {powf}");
    let hypot = transpile_str("pub fn f(x: f64, y: f64) -> f64 { x.hypot(y) }");
    assert!(hypot.contains("std::hypot(x, y)"), "hypot: {hypot}");

    // Integer receivers must NOT be hijacked (no float lowering for ints).
    let int_pow = transpile_str("pub fn f(x: u32) -> u32 { x.pow(2) }");
    assert!(!int_pow.contains("std::pow(x"), "int pow untouched: {int_pow}");
}

#[test]
fn test_write_writeln_macros_lower_to_write_fmt() {
    // write!/writeln! previously fell through to `/* write!(…) */`, so a chained
    // `.unwrap()` produced ill-formed C++. They now lower to rusty::write_fmt.
    let w = transpile_str_module(
        r#"pub fn f(buf: &mut String, x: i32) { write!(buf, "val {}", x).unwrap(); }"#,
        "wmod",
    );
    assert!(
        w.contains(r#"rusty::write_fmt(buf, std::format("val {}", x)).unwrap()"#),
        "write!: {w}"
    );
    assert!(!w.contains("/* write!"), "no comment fallback: {w}");
    // The fmt::Write dispatch block must be pulled in.
    assert!(w.contains("Result write_fmt(Writer"), "write_fmt block: {w}");

    // writeln! appends a newline and still honors inline captures.
    let wl = transpile_str_module(
        r#"pub fn f(buf: &mut String, x: i32) { writeln!(buf, "line {x}").unwrap(); }"#,
        "wlmod",
    );
    assert!(
        wl.contains(r#"rusty::write_fmt(buf, std::format("line {0}", x) + std::string("\n")).unwrap()"#),
        "writeln!: {wl}"
    );

    // writeln!(buf) with no format writes just the newline.
    let wl0 = transpile_str_module(
        r#"pub fn f(buf: &mut String) { writeln!(buf).unwrap(); }"#,
        "wl0mod",
    );
    assert!(
        wl0.contains(r#"rusty::write_fmt(buf, std::string() + std::string("\n")).unwrap()"#),
        "writeln!(buf): {wl0}"
    );
}

