fn test_leaf5142_iterator_skip_lowers_to_runtime_helper() {
    let out = transpile_str(
        r#"
        fn f() {
            let mut v = Vec::<u8>::new();
            let _ = v.into_iter().skip(1);
        }
    "#,
    );
    // `into_iter()` may stay as method call or be bridged via `rusty::iter(std::move(v))`.
    assert!(
        out.contains("rusty::skip(v.into_iter(), 1)")
            || out.contains("rusty::skip(rusty::iter(std::move(v)), 1)")
            || out.contains("rusty::skip(rusty::iter(v), 1)"),
        "{out}"
    );
    assert!(!out.contains("v.into_iter().skip(1)"), "{out}");
}

