#[test]
fn test_private_namespace_alias_precedes_reexported_forward_decl_signature() {
    let file: syn::File = syn::parse_str(
        r#"
        extern crate serde_core;
        use serde_core::__private228 as serde_core_private;

        mod private {
            pub mod de {
                pub use self::content::Content;

                pub mod content {
                    pub use crate::serde_core_private::Content;
                }

                pub fn take(content: Content) {}
            }
        }

        pub mod __private228 {
            pub struct Content;
        }
        "#,
    )
    .unwrap();
    let mut cg = CodeGen::new();
    let mut aliases = HashMap::new();
    aliases.insert("serde_core".to_string(), String::new());
    cg.set_external_crate_module_aliases(aliases);
    cg.emit_file(&file, Some("serde"));
    let out = cg.into_output();

    let alias_pos = out
        .find("namespace serde_core_private = ::__private228;")
        .expect("missing early private namespace alias");
    let sig_alias = "void take(serde_core_private::Content content);";
    let sig_private_root = "void take(::__private228::Content content);";
    let sig_pos = out
        .find(sig_alias)
        .or_else(|| out.find(sig_private_root))
        .unwrap_or_else(|| {
            panic!(
                "missing rewritten forward declaration `{sig_alias}` or `{sig_private_root}`\n{out}"
            )
        });
    assert!(
        alias_pos < sig_pos,
        "private namespace alias must precede forward declaration:\n{out}"
    );
    assert!(
        !out.contains("void take(::private_::de::content::Content content);"),
        "forward declaration should use the imported re-export target:\n{out}"
    );
    assert!(
        !out.contains("crate::serde_core_private::Content"),
        "crate root should not leak into C++ type spelling:\n{out}"
    );
}

