#[test]
fn test_leaf5158_ptr_write_value_arg_marks_local_as_consumed() {
    let out = transpile_str(
        r#"
        fn f(mut opt: Option<Box<i32>>, p: *mut Box<i32>) {
            let element = match opt.take() {
                Some(x) => x,
                None => return,
            };
            unsafe {
                std::ptr::write(p, element);
            }
        }
        "#,
    );
    assert!(out.contains("auto element ="), "{out}");
    // Some-arm consumption may use `std::move(x)` (binding-named) or
    // forward `_mv` directly through `_match_value.emplace`.
    assert!(
        out.contains("std::move(x)")
            || out.contains("_match_value.emplace(std::forward<decltype(_mv)>(_mv))"),
        "{out}"
    );
    assert!(!out.contains("auto element = x;"), "{out}");
    assert!(!out.contains("const auto element ="), "{out}");
    assert!(out.contains("rusty::ptr::write"), "{out}");
    assert!(out.contains("std::move(element)"), "{out}");
}

#[test]
fn test_leaf5158_match_break_initializer_moves_consumed_success_binding() {
    let out = transpile_str(
        r#"
        fn f(mut iter: std::vec::IntoIter<Box<i32>>, p: *mut Box<i32>) {
            let mut n = 0;
            while n < 1 {
                let element = match iter.next() {
                    Some(x) => x,
                    None => break,
                };
                unsafe {
                    std::ptr::write(p, element);
                }
                n += 1;
            }
        }
        "#,
    );
    // Element binding may come from direct `auto element = std::move(x)`
    // (legacy IIFE) or via stmt-expr `_match_value.emplace(std::move(x))`
    // + `auto element = std::move(_match_value).value()`.
    assert!(
        out.contains("auto element = std::move(x);")
            || (out.contains("_match_value.emplace(std::move(x));")
                && out.contains("auto element = std::move(_match_value).value();")),
        "{out}"
    );
    assert!(!out.contains("auto element = x;"), "{out}");
}

