#[test]
fn test_leaf41543333333181_result_tuple_match_uses_context_typed_ctor_and_direct_equality() {
    let out = transpile_str(
        r#"
        fn f(v: Result<i32, i32>) {
            match (&v, &Ok(1)) {
                (left_val, right_val) => {
                    let _same = *left_val == *right_val;
                }
            };
        }
    "#,
    );
    // The comparison may keep the dereference (`*left_val == *right_val`)
    // or the bindings may already be deref-collapsed at extraction time,
    // leaving a bare `left_val == right_val`.
    assert!(
        out.contains("*left_val == *right_val")
            || out.contains("left_val == right_val"),
        "{out}"
    );
    // The Ok constructor may pass arg bare or wrapped in static_cast,
    // and may be qualified or use the context-derived alias.
    assert!(
        out.contains("_ResultCtorCtx::Ok_compat(1)")
            || out.contains("rusty::Result<int32_t, int32_t>::Ok(1)")
            || out.contains("_ResultCtorCtx::Ok_compat(static_cast<int32_t>(1))")
            || out.contains("rusty::Result<int32_t, int32_t>::Ok(static_cast<int32_t>(1))"),
        "{out}"
    );
    assert!(!out.contains("auto _m1_tmp = Ok("));
}

