#[test]
fn test_leaf41543333333101_std_optional_like_methods_lower_to_optional_surface() {
    let out = transpile_str(
        r#"
        fn f() {
            let x = Some(1);
            let _a = x.is_some();
            let _b = x.is_none();
            let _c = x.unwrap();
        }
    "#,
    );
    // `rusty::Option<T>` exposes both `has_value()`/`value()` (std::optional
    // compatibility) and `is_some()`/`is_none()`/`unwrap()` (Rust style).
    // The codegen now preserves the Rust spelling at the call site.
    assert!(
        out.contains("x.has_value()") || out.contains("x.is_some()"),
        "{out}"
    );
    assert!(
        out.contains("!x.has_value()") || out.contains("x.is_none()"),
        "{out}"
    );
    assert!(
        out.contains("x.value()") || out.contains("x.unwrap()"),
        "{out}"
    );
}

