#[test]
fn test_typed_let_variant_constructor_left_gets_template_args() {
    let out = transpile_str(
        r#"
        enum Either<L, R> { Left(L), Right(R) }
        fn f() { let e: Either<i32, i32> = Left(2); }
    "#,
    );
    // Variant ctor may be free-function form (`Left<...>(2)`) or
    // expanded-wrapper form, with arg bare or wrapped in static_cast.
    let free = out.contains("const Either<int32_t, int32_t> e = Left<int32_t, int32_t>(2);")
        || out.contains(
            "const Either<int32_t, int32_t> e = Left<int32_t, int32_t>(static_cast<int32_t>(2));"
        );
    let wrapped = out.contains(
        "const Either<int32_t, int32_t> e = Either<int32_t, int32_t>{Either_Left<int32_t, int32_t>{static_cast<int32_t>(2)}};",
    );
    assert!(free || wrapped, "{out}");
}

