    // `Either<L, R>{Either_Left<L, R>{static_cast<int32_t>(2)}}`.
    let free_left = out.contains("const auto e = Left<int32_t, int32_t>(2);");
    let wrapper_left = out.contains(
        "const auto e = Either<int32_t, int32_t>{Either_Left<int32_t, int32_t>{static_cast<int32_t>(2)}};",
    );
