#[test]
fn test_untyped_shadow_blocks_outer_assignment_type_context() {
    let out = transpile_str(
        r#"
        enum Either<L, R> { Left(L), Right(R) }
        fn f() {
            let mut e: Either<i32, i32> = Left(1);
            {
                let mut e = Left(3);
                e = Right(4);
            }
            e = Right(2);
        }
    "#,
    );
    // Variant ctor may be free-function or expanded-wrapper form, and
    // the inner `e` may be shadowed via `e_shadow1`.
    let inner_free = out.contains("e = Right<int32_t, int32_t>(4);")
        || out.contains("e = Right<int32_t, int32_t>(static_cast<int32_t>(4));")
        || out.contains("e_shadow1 = Right<int32_t, int32_t>(4);")
        || out.contains("e_shadow1 = Right<int32_t, int32_t>(static_cast<int32_t>(4));");
    let inner_wrapped = out.contains(
        "e = Either<int32_t, int32_t>{Either_Right<int32_t, int32_t>{static_cast<int32_t>(4)}};",
    ) || out.contains(
        "e_shadow1 = Either<int32_t, int32_t>{Either_Right<int32_t, int32_t>{static_cast<int32_t>(4)}};",
    );
    assert!(inner_free || inner_wrapped, "{out}");
    let outer_free = out.contains("e = Right<int32_t, int32_t>(2);")
        || out.contains("e = Right<int32_t, int32_t>(static_cast<int32_t>(2));");
    let outer_wrapped = out.contains(
        "e = Either<int32_t, int32_t>{Either_Right<int32_t, int32_t>{static_cast<int32_t>(2)}};",
    );
    assert!(outer_free || outer_wrapped, "{out}");
}

