#[test]
fn test_leaf5191_tuple_match_deref_temporary_materializes_before_address() {
    let out = transpile_str(
        r#"
        use std::ops::Deref;

        struct BoxI32 { value: i32 }

        impl Deref for BoxI32 {
            type Target = i32;
            fn deref(&self) -> &Self::Target { &self.value }
        }

        fn mk() -> BoxI32 { BoxI32 { value: 1 } }

        fn f() {
            match (&*mk(), &1) {
                (left_val, right_val) => {
                    let _ = *left_val == *right_val;
                }
            };
        }
    "#,
    );
    // Deref of pointer-like return values may use C-style `*` or the
    // `rusty::detail::deref_if_pointer_like(...)` helper.
    assert!(
        out.contains("auto _m0_tmp = *mk();")
            || out.contains("auto _m0_tmp = *::mk();")
            || out.contains("auto _m0_tmp = rusty::detail::deref_if_pointer_like(mk());")
            || out.contains("auto _m0_tmp = rusty::detail::deref_if_pointer_like(::mk());"),
        "{out}"
    );
    assert!(out.contains("auto _m0 = &_m0_tmp;"), "{out}");
    assert!(!out.contains("auto _m0 = &*mk();"), "{out}");
}

#[test]
fn test_leaf5191_tuple_match_deref_method_call_temporary_materializes_before_address() {
    let out = transpile_str(
        r#"
        use std::ops::Deref;

        struct BoxI32 { value: i32 }
        struct Holder;

        impl Deref for BoxI32 {
            type Target = i32;
            fn deref(&self) -> &Self::Target { &self.value }
        }

        impl Holder {
            fn swap_remove(&mut self, _: usize) -> BoxI32 { BoxI32 { value: 1 } }
        }

        fn f() {
            let mut v = Holder;
            match (&*v.swap_remove(1), &1) {
                (left_val, right_val) => {
                    let _ = *left_val == *right_val;
                }
            };
        }
    "#,
    );
    // Deref of method-call return may use C-style `*` or the
    // `deref_if_pointer_like` helper; the literal may be wrapped in
    // `static_cast<size_t>(...)`.
    assert!(
        out.contains("auto _m0_tmp = *v.swap_remove(1);")
            || out.contains(
                "auto _m0_tmp = rusty::detail::deref_if_pointer_like(v.swap_remove(1));"
            )
            || out.contains(
                "auto _m0_tmp = rusty::detail::deref_if_pointer_like(v.swap_remove(static_cast<size_t>(1)));"
            ),
        "{out}"
    );
    assert!(
        !out.contains("auto&& _m0_tmp = *v.swap_remove(1);"),
        "{out}"
    );
    assert!(out.contains("auto _m0 = &_m0_tmp;"), "{out}");
}

