#[test]
fn test_leaf10529_module_mode_option_none_avoids_assoc_ctor_type_in_value_position() {
    let out = transpile_str_module(
        r#"
        trait IteratorLike { type Item; fn next(self) -> Option<Self::Item>; }
        enum IterEither<L, R> { Left(L), Right(R) }
        impl<L: IteratorLike, R: IteratorLike<Item = L::Item>> IteratorLike for IterEither<L, R> {
            type Item = L::Item;
            fn next(self) -> Option<IterEither::Item> { None }
        }
    "#,
        "either",
    );
    // `None` may lower to `std::nullopt` (legacy),
    // `rusty::Option<auto>{rusty::None}` (intermediate), or bare
    // `rusty::None` (current — relies on implicit Option conversion).
    assert!(
        out.contains("return std::nullopt;")
            || out.contains("return rusty::Option<auto>{rusty::None};")
            || out.contains("return rusty::Option<auto>(rusty::None);")
            || out.contains("return rusty::None;"),
        "{out}"
    );
    // Negative: must NOT have an unresolved assoc-type spelling in the
    // ctor type. These shapes break C++ semantics regardless of
    // None/nullopt spelling.
    assert!(!out.contains("rusty::Option<typename IterEither::Item>(rusty::None)"), "{out}");
    assert!(!out.contains("rusty::Option<IterEither::Item>(rusty::None)"), "{out}");
}

