#[test]
fn test_leaf5202_map_deserialize_uses_self_value_for_next_entry() {
    let out = transpile_str(
        r#"
        mod value {
            pub struct Value;
            pub struct Map<K, V> {
                key: K,
                value: V,
            }
            impl<K, V> Map<K, V> {
                fn new() -> Map<K, V> {
                    loop {}
                }
                fn insert(&mut self, key: K, value: V) {}
            }
            pub mod de {
                pub trait Deserialize<'de> {}
                pub trait Deserializer<'de> {
                    type Error;
                    fn deserialize_map<V>(self, visitor: V) -> Result<V::Value, Self::Error>
                    where
                        V: Visitor<'de>;
                }
                pub trait Visitor<'de> {
                    type Value;
                }
                pub trait MapAccess<'de> {
                    type Error;
                    fn next_entry<K, V>(&mut self) -> Result<Option<(K, V)>, Self::Error>;
                }
            }
            impl<'de> de::Deserialize<'de> for Map<String, Value> {
                fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
                where
                    D: de::Deserializer<'de>,
                {
                    struct Visitor;
                    impl<'de> de::Visitor<'de> for Visitor {
                        type Value = Map<String, Value>;
                        fn visit_map<V>(self, mut visitor: V) -> Result<Self::Value, V::Error>
                        where
                            V: de::MapAccess<'de>,
                        {
                            let mut values = Map::new();
                            while let Some((key, value)) = match visitor.next_entry() {
                                Ok(val) => val,
                                Err(err) => return Err(err),
                            } {
                                values.insert(key, value);
                            }
                            Ok(values)
                        }
                    }
                    deserializer.deserialize_map(Visitor)
                }
            }
        }
    "#,
    );
    assert!(
        out.contains("Map<rusty::String, value::Value>::new_()")
            || out.contains("Map<rusty::String, ::value::Value>::new_()")
            || out.contains("Map<String, value::Value>::new_()")
            || out.contains("Map<rusty::String, Value>::new_()"),
        "expected Map::new to use Self::Value's concrete map type, got:\n{}",
        out
    );
    assert!(
        out.contains("next_entry<rusty::String, value::Value>")
            || out.contains("next_entry<rusty::String, ::value::Value>")
            || out.contains("next_entry<String, value::Value>")
            || out.contains("next_entry<rusty::String, Value>"),
        "expected next_entry template args from concrete Self::Value map type, got:\n{}",
        out
    );
    assert!(!out.contains("Map<rusty::String, V>::new_()"), "{out}");
    assert!(!out.contains("next_entry<rusty::String, value>"), "{out}");
}

#[test]
fn test_leaf5202_map_new_in_mapaccess_where_clause_uses_object_value_type() {
    let out = transpile_str(
        r#"
        mod value {
            pub enum Value {
                Object(Map<String, Value>),
            }
            pub struct Map<K, V> {
                key: K,
                value: V,
            }
            impl<K, V> Map<K, V> {
                fn new() -> Map<K, V> {
                    loop {}
                }
                fn insert(&mut self, key: K, value: V) {}
            }
            pub mod de {
                use super::{Map, Value};
                pub enum KeyClass {
                    Map(String),
                }
                pub struct KeyClassifier;
                pub trait MapAccess<'de> {
                    type Error;
                    fn next_key_seed(&mut self, seed: KeyClassifier) -> Result<Option<KeyClass>, Self::Error>;
                    fn next_value<T>(&mut self) -> Result<T, Self::Error>;
                    fn next_entry<K, V>(&mut self) -> Result<Option<(K, V)>, Self::Error>;
                }
                pub struct ValueVisitor;
                impl ValueVisitor {
                    fn visit_map<'de, V>(self, mut visitor: V) -> Result<Value, V::Error>
                    where
                        V: MapAccess<'de>,
                    {
                        match match visitor.next_key_seed(KeyClassifier) {
                            Ok(val) => val,
                            Err(err) => return Err(err),
                        } {
                            Some(KeyClass::Map(first_key)) => {
                                let mut values = Map::new();
                                values.insert(first_key, match visitor.next_value() {
                                    Ok(val) => val,
                                    Err(err) => return Err(err),
                                });
                                while let Some((key, value)) = match visitor.next_entry() {
                                    Ok(val) => val,
                                    Err(err) => return Err(err),
                                } {
                                    values.insert(key, value);
                                }
                                Ok(Value::Object(values))
                            }
                            None => Ok(Value::Object(Map::new())),
                        }
                    }
                }
            }
        }
    "#,
    );
    assert!(
        out.contains("Map<rusty::String, value::Value>::new_()")
            || out.contains("Map<rusty::String, ::value::Value>::new_()")
            || out.contains("Map<String, value::Value>::new_()"),
        "expected Map::new in MapAccess visitor to use object map type, got:\n{}",
        out
    );
    assert!(
        out.contains("values.insert(std::move(first_key)")
            || out.contains("values.insert(rusty::clone(first_key)"),
        "expected first map key to be consumed without copying, got:\n{}",
        out
    );
    assert!(
        out.contains("next_entry<rusty::String, value::Value>")
            || out.contains("next_entry<rusty::String, ::value::Value>")
            || out.contains("next_entry<String, value::Value>"),
        "expected next_entry template args from map insert usage, got:\n{}",
        out
    );
    assert!(!out.contains("Map<V, V>::new_()"), "{out}");
}

#[test]
fn test_leaf5202_deserialize_method_generic_shadowing_owner_param_is_renamed() {
    let out = transpile_str(
        r#"
        trait Visitor {
            type Value;
        }
        trait Deserializer {
            type Error;
            fn deserialize_bool<V>(self, visitor: V) -> Result<V::Value, Self::Error>
            where
                V: Visitor;
        }
        struct Map<K, V> {
            key: K,
            value: V,
        }
        impl<K, V> Deserializer for Map<K, V> {
            type Error = ();
            fn deserialize_bool<V>(self, visitor: V) -> Result<V::Value, Self::Error>
            where
                V: Visitor,
            {
                loop {}
            }
        }
    "#,
    );
    assert!(
        out.contains("template<typename V_"),
        "expected shadowing method generic to be renamed, got:\n{}",
        out
    );
    assert!(
        out.contains("rusty::Result<typename V_::Value,")
            && out.contains("deserialize_bool(V_ visitor)"),
        "expected visitor Value and parameter to use renamed method generic, got:\n{}",
        out
    );
    assert!(
        !out.contains("rusty::Result<typename V::Value, Error> deserialize_bool(V visitor)")
            && !out.contains(
                "rusty::Result<typename V::Value, typename Map<K, V>::Error> deserialize_bool(V visitor)"
            ),
        "deserialize method must not bind visitor Value to owner V, got:\n{}",
        out
    );
}

