#[test]
fn test_leaf437_as_ref_as_mut_reference_constructor_args_are_not_moved() {
    let out = transpile_str(
        r#"
        enum Either<L, R> { Left(L), Right(R) }
        impl<L, R> Either<L, R> {
            fn as_ref(&self) -> Either<&L, &R> {
                match *self {
                    Either::Left(ref inner) => Left(inner),
                    Either::Right(ref inner) => Right(inner),
                }
            }
            fn as_mut(&mut self) -> Either<&mut L, &mut R> {
                match *self {
                    Either::Left(ref mut inner) => Left(inner),
                    Either::Right(ref mut inner) => Right(inner),
                }
            }
        }
    "#,
    );
    // Variant ctor may use the legacy free-function form (`Either<...>(Left<...>(inner))`)
    // or expanded-wrapper brace-init (`Either<...>{Either_Left<...>{inner}}`).
    let ref_left_legacy = out
        .contains("return Either<const L&, const R&>(Left<const L&, const R&>(inner));");
    let ref_left_expanded = out.contains(
        "return Either<const L&, const R&>{Either_Left<const L&, const R&>{inner}};",
    );
    let ref_right_legacy = out.contains(
        "return Either<const L&, const R&>(Right<const L&, const R&>(inner));"
    );
    let ref_right_expanded = out.contains(
        "return Either<const L&, const R&>{Either_Right<const L&, const R&>{inner}};",
    );
    let mut_left_legacy = out.contains("return Either<L&, R&>(Left<L&, R&>(inner));");
    let mut_left_expanded =
        out.contains("return Either<L&, R&>{Either_Left<L&, R&>{inner}};");
    let mut_right_legacy = out.contains("return Either<L&, R&>(Right<L&, R&>(inner));");
    let mut_right_expanded =
        out.contains("return Either<L&, R&>{Either_Right<L&, R&>{inner}};");
    assert!(ref_left_legacy || ref_left_expanded, "{out}");
    assert!(ref_right_legacy || ref_right_expanded, "{out}");
    assert!(mut_left_legacy || mut_left_expanded, "{out}");
    assert!(mut_right_legacy || mut_right_expanded, "{out}");
    assert!(!out.contains("Left<const L&, const R&>(std::move(inner))"));
    assert!(!out.contains("Right<const L&, const R&>(std::move(inner))"));
    assert!(!out.contains("Left<L&, R&>(std::move(inner))"));
    assert!(!out.contains("Right<L&, R&>(std::move(inner))"));
}

