#[test]
fn test_leaf5182_tuple_mut_ref_rebind_uses_pointer_alias_semantics() {
    let out = transpile_str(
        r#"
        struct Holder {
            a: usize,
            b: usize,
        }

        impl Holder {
            fn triple_mut(&mut self) -> (usize, &mut usize, usize) {
                (0, &mut self.a, self.b)
            }

            fn heap_mut(&mut self) -> (usize, &mut usize) {
                (1, &mut self.b)
            }

            fn bump(&mut self) {
                let (mut ptr, mut len, cap) = self.triple_mut();
                if len == cap {
                    let (heap_ptr, heap_len) = self.heap_mut();
                    ptr = heap_ptr;
                    len = heap_len;
                }
                len += 1;
            }
        }
    "#,
    );
    assert!(
        out.contains(
            "auto _tuple_destructure = rusty::detail::deref_if_pointer_like(this->triple_mut());"
        ),
        "{out}"
    );
    assert!(
        out.contains(
            "auto ptr = std::get<0>(rusty::detail::deref_if_pointer(_tuple_destructure));"
        ),
        "{out}"
    );
    assert!(
        out.contains(
            "auto&& len_ref = std::get<1>(rusty::detail::deref_if_pointer(_tuple_destructure));"
        ),
        "{out}"
    );
    assert!(
        out.contains(
            "auto cap = std::get<2>(rusty::detail::deref_if_pointer(_tuple_destructure));"
        ),
        "{out}"
    );
    assert!(out.contains("size_t* len = &len_ref;"), "{out}");
    // The if-condition's `*len` may emit with one or more layers
    // of parentheses depending on operator-precedence-safety
    // wrapping (`*((*len))` is equivalent to `*len`). Accept any
    // shape where the `*len`/`(*len)` is compared against `cap` via
    // either the bare expression or `deref_if_pointer_like` wrappers.
    let has_if = out.contains("if (*len == cap)")
        || out.contains("if (*(*len) == cap)")
        || out.contains("if (*((*len)) == cap)")
        || out.contains(
            "if (rusty::detail::deref_if_pointer_like(*len) == rusty::detail::deref_if_pointer_like(cap))",
        )
        || out.contains(
            "if (*((*len)) == rusty::detail::deref_if_pointer_like(cap))",
        )
        || out.contains(
            "if (*(*len) == rusty::detail::deref_if_pointer_like(cap))",
        );
    assert!(has_if, "{out}");
    assert!(out.contains("len = &heap_len;"), "{out}");
    // `*len += 1` may be parenthesized as `(*len) += 1` for the
    // same precedence-safety reason.
    assert!(out.contains("*len += 1;") || out.contains("(*len) += 1;"), "{out}");
    assert!(
        !out.contains("[&]() { static_cast<void>(*len += 1); return std::make_tuple(); }();"),
        "{out}"
    );
    assert!(
        !out.contains("[&]() { static_cast<void>((*len) += 1); return std::make_tuple(); }();"),
        "{out}"
    );
    assert!(!out.contains("len = heap_len;"), "{out}");
}

