#[test]
fn test_bitflags_synthetic_methods_not_duplicated_when_already_present() {
    // If a method is already defined in an impl block, synthetic should skip it
    let out = transpile_str(
        r#"
        struct Flags(u8);

        impl Flags {
            fn bits(&self) -> u8 { self.0 }
            fn is_empty(&self) -> bool { self.0 == 0 }
        }

        impl std::ops::BitOr for Flags {
            type Output = Self;
            fn bitor(self, rhs: Self) -> Self { Flags(self.0 | rhs.0) }
        }
        "#,
    );
    // bits() should appear exactly once (from the impl, not synthetic)
    let bits_count = out.matches("bits()").count();
    assert!(
        bits_count >= 1,
        "bits() should appear at least once\nGot: {out}"
    );
    // is_empty should also not be duplicated
    let is_empty_count = out.matches("is_empty()").count();
    assert!(
        is_empty_count >= 1,
        "is_empty() should appear at least once\nGot: {out}"
    );
}

#[test]
fn test_leaf105409_recursive_bitflags_forwarders_are_skipped() {
    let out = transpile_str(
        r#"
        trait FlagLike {
            fn bits(&self) -> u8;
            fn from_bits_retain(bits: u8) -> Self where Self: Sized;
        }

        struct Flags(u8);

        impl FlagLike for Flags {
            fn bits(&self) -> u8 { Flags::bits(self) }
            fn from_bits_retain(bits: u8) -> Self { Flags::from_bits_retain(bits) }
        }

        impl std::ops::BitOr for Flags {
            type Output = Self;
            fn bitor(self, rhs: Self) -> Self { Flags(self.0 | rhs.0) }
        }
        "#,
    );

    assert!(
        out.contains("uint8_t bits() const { return this->_0; }"),
        "synthetic non-recursive bits() helper should be emitted\nGot: {out}"
    );
    assert!(
        out.contains("static Flags from_bits_retain(uint8_t bits) { return Flags{bits}; }"),
        "synthetic non-recursive from_bits_retain() helper should be emitted with concrete bits type\nGot: {out}"
    );
    assert!(
        !out.contains("return (*this).bits();"),
        "recursive bits forwarder should be skipped\nGot: {out}"
    );
    assert!(
        !out.contains("return Flags::from_bits_retain("),
        "recursive from_bits_retain forwarder should be skipped\nGot: {out}"
    );
    assert!(
        !out.contains("std::declval<Flags>()._0"),
        "synthetic from_bits_retain should not use incomplete-type declval member access\nGot: {out}"
    );
}

#[test]
fn test_uncertain_receiver_method_call_uses_rusty_deref_call() {
    let out = transpile_str(
        r#"
        trait Bag {
            type Bits;
            fn bits(self) -> Self::Bits where Self: Sized;
        }

        fn extract<B: Bag>(value: B) -> B::Bits {
            value.bits()
        }
        "#,
    );
    // Receiver `value` is a type-parameter-typed local — the transpiler
    // can't statically prove `B::bits` lives directly on `B`, so the
    // emit must walk the deref chain via `rusty::deref_call`. The
    // lambda's trailing return must use the SFINAE-friendly
    // expression-decltype, not `decltype(auto)`.
    assert!(
        out.contains("rusty::deref_call(value, [&](auto&& __recv) -> decltype("),
        "uncertain receiver should be lowered via rusty::deref_call\nGot: {out}"
    );
    assert!(
        out.contains(".bits()"),
        "lambda body must invoke the requested method on __recv\nGot: {out}"
    );
    // Old hand-rolled two-arm dispatcher must not appear.
    assert!(
        !out.contains(
            "if constexpr (requires { std::forward<decltype(__recv)>(__recv).bits()"
        ),
        "old object-vs-pointer two-arm IIFE should be gone\nGot: {out}"
    );
}

#[test]
fn test_leaf1054010_unary_not_bits_method_lowers_to_bitwise_not() {
    let out = transpile_str(
        r#"
        trait Flags {
            type Bits;
            fn bits(self) -> Self::Bits where Self: Sized;
            fn from_bits_truncate(bits: Self::Bits) -> Self where Self: Sized;
        }

        fn complement<F: Flags>(value: F) -> F {
            F::from_bits_truncate(!value.bits())
        }
        "#,
    );
    // Unary-not on bits() should still lower to bitwise-not (`~...`),
    // but the receiver may be wrapped — historically via an
    // arrow-vs-dot IIFE probe, now via `rusty::deref_call` which
    // walks the full receiver deref chain.
    assert!(
        out.contains("from_bits_truncate(~value.bits())")
            || (out.contains("from_bits_truncate(~")
                && out.contains(".bits()")
                && !out.contains("from_bits_truncate(!")),
        "bitflags-style bits() unary-not should lower to bitwise-not\nGot: {out}"
    );
    assert!(
        !out.contains("from_bits_truncate(!value.bits())"),
        "bits() unary-not must not lower to logical-not\nGot: {out}"
    );
}

