#[test]
fn test_leaf10541_tuple_option_or_pattern_match_avoids_some_visit_lambdas() {
    let out = transpile_str(
        r#"
        fn f(a: (usize, Option<usize>), b: (usize, Option<usize>)) -> (usize, Option<usize>) {
            let hi = match (a.1, b.1) {
                (Some(x), Some(y)) => x.checked_mul(y),
                (Some(0), None) | (None, Some(0)) => Some(0),
                _ => None,
            };
            (a.0.saturating_mul(b.0), hi)
        }
        "#,
    );
    assert!(
        !out.contains("std::visit(overloaded { [&](const Some&"),
        "{out}"
    );
    // is_some() may be called directly on the scrutinee or through a
    // deref_if_pointer wrapper.
    assert!(
        out.contains("_m0.is_some() && _m1.is_some()")
            || (out.contains("_m0).is_some()") && out.contains("_m1).is_some()")),
        "{out}"
    );
    // Inferred payload type may be `size_t` (from the tuple type
    // annotation) or `int32_t` (from the `Some(0)` literal arm).
    assert!(
        out.contains("[&]() -> rusty::Option<size_t>")
            || out.contains("[&]() -> rusty::Option<int32_t>"),
        "{out}"
    );
    assert!(
        out.contains("rusty::Option<size_t>(0)")
            || out.contains("rusty::Option<int32_t>(0)")
            || out.contains("rusty::Option<size_t>(static_cast<size_t>(0))")
            || out.contains("rusty::Option<int32_t>(static_cast<int32_t>(0))"),
        "{out}"
    );
}

#[test]
fn test_leaf10541_tuple_option_match_some_cmp_max_infers_option_payload_type() {
    let out = transpile_str(
        r#"
        fn f(a: (usize, Option<usize>), b: (usize, Option<usize>)) -> (usize, Option<usize>) {
            let upper = match (a.1, b.1) {
                (Some(x), Some(y)) => Some(core::cmp::max(x, y)),
                _ => None,
            };
            (core::cmp::max(a.0, b.0), upper)
        }
        "#,
    );
    assert!(out.contains("[&]() -> rusty::Option<size_t>"), "{out}");
    // The path may resolve to either `core::cmp::max` (legacy) or
    // `rusty::cmp::max` (current — both alias the same runtime namespace).
    assert!(
        out.contains("rusty::Option<size_t>(core::cmp::max")
            || out.contains("rusty::Option<size_t>(rusty::cmp::max"),
        "{out}"
    );
}

#[test]
fn test_leaf10541_tuple_alias_destructure_keeps_match_option_return_typed() {
    let out = transpile_str(
        r#"
        type SizeHint = (usize, Option<usize>);
        fn f(a: SizeHint, b: SizeHint) -> SizeHint {
            let (a_lower, a_upper) = a;
            let (b_lower, b_upper) = b;
            let upper = match (a_upper, b_upper) {
                (Some(x), Some(y)) => Some(core::cmp::max(x, y)),
                _ => None,
            };
            (core::cmp::max(a_lower, b_lower), upper)
        }
        "#,
    );
    assert!(out.contains("[&]() -> rusty::Option<size_t>"), "{out}");
    assert!(out.contains("rusty::Option<size_t>(rusty::None)"), "{out}");
}

#[test]
fn test_leaf10541_closure_tuple_destructure_renames_value_bindings_that_shadow_type_params() {
    let out = transpile_str(
        r#"
        fn f<A, I>(iter: I)
        where
            I: Iterator<Item = (A,)>,
        {
            let _ = iter.fold((), |(), (A,)| {
                let _ = A;
                ()
            });
        }
        "#,
    );
    // The shadowed `A` rename may surface in a structured binding
    // (`[A_shadow1]`) or in a positional extraction (`auto&& A_shadow1 =
    // ... std::get<0>(...)`); either way it must not bind a literal `A`.
    assert!(
        out.contains("[A_shadow1]") || out.contains("auto&& A_shadow1 = "),
        "{out}"
    );
    assert!(!out.contains("auto&& [A] ="), "{out}");
}

#[test]
fn test_leaf10541_method_tuple_parameter_pattern_emits_destructure_prelude() {
    let out = transpile_str(
        r#"
        struct S;
        impl S {
            fn sum((c, t): (usize, usize)) -> usize {
                c + t
            }
        }
        "#,
    );
    assert!(out.contains("_arg0"), "{out}");
    // The destructured element extraction may have an outer
    // `rusty::detail::deref_if_pointer(...)` wrap to handle pointer-like
    // tuple parameters uniformly.
    assert!(
        out.contains("auto&& c = std::get<0>(rusty::detail::deref_if_pointer(_arg0));")
            || out.contains(
                "auto&& c = rusty::detail::deref_if_pointer(std::get<0>(rusty::detail::deref_if_pointer(_arg0)));"
            ),
        "{out}"
    );
    assert!(
        out.contains("auto&& t = std::get<1>(rusty::detail::deref_if_pointer(_arg0));")
            || out.contains(
                "auto&& t = rusty::detail::deref_if_pointer(std::get<1>(rusty::detail::deref_if_pointer(_arg0)));"
            ),
        "{out}"
    );
}

