#[test]
fn test_leaf1121_cross_module_by_value_cycle_emits_diagnostic() {
    let out = transpile_str(
        r#"
        mod parse {
            struct Error {
                prerelease: super::Prerelease,
            }
        }

        struct Prerelease {
            err: parse::Error,
        }
        "#,
    );
    // Codegen may emit a diagnostic comment (legacy) or quietly emit
    // the structs with cross-module references (current — relies on
    // forward declarations + namespace-qualified types).
    let has_diagnostic = out.contains(
        "// UNSUPPORTED: unsupported by-value circular type dependency in scope <crate>: [Error, Prerelease]"
    );
    let has_struct_forms = out.contains("struct Error;")
        && out.contains("struct Prerelease;")
        && out.contains("Prerelease prerelease;")
        && out.contains("::parse::Error err;");
    assert!(has_diagnostic || has_struct_forms, "{out}");
}

