#[test]
fn test_match_or_pattern_bool_uses_if_expression_not_switch() {
    // Simple OR patterns on bool (true | false) are emitted as if-expressions
    // because try_emit_runtime_match_stmt handles them as boolean conditions.
    // The switch path (emit_match_as_switch) is only reached for complex patterns
    // that aren't handled by the runtime match stmt path.
    let out = transpile_str(
        r#"
        fn test(x: bool) -> i32 {
            match x {
                true | false => 1,
            }
        }
        "#,
    );
    // Should use if-expression form since it's a simple boolean match.
    // The boolean OR pattern may be the only condition, or it may be
    // guarded by a `!_m_matched &&` prefix under the accumulator-style
    // statement-expression lowering.
    assert!(
        out.contains("if (_m == true || _m == false)")
            || out.contains("if (!_m_matched && (_m == true || _m == false))"),
        "Simple bool OR pattern should emit if-expression\nGot: {out}"
    );
}

#[test]
fn test_leaf_serde_runtime_match_stmt_break_targets_outer_loop() {
    let out = transpile_str(
        r#"
        fn f() {
            let mut i: u8 = 0;
            loop {
                match i.checked_add(1) {
                    Some(next) => i = next,
                    None => break,
                }
            }
        }
        "#,
    );
    // checked_add may be invoked directly or via an IIFE that binds
    // `_checked_lhs` for the receiver to ensure single-evaluation.
    assert!(
        out.contains(
            "auto&& _m = rusty::checked_add(i, static_cast<std::remove_cvref_t<decltype((i))>>(1));"
        ) || out.contains("rusty::checked_add(_checked_lhs, static_cast<std::remove_cvref_t<decltype((_checked_lhs))>>(1))"),
        "runtime match should lower checked_add call as scrutinee\nGot: {out}"
    );
    assert!(
        out.contains("bool _m_matched = false;"),
        "runtime match lowering should gate arms with a matched flag\nGot: {out}"
    );
    assert!(
        out.contains("if (!_m_matched) {"),
        "runtime match lowering should guard arm evaluation after first match\nGot: {out}"
    );
    assert!(
        !out.contains("} while (false);"),
        "runtime match stmt lowering must not wrap arms in do-while(false) because break/continue in arm bodies must target outer loops\nGot: {out}"
    );
}

#[test]
fn test_leaf_serde_binding_tuple_match_stmt_break_targets_outer_loop() {
    let out = transpile_str(
        r#"
        fn f() {
            let a = 1;
            let b = 2;
            loop {
                match (&a, &b) {
                    (_, _) => break,
                }
            }
        }
        "#,
    );
    assert!(out.contains("auto _m_tuple = std::make_tuple("));
    assert!(
        out.contains("bool _m_matched = false;"),
        "binding tuple match lowering should gate arms with a matched flag\nGot: {out}"
    );
    assert!(
        !out.contains("} while (false);"),
        "binding tuple match stmt lowering must not use do-while(false) wrapper\nGot: {out}"
    );
}

#[test]
fn test_self_referencing_local_init_uses_temp() {
    // `let right = ptr::read(&right)` shadows an outer `right`.
    // C++ `auto right = ptr::read(&right)` creates a self-reference.
    // The transpiler should use a temp to break the cycle.
    let out = transpile_str(
        r#"
        fn f() {
            let right = 42;
            {
                let right = std::ptr::read(&right);
                drop(right);
            }
        }
        "#,
    );
    assert!(
        !out.contains("auto right = rusty::ptr::read(&right)"),
        "Should NOT self-reference: auto right = ptr::read(&right)\nGot: {out}"
    );
}

#[test]
fn test_enum_variant_import_uses_constexpr_auto() {
    // `use std::sync::atomic::Ordering::SeqCst;` should emit
    // `constexpr auto SeqCst = ...::Ordering::SeqCst;` not `using`.
    let out = transpile_str(
        r#"
        enum Ordering { SeqCst, Acquire, Release }
        fn f() {
            use crate::Ordering::SeqCst;
            let x = SeqCst;
        }
        "#,
    );
    // Should NOT emit `using ...::SeqCst` (invalid for enum class)
    assert!(
        !out.contains("using") || !out.contains("SeqCst"),
        "enum variant import should not use 'using' declaration\nGot: {out}"
    );
}

#[test]
fn test_leaf_serde_content_import_alias_beats_unique_nonlocal_content_fallback() {
    let out = transpile_str(
        r#"
        mod private {
            pub mod de {
                pub mod content {
                    pub use crate::serde_core_private::Content;

                    pub fn content_as_str<'a, 'de>(content: &'a Content<'de>) -> Option<&'a str> {
                        None
                    }
                }
            }

            pub mod ser {
                pub mod content {
                    pub struct Content<'de>(pub &'de str);
                }
            }
        }

        mod serde_core_private {}
        "#,
    );
    assert!(
        out.contains("using serde_core_private::Content;"),
        "in-scope Content import should be preserved\nGot: {out}"
    );
    assert!(
        out.contains("content_as_str(const ::serde_core_private::Content& content)")
            || out.contains("content_as_str(const serde_core_private::Content& content)"),
        "single-segment imported type should qualify through the bound import target when local tail names conflict\nGot: {out}"
    );
    assert!(
        !out.contains("content_as_str(const ::private_::ser::content::Content& content)"),
        "imported Content alias must not be rewritten to unrelated local ser::content::Content\nGot: {out}"
    );
}

