#[test]
fn test_oncebox_new_infers_type_from_later_set_box_payload() {
    let out = transpile_str(
        r#"
        struct Box<T>(T);
        impl<T> Box<T> {
            fn new(value: T) -> Box<T> {
                Box(value)
            }
        }

        enum Option<T> {
            None,
            Some(T),
        }

        enum Result<T, E> {
            Ok(T),
            Err(E),
        }

        struct OnceBox<T>(Option<Box<T>>);
        impl<T> OnceBox<T> {
            fn new() -> OnceBox<T> {
                OnceBox(Option::None)
            }

            fn set(&self, value: Box<T>) -> Result<(), Box<T>> {
                Result::Ok(())
            }
        }

        struct Pebble<T> {
            val: T,
        }

        struct Heap;
        impl Heap {
            fn new_pebble<T>(&self, val: T) -> Pebble<T> {
                Pebble { val }
            }
        }

        fn f() {
            let heap = Heap;
            let cell = OnceBox::new();
            let _ = cell.set(Box::new(heap.new_pebble("hello")));
        }
        "#,
    );
    assert!(
        out.contains("OnceBox<Pebble<std::string_view>>::new_()")
            || out.contains("OnceBox<Pebble<const char *>>::new_()")
            || out.contains("OnceBox<Pebble<rusty::String>>::new_()"),
        "OnceBox::new should recover T from a later set(Box<T>) call\nGot: {out}"
    );
    assert!(
        !out.contains("OnceBox<auto>::new_()"),
        "OnceBox::new should not emit an unresolved auto template argument\nGot: {out}"
    );
}

// ============================================================
// Phase 4c-ii — bridge: emit-side `try_infer_ternary_arm_type`
// consumes the inference engine and returns a C++ type string
// (or None) for the unified type of two ternary arms.
// ============================================================

#[test]
fn try_infer_ternary_arm_type_either_constructors_with_concrete_args() {
    // The canonical §13.3 case but with concrete argument types
    // baked into one of the variant constructor calls. The engine
    // can't fully infer because we don't know `cursor_a` /
    // `cursor_b`'s types from this isolated expression — bare
    // idents stay variables — so we expect None (fallback to
    // local CTAD). This proves the bridge connects without
    // pretending to solve cases it can't.
    let cg = CodeGen::new();
    let arm_a: syn::Expr = syn::parse_str("Either::Left(cursor_a)").unwrap();
    let arm_b: syn::Expr = syn::parse_str("Either::Right(cursor_b)").unwrap();
    assert!(
        cg.try_infer_ternary_arm_type(&arm_a, &arm_b).is_none(),
        "engine should signal underdetermined when arm values are bare idents"
    );
}

#[test]
fn try_infer_ternary_arm_type_unrecognized_constructors_yield_none() {
    // Constructor that isn't in the recognition table — the
    // engine has no rule for it, so it can't pin any parameters,
    // and the bridge returns None. Confirms the API doesn't try
    // to invent a type.
    let cg = CodeGen::new();
    let arm_a: syn::Expr = syn::parse_str("Foo::A(x)").unwrap();
    let arm_b: syn::Expr = syn::parse_str("Foo::B(y)").unwrap();
    assert!(cg.try_infer_ternary_arm_type(&arm_a, &arm_b).is_none());
}

// itertools' `iproduct!`/`izip!`/`chain!` macros expand (via cargo expand) to
// `$crate::__std_iter::{once, Iterator::map, IntoIterator::into_iter, ...}`,
// where `__std_iter` is the crate's `pub use std::iter as __std_iter` alias.
// These must resolve to the standard iterator runtime, not leak `__std_iter`.
#[test]
fn test_std_iter_alias_and_ufcs_lowering() {
    let out = transpile_str(
        "fn f() { \
            let _ = ::itertools::__std_iter::once(()); \
            let _ = ::itertools::__std_iter::Iterator::map(\
                ::itertools::__std_iter::IntoIterator::into_iter(0..6), |elt| (elt,)); \
            let _ = ::itertools::__std_iter::Iterator::zip(\
                ::itertools::__std_iter::IntoIterator::into_iter(0..6), 0..9); \
        }",
    );
    assert!(!out.contains("__std_iter"), "leaked __std_iter alias:\n{out}");
    assert!(out.contains("rusty::once("), "std::iter::once not mapped:\n{out}");
    assert!(out.contains("rusty::map("), "Iterator::map UFCS not lowered:\n{out}");
    assert!(out.contains("rusty::zip("), "Iterator::zip UFCS not lowered:\n{out}");
    assert!(
        out.contains(".into_iter()"),
        "IntoIterator::into_iter UFCS not lowered:\n{out}"
    );
}

// A flat (libtest) target that imports its own crate as one C++ module
// (`use itertools as it; use crate::it::chain;`) must NOT emit
// `using itertools::chain;` / `using it = itertools;` — the crate's public
// items are already visible via `import itertools;`, and macro-only names
// (`iproduct!`) have no C++ symbol to bring in. They're dropped to comments.
#[test]
fn test_own_crate_use_imports_skipped() {
    let file: syn::File = syn::parse_str(
        "use itertools as it; \
         use crate::it::chain; \
         use crate::it::iproduct; \
         use crate::it::Itertools; \
         fn f() {}",
    )
    .unwrap();
    let mut cg = CodeGen::new();
    cg.set_crate_name("itertools");
    cg.emit_file(&file, Some("test_core"));
    let out = cg.into_output();
    let emits_uncommented = |needle: &str| {
        out.lines()
            .any(|l| l.trim_start().starts_with(needle))
    };
    assert!(
        !emits_uncommented("using itertools::"),
        "emitted own-crate using referencing nonexistent `itertools` namespace:\n{out}"
    );
    assert!(
        !emits_uncommented("using it::"),
        "emitted own-crate using via unresolved crate alias:\n{out}"
    );
    assert!(
        !emits_uncommented("using it ="),
        "emitted crate self-alias:\n{out}"
    );
}

// `std::vec::IntoIter<T>` (e.g. itertools test return types) maps to
// `rusty::port::vec::IntoIter<T>`, whose declaration must be imported directly
// from its owning C++ module — the umbrella `rusty` module does not alias it.
// Exercise the injection directly: it fires only when the type is referenced,
// places the import in the module preamble, and is idempotent.
#[test]
fn test_vec_into_iter_module_import_injection() {
    let needle = "rusty::port::vec::IntoIter";
    let import_line = "import vec_port.vec.into_iter;";

    let referenced =
        "module;\nexport module mymod;\n\nrusty::port::vec::IntoIter<int32_t> f();\n";
    let out = inject_module_import_if_referenced(referenced, needle, import_line);
    assert!(
        out.contains(&format!("\n{}\n", import_line)),
        "import not injected:\n{out}"
    );
    // Injected into the module preamble (after `export module …;`).
    assert!(
        out.find(import_line).unwrap() > out.find("export module mymod;").unwrap(),
        "import not placed after module declaration:\n{out}"
    );
    // Idempotent — already-imported output is left untouched.
    assert_eq!(
        inject_module_import_if_referenced(&out, needle, import_line),
        out,
        "double-injected the import"
    );
    // No reference → no injection.
    let unreferenced = "module;\nexport module mymod;\n\nint32_t f();\n";
    assert_eq!(
        inject_module_import_if_referenced(unreferenced, needle, import_line),
        unreferenced,
        "injected without any reference to the type"
    );
}

// `vec![Ok(..), Err(..)].into_iter()` returning `std::vec::IntoIter<Result<..>>`
// must construct its elements as the Vec's element type (`Result<..>`), not
// qualify them with the function's `IntoIter<..>` return type. The `vec!`
// macro lowers to a slice/boxed `into_vec(..)` constructor whose `.into_iter()`
// receiver must be typed `Vec<Result<..>>` so the element type propagates.
#[test]
fn test_vec_ok_err_into_iter_return_uses_result_element_owner() {
    let out = transpile_str(
        "pub fn mix_data() -> std::vec::IntoIter<Result<i32, bool>> { \
            <[_]>::into_vec(::std::boxed::Box::new([Ok(1), Err(false), Ok(2)])).into_iter() \
        }",
    );
    assert!(
        out.contains("rusty::Result<int32_t, bool>::Ok("),
        "Ok element should construct the Vec element Result type:\n{out}"
    );
    assert!(
        out.contains("rusty::Result<int32_t, bool>::Err("),
        "Err element should construct the Vec element Result type:\n{out}"
    );
    // The element ctor must NOT be qualified with the `IntoIter<..>` /
    // `decltype(rusty::iter(..))` return type owner.
    assert!(
        !out.contains(")::Ok("),
        "Ok wrongly qualified with a decltype/IntoIter owner:\n{out}"
    );
    assert!(
        !out.contains("IntoIter<rusty::Result<int32_t, bool>>::Ok"),
        "Ok wrongly qualified with the IntoIter return type:\n{out}"
    );
}

#[test]
fn test_find_invalid_auto_template_arg_flags_invalid_targs() {
    // `auto` used as a complete template argument (terminated by `,` or `>`)
    // is invalid C++ and must be flagged.
    assert!(find_invalid_auto_template_arg("rusty::Vec<auto>::new_()").is_some());
    assert!(find_invalid_auto_template_arg("auto x = std::tuple<auto, auto>{};").is_some());
    assert!(find_invalid_auto_template_arg("std::tuple<int32_t, auto>").is_some());
    // Report the 1-based line of the first offender.
    let multi = "line one\nok line\nrusty::Vec<auto>::new_()\n";
    assert_eq!(find_invalid_auto_template_arg(multi).map(|(n, _)| n), Some(3));
}

#[test]
fn test_find_invalid_auto_template_arg_allows_legitimate_auto() {
    // Abbreviated function-template parameters: `auto` is inside `(...)`, not `<...>`.
    assert!(find_invalid_auto_template_arg("export SizeHint add(auto a, auto b);").is_none());
    // C++ NTTP declaration: `auto` is followed by a parameter identifier.
    assert!(find_invalid_auto_template_arg("template <auto N>").is_none());
    assert!(find_invalid_auto_template_arg("template <auto Value, class T>").is_none());
    // Plain declaration spellings outside angle brackets stay fine.
    assert!(find_invalid_auto_template_arg("const auto& x = y;").is_none());
    assert!(find_invalid_auto_template_arg("auto&& v = make();").is_none());
    assert!(find_invalid_auto_template_arg("std::vector<int32_t> v;").is_none());
}

#[test]
fn test_to_owned_owned_type_mapping() {
    // `<Self as ToOwned>::Owned`: bespoke impls (str/[T]/Path) + Clone blanket.
    let cg = CodeGen::new();
    let norm = |t: &syn::Type| {
        use quote::ToTokens;
        t.to_token_stream().to_string().replace(' ', "")
    };
    let map = |s: &str| {
        let ty: syn::Type = syn::parse_str(s).unwrap();
        norm(&cg.to_owned_owned_type_from_self(&ty))
    };
    assert_eq!(map("str"), "String"); // bespoke: str -> String
    assert_eq!(map("[u8]"), "Vec<u8>"); // bespoke: [T] -> Vec<T>
    assert_eq!(map("Path"), "std::path::PathBuf"); // bespoke: Path -> PathBuf
    assert_eq!(map("i32"), "i32"); // Clone blanket
    assert_eq!(map("I"), "I"); // generic param, Clone blanket
    assert_eq!(map("MyStruct"), "MyStruct"); // concrete, Clone blanket
    assert_eq!(map("String"), "String"); // value receiver, blanket (not bespoke)
    // The `&&str` case: Self is `&str`, blanket Clone -> `&str`, NOT String.
    assert_eq!(map("&str"), "&str");
    // str-family smart pointers must NOT collapse to String.
    assert_eq!(map("Box<str>"), "Box<str>");
    assert_eq!(map("Cow<str>"), "Cow<str>");
}

#[test]
fn test_find_invalid_auto_template_arg_skips_dead_code_and_comments() {
    // `<auto>` inside a `#if 0 ... #endif` block is never compiled (the
    // patcher's stubbed orphan-impl blocks) — not a real leak.
    let dead = "#if 0\nauto x = rusty::Vec<auto>::new_();\n#endif\nint y = 0;\n";
    assert!(find_invalid_auto_template_arg(dead).is_none());
    // Nested `#if` inside the dead region still resolves to the right `#endif`.
    let nested = "#if 0\n#ifdef FOO\nrusty::Vec<auto>::new_();\n#endif\n#endif\nok();\n";
    assert!(find_invalid_auto_template_arg(nested).is_none());
    // `<auto>` in a line comment or block comment is not a leak.
    assert!(find_invalid_auto_template_arg("int z = 0; // rusty::Vec<auto>::new_()").is_none());
    assert!(find_invalid_auto_template_arg("/* rusty::Vec<auto> */ int w = 0;").is_none());
    let multiline_comment = "/* leak here:\nrusty::Vec<auto>::new_()\nstill comment */ int q;\n";
    assert!(find_invalid_auto_template_arg(multiline_comment).is_none());
    // But a real `<auto>` in LIVE code after a closed `#if 0` is still caught.
    let live = "#if 0\nrusty::Vec<auto>::new_();\n#endif\nrusty::Vec<auto>::new_();\n";
    assert_eq!(find_invalid_auto_template_arg(live).map(|(n, _)| n), Some(4));
    // The `#else` branch of a `#if 0` is live, so a leak there is caught.
    let else_live = "#if 0\nok();\n#else\nrusty::Vec<auto>::new_();\n#endif\n";
    assert_eq!(find_invalid_auto_template_arg(else_live).map(|(n, _)| n), Some(4));
}

#[test]
fn test_placeholder_tuple_turbofish_is_dropped_not_emitted_as_auto() {
    // A Rust `(_, _)` placeholder turbofish (e.g. `collect_tuple::<(_, _)>()`)
    // cannot become an explicit `std::tuple<auto, auto>` C++ template-argument
    // list. The emitter drops the turbofish so the call deduces from context,
    // matching the equivalent no-turbofish call. The output must not contain an
    // invalid `<auto>` template argument.
    let out = transpile_str(
        "pub fn t() { let it = [1, 2].iter(); let _x = it.collect_tuple::<(_, _)>(); }",
    );
    assert!(
        !out.contains("<auto"),
        "placeholder turbofish must not emit an `auto` template argument:\n{out}"
    );
    assert!(
        find_invalid_auto_template_arg(&out).is_none(),
        "no invalid auto template arg should survive:\n{out}"
    );
    assert!(
        out.contains("collect_tuple()"),
        "turbofish should be dropped, leaving a deducible call:\n{out}"
    );
}


// §13.14.1 reconcile-telemetry classifier (RUSTY_CPP_PRINT_INFERENCE). The
// classifier is the substance of the disagreement log; the eprintln wrapper is
// not unit-tested. Both-silent must be NEITHER (None, not logged); the verdict
// is computed on the normalized ELEMENT type (not the raw representation), so
// the engine's `Vec<T>` and a heuristic's bare `T` count as AGREE; differing
// elements DISAGREE; one-sided answers name the gap.
#[test]
fn reconcile_classifier_agrees_on_identical_types() {
    let h: syn::Type = syn::parse_str("Vec<u8>").unwrap();
    let e: syn::Type = syn::parse_str("Vec < u8 >").unwrap(); // whitespace differs
    let got = classify_inference_reconcile(Some(&h), Some(&e));
    assert_eq!(got.as_ref().map(|t| t.0), Some("AGREE"), "{got:?}");
}

// The exact shape the first real telemetry run surfaced: the heuristic stores
// the bare element (`u8`) while the engine seam stores the full owner
// (`Vec<u8>`). These are equivalent downstream and MUST classify as AGREE.
#[test]
fn reconcile_classifier_agrees_across_element_vs_owner_representation() {
    let heuristic_elem: syn::Type = syn::parse_str("u8").unwrap();
    let engine_owner: syn::Type = syn::parse_str("Vec<u8>").unwrap();
    let got = classify_inference_reconcile(Some(&heuristic_elem), Some(&engine_owner));
    assert_eq!(got.as_ref().map(|t| t.0), Some("AGREE"), "{got:?}");
    let (_, hs, es) = got.unwrap();
    assert_eq!(hs, "u8", "raw heuristic representation preserved in the log");
    assert_eq!(es, "Vec<u8>", "raw engine representation preserved in the log");
}

#[test]
fn reconcile_classifier_disagrees_on_different_elements() {
    // Different elements even after normalization → a genuine bug in one path.
    let h: syn::Type = syn::parse_str("Vec<ByteArray<N>>").unwrap();
    let e: syn::Type = syn::parse_str("Vec<u8>").unwrap();
    let got = classify_inference_reconcile(Some(&h), Some(&e));
    assert_eq!(got.as_ref().map(|t| t.0), Some("DISAGREE"), "{got:?}");
    let (_, hs, es) = got.unwrap();
    assert_eq!(hs, "Vec<ByteArray<N>>");
    assert_eq!(es, "Vec<u8>");
}

#[test]
fn reconcile_classifier_reports_one_sided_answers() {
    let t: syn::Type = syn::parse_str("Vec<u8>").unwrap();
    assert_eq!(
        classify_inference_reconcile(None, Some(&t)).as_ref().map(|c| c.0),
        Some("ENGINE-ONLY")
    );
    assert_eq!(
        classify_inference_reconcile(Some(&t), None).as_ref().map(|c| c.0),
        Some("HEURISTIC-ONLY")
    );
}

#[test]
fn reconcile_classifier_skips_both_silent() {
    assert!(classify_inference_reconcile(None, None).is_none());
}

// §13.14.1: enabling reconcile telemetry must be read-only — the emitted C++
// is byte-identical with and without the flag (it only adds stderr logging).
#[test]
fn reconcile_telemetry_does_not_change_emit() {
    let src = "pub fn t() -> Vec<u8> { let mut v = Vec::new(); v.push(1u8); v }";
    let baseline = transpile_str(src);
    let file: syn::File = syn::parse_str(src).unwrap();
    let mut cg = CodeGen::new();
    cg.set_print_inference(true);
    cg.emit_file(&file, None);
    let with_telemetry = cg.into_output();
    assert_eq!(
        baseline, with_telemetry,
        "RUSTY_CPP_PRINT_INFERENCE must not alter emitted code"
    );
}




#[test]
fn test_into_iter_cross_source_hint_not_routed_to_unqualified_rusty_ext() {
    // serde_yaml seeds `into_iter` into external_extension_method_hints (its
    // de::value IntoDeserializer surface). For a non-bridging receiver (a
    // concrete type, not a Vec/array/iterator), the cross-source extension-hint
    // fallback emitted an UNQUALIFIED `rusty_ext::into_iter(...)` lambda. When
    // that body is emitted inside a nested `*::rusty_ext` namespace, the
    // unqualified `rusty_ext` binds the ENCLOSING namespace (which has no
    // into_iter member) -> hard "no member named into_iter" at every call site
    // (serde_core's 40 errors). into_iter is a std IntoIterator method with
    // dedicated handling and must never route through the cross-source shim.
    let src = r#"
        struct W;
        fn g(w: W) { let _ = w.into_iter(); }
    "#;
    let file: syn::File = syn::parse_str(src).unwrap();
    let mut cg = CodeGen::new();
    cg.external_extension_method_hints.insert("into_iter".to_string());
    cg.emit_file(&file, None);
    let out = cg.into_output();
    assert!(
        !out.contains("rusty_ext::into_iter"),
        "into_iter must not route through the unqualified cross-source extension shim\n{out}"
    );
    // It must still be lowered to *some* valid iterator form, not dropped.
    assert!(
        out.contains("into_iter") || out.contains("rusty::iter"),
        "into_iter must still be emitted in a valid form\n{out}"
    );
}

#[test]
fn test_extern_crate_alias_resolved_in_use_import_qualification() {
    // `extern crate alloc as stdalloc;` then `use stdalloc::alloc::Layout;` and
    // a bare `Layout` param. When a UFCS/forward-decl signature re-qualifies the
    // bare `Layout` to its use-source path, the leading extern-crate alias
    // `stdalloc` must resolve to `alloc` (-> rusty::alloc::Layout). Otherwise it
    // emits an undeclared `stdalloc::alloc::Layout` (hashbrown's 34-error cluster).
    let out = transpile_str(
        r#"
        extern crate alloc as stdalloc;
        pub mod a {
            use stdalloc::alloc::Layout;
            pub enum Fallibility { Inf, Stb }
            impl Fallibility {
                pub fn alloc_err(self, layout: Layout) -> u32 { 0 }
            }
        }
        "#,
    );
    assert!(
        !out.contains("stdalloc"),
        "extern-crate alias `stdalloc` must be resolved away, not emitted\n{out}"
    );
    assert!(
        out.contains("rusty::alloc::Layout"),
        "stdalloc::alloc::Layout must map to rusty::alloc::Layout\n{out}"
    );
}

#[test]
fn test_unsafe_wrapped_tuple_destructure_binds_by_value_not_dangling_ref() {
    // `let (a, b) = unsafe { (x, y) };` — the init is `Expr::Unsafe`, a
    // block-like rvalue. It must be classified as an rvalue so the owning
    // `auto [a, b] = deref_if_pointer_like(make_tuple(...))` binding is used.
    // That binding MOVE-constructs from the make_tuple temporary (deref_if_
    // pointer_like forwards the xvalue), so it owns and never copies — move is
    // preserved. The previous `auto&&` (from misclassifying unsafe{} as a
    // non-rvalue) bound a reference INTO the temporary, which dies at end of
    // statement -> dangling (hashbrown RawTableInner::erase control-byte
    // corruption).
    let out = transpile_str(
        r#"
        pub unsafe fn f(x: u32, y: u32) -> u32 {
            let (a, b) = unsafe { (x, y) };
            a + b
        }
        "#,
    );
    assert!(
        out.contains("auto [a, b] ="),
        "unsafe-wrapped owning tuple destructure must bind by value (owns + moves)\n{out}"
    );
    assert!(
        !out.contains("auto&& [a, b]"),
        "must not bind a dangling forwarding-ref to the make_tuple temporary\n{out}"
    );
}

#[test]
fn test_multi_super_use_path_peels_progressively() {
    // `use super::super::X;` inside a 3-deep module (control::group::sse2) must
    // peel TWO levels to `control::X`. The old `super` arm re-derived
    // `module_stack[..len-1]` on every super and concatenated, doubling the path
    // to `control::group::control::group::X` (hashbrown control::group cluster,
    // ~33 errors). Each super must peel one level from the accumulated prefix.
    let out = transpile_str(
        r#"
        pub mod control {
            pub struct BitMask;
            pub mod group {
                pub mod sse2 {
                    use super::super::BitMask;
                    pub fn f(_b: BitMask) {}
                }
            }
        }
        "#,
    );
    assert!(
        !out.contains("control::group::control"),
        "multi-super must not double the module path\n{out}"
    );
    assert!(
        out.contains("control::BitMask"),
        "super::super from control::group::sse2 must resolve to control::BitMask\n{out}"
    );
}

#[test]
fn test_sibling_same_named_generic_type_recovers_own_params_not_collide() {
    // Sibling modules define same-named generic types with DIFFERENT params:
    // map::IntoIter<K,V> vs set::IntoIter<T,A>. Both register a bare
    // `declared_type_params["IntoIter"]` key (map's, registered first). When
    // set::IntoIter's `-> Self` / struct-literal recovers its omitted type
    // args, the owner-param lookup must use the MODULE-SCOPED key
    // (`set::IntoIter` -> [T,A]), not the colliding bare key (map's [K,V]),
    // which previously emitted `IntoIter<K, V>` with K/V undeclared in set.
    let out = transpile_str(
        r#"
        pub mod map {
            pub struct IntoIter<K, V> { pub k: K, pub v: V }
        }
        pub mod set {
            pub struct IntoIter<T, A> { pub t: T, pub a: A }
            impl<T, A> IntoIter<T, A> {
                pub fn make(t: T, a: A) -> Self { IntoIter { t, a } }
            }
        }
        "#,
    );
    assert!(
        out.contains("IntoIter<T, A>"),
        "set::IntoIter must recover its own params <T, A>\n{out}"
    );
    assert!(
        !out.contains("IntoIter<K, V>"),
        "set::IntoIter must not pull map's <K, V> via the colliding bare key\n{out}"
    );
}

#[test]
fn test_copy_struct_by_value_self_method_is_const() {
    // A `Copy` struct's fields are all `Copy`, so a by-value-`self` method can
    // never move out of `self` and must be emitted as a C++ `const` method —
    // otherwise it can't be called on a const receiver (hashbrown's `Tag`/
    // `Group` predicate methods). `Copy` arrives as an `impl Copy for X` block
    // in expanded (cargo-expand) source, which is what gets transpiled.
    let out = transpile_str(
        r#"
        pub struct Tag(u8);
        impl ::core::marker::Copy for Tag {}
        impl Tag {
            pub fn is_special(self) -> bool { self.0 & 1 != 0 }
        }
        "#,
    );
    assert!(
        out.contains("is_special() const"),
        "by-value-self method on a Copy struct must be a const method\n{out}"
    );
}

#[test]
fn test_crate_declaring_std_named_type_keeps_self_refs_local() {
    // A std-library port that DEFINES its own `HashMap` (hashbrown) must keep
    // bare self-references local, not rewrite them to the umbrella
    // `rusty::HashMap` alias — that collides with and circularly imports the
    // very type the port defines. A bare name resolves local-first in Rust.
    let out = transpile_str(
        r#"
        pub struct HashMap<K, V> { k: K, v: V }
        pub fn first(m: &HashMap<i32, i64>) -> i32 { m.k }
        "#,
    );
    assert!(
        !out.contains("rusty::HashMap"),
        "a crate that declares its own HashMap must not map self-refs to rusty::HashMap\n{out}"
    );
    assert!(
        out.contains("HashMap<int32_t, int64_t>"),
        "bare HashMap reference should stay local\n{out}"
    );
}

#[test]
fn test_integer_intrinsic_methods_lower_on_field_chain_and_param_receivers() {
    // Rust integer-trait methods (leading_zeros / swap_bytes / is_power_of_two)
    // only exist on primitive integers, so they must lower to `rusty::` free
    // functions even when the receiver's type can't be inferred — a tuple-struct
    // field (`self.0`), a chained intrinsic (`x.swap_bytes().leading_zeros()`),
    // or a bare function parameter. Otherwise they emit `.method()` on a
    // primitive and fail to compile (hashbrown's SIMD bitmask path).
    let out = transpile_str(
        r#"
        struct BitMask(u16);
        impl BitMask {
            fn lowest(&self) -> u32 { self.0.swap_bytes().leading_zeros() }
        }
        fn is_pow2(n: usize) -> bool { n.is_power_of_two() }
        "#,
    );
    assert!(
        out.contains("rusty::leading_zeros(rusty::swap_bytes(this->_0))"),
        "field + chained integer intrinsics must lower to rusty:: free fns\n{out}"
    );
    assert!(
        out.contains("rusty::is_power_of_two(n)"),
        "is_power_of_two on a parameter must lower to rusty::is_power_of_two\n{out}"
    );
    assert!(
        !out.contains(".swap_bytes()") && !out.contains(".is_power_of_two()"),
        "no integer intrinsic should remain as a `.method()` call on a primitive\n{out}"
    );
}

#[test]
fn test_module_alias_resolved_in_sibling_reexport() {
    // `use sse2 as imp;` is a MODULE rename. A sibling module's re-export
    // resolved transitively through `control::group`'s `pub use self::imp::X`
    // must expand the `imp` alias to `sse2` (`control::group::sse2::X`), not
    // leak `control::group::imp::X` (hashbrown's control::group cluster).
    let out = transpile_str(
        r#"
        pub mod control {
            pub mod group {
                pub mod sse2 { pub const BITMASK_ITER_MASK: usize = 1; }
                use sse2 as imp;
                pub(super) use self::imp::BITMASK_ITER_MASK;
            }
            pub mod bitmask {
                use super::group::BITMASK_ITER_MASK;
                pub fn f() -> usize { BITMASK_ITER_MASK }
            }
        }
        "#,
    );
    assert!(
        !out.contains("control::group::imp"),
        "`use sse2 as imp` module alias must be resolved, not leaked\n{out}"
    );
    assert!(
        out.contains("control::group::sse2::BITMASK_ITER_MASK"),
        "must resolve the sibling re-export through imp to sse2\n{out}"
    );
}

#[test]
fn test_flat_umbrella_reexport_does_not_bind_deep_sibling_same_named_type() {
    // serde regression (commit a04b1a0): a flat `private_::Content` re-export
    // must NOT resolve into the two-levels-deep `private_::ser::content::Content`
    // just because that sibling is the only declared `Content` in scope. serde's
    // umbrella `__private` carries BOTH `ser::content::Content` and
    // `de::content::Content`; binding the flat re-export to the `ser` one gives
    // the de-side use sites a type missing their `Str`/`ByteBuf`/`Newtype`
    // variants (incomplete-type + no-member compile errors). Keep it flat so the
    // emitter's own `using` binds the correct type.
    let mut cg = CodeGen::new();
    cg.local_declared_types
        .insert("private_::ser::content::Content".to_string());
    assert_eq!(
        cg.try_resolve_nested_local_type_path("private_::Content"),
        None,
        "flat umbrella re-export must not bind a 2-levels-deep sibling type"
    );

    // A single-intermediate re-export (`mod::Type` -> `mod::sub::Type`) is the
    // common, legitimate case and must still resolve.
    cg.local_declared_types
        .insert("modx::sub::Widget".to_string());
    assert_eq!(
        cg.try_resolve_nested_local_type_path("modx::Widget")
            .as_deref(),
        Some("modx::sub::Widget"),
        "one-level re-export resolution must be preserved"
    );
}

#[test]
fn test_mutual_module_cycle_orders_by_inline_field_edge() {
    // de<->loader shape: loader's signature/body references to de are
    // satisfiable via the pre-pass (fwd decls + early variant alias), while
    // de's variant payload stores Loader INLINE — the only genuine
    // completeness edge. The false reverse edges (Vec payload, method
    // params, body member paths) must not force de before loader.
    let out = transpile_str_module(
        r#"
        pub mod de {
            use crate::loader::Loader;
            pub enum Progress {
                Nothing,
                Iterable(Loader),
            }
        }
        pub mod loader {
            use crate::de::Progress;
            pub struct Loader {
                pub count: usize,
                pub marks: Vec<(crate::de::Progress, usize)>,
            }
            impl Loader {
                pub fn new(progress: Progress) -> Loader {
                    let _ = progress;
                    Loader { count: 0, marks: Vec::new() }
                }
            }
        }
    "#,
        "cycle_order",
    );
    let loader_def = out
        .find("struct Loader {")
        .expect("Loader definition missing");
    let iterable_def = out
        .find("struct Progress_Iterable {")
        .expect("Progress_Iterable definition missing");
    assert!(
        loader_def < iterable_def,
        "Loader must be complete before Progress_Iterable stores it inline:\n{out}"
    );
}

#[test]
fn test_assignment_from_plain_local_moves_rhs() {
    // `self.state = state;` — Rust assignment moves the local; without
    // std::move the C++ variant with a move-only alternative selects its
    // deleted copy assignment.
    let out = transpile_str(
        r#"
        enum State {
            Nothing,
            Found(String),
        }
        struct Holder {
            state: State,
        }
        impl Holder {
            fn put(&mut self, other: State) {
                let state = other;
                self.state = state;
            }
        }
    "#,
    );
    assert!(
        out.contains("this->state = std::move(state)"),
        "{out}"
    );
}

#[test]
fn test_if_let_expression_variant_test_uses_variant_holds_not_is_some() {
    // `x = if let State::Found(_) = self.state {..} else {..}` — the
    // expression-form if-let lowerings must test the data-enum variant, not
    // call the Option surface on a std::variant scrutinee.
    let out = transpile_str(
        r#"
        enum State {
            Nothing,
            Waiting,
            Found(String),
        }
        struct Holder {
            state: State,
        }
        impl Holder {
            fn advance(&mut self) -> i32 {
                let n = if let State::Found(_) = self.state { 1 } else { 0 };
                let m = if let State::Nothing | State::Waiting = self.state {
                    let bump = 2;
                    bump
                } else {
                    3
                };
                n + m
            }
        }
    "#,
    );
    // Single-variant test lowers via the index() IIFE path; the or-pattern
    // multi-statement form goes through the variant_holds condition.
    assert!(
        out.contains("rusty::detail::variant_holds<State_Found>")
            || out.contains(") == 2"),
        "{out}"
    );
    assert!(
        out.contains("rusty::detail::variant_holds<State_Nothing>")
            && out.contains("rusty::detail::variant_holds<State_Waiting>"),
        "{out}"
    );
    assert!(!out.contains("_iflet_scrutinee.is_some()"), "{out}");
    assert!(!out.contains("_iflet.is_some()"), "{out}");
}

#[test]
fn test_loop_rebind_match_arm_lowers_as_statement() {
    // serde_yaml value/index.rs index_or_insert: a unit-typed tail match in
    // a `loop` whose arms mix early `return`s with a REBIND arm
    // (`Value::Tagged(tagged) => v = &mut tagged.value`). The rebind arm is
    // an assignment (always unit in Rust) — the match must lower as a
    // STATEMENT so the rebind falls through to the next loop iteration,
    // NOT as a value-IIFE whose `return v = &x;` mis-types (Value* vs
    // Value&) and exits the loop early.
    let out = transpile_str(
        r#"
        enum Value {
            Leaf(i32),
            Nest(Box<Value>),
        }
        fn index_or_insert(mut v: &mut Value) -> &mut Value {
            loop {
                match v {
                    Value::Leaf(_) => return v,
                    Value::Nest(inner) => v = inner,
                }
            }
        }
        "#,
    );
    // The rebind arm must be a plain assignment statement, never returned.
    assert!(!out.contains("return v_shadow1 ="), "{out}");
    assert!(!out.contains("return v ="), "{out}");
    assert!(out.contains("while (true)"), "{out}");
}


#[test]
fn test_known_receiver_type_not_misrouted_to_unrelated_alias() {
    // A method call whose receiver type is a KNOWN concrete type must resolve
    // to that type's member/runtime method — never fall back to a same-named
    // inherent method on an UNRELATED type-alias owner (which emits a
    // `__rusty_alias_<Owner>_<method>` free fn). Regression: `String.vec:
    // Vec<u8>`'s `.split_off` was mis-dispatched to btree `Root::split_off`
    // (the sole `split_off` alias) because the by-method-name fallback fired
    // even though the receiver's `Vec` type was known.
    let out = transpile_str(
        r#"
        pub struct MyVec { len: usize }
        impl MyVec {
            pub fn split_off(&mut self, at: usize) -> MyVec { MyVec { len: 0 } }
        }
        pub struct NodeRef { h: usize }
        pub type Root = NodeRef;
        impl Root {
            pub fn split_off(&mut self, at: usize) -> Root { NodeRef { h: 0 } }
        }
        pub struct Holder { v: MyVec }
        impl Holder {
            pub fn go(&mut self, at: usize) -> MyVec {
                self.v.split_off(at)
            }
        }
        "#,
    );
    // `Root::split_off` still emits its alias helper (it is a type-alias owner)...
    assert!(out.contains("__rusty_alias_Root_split_off"), "{out}");
    // ...but the KNOWN-typed `self.v` receiver must call the member directly,
    // not route to that unrelated alias.
    assert!(out.contains("this->v.split_off"), "{out}");
    assert!(
        !out.contains("__rusty_alias_Root_split_off(this->v"),
        "known Vec receiver mis-dispatched to Root's split_off alias:\n{out}"
    );
}

#[test]
fn test_enum_deref_self_return_coerces_via_operator_star() {
    // `fn as_ref(&self) -> &Target { self }` deref-coerces &Self to
    // &Deref::Target. This works for structs; the ENUM emit path does not
    // push a method-output scope, so the deref lookup missed it and the enum
    // returned the whole value (`return (*this)`) instead of the deref.
    // Regression: Cow<B>'s `AsRef<T>::as_ref` (enum, Deref param B vs AsRef
    // param T) returned the whole Cow. Fixed via user_deref_targets.
    let out = transpile_str(
        r#"
        pub enum E<T> { A(T), B(T) }
        impl<T> core::ops::Deref for E<T> {
            type Target = T;
            fn deref(&self) -> &T { match self { E::A(x) => x, E::B(x) => x } }
        }
        impl<T> AsRef<T> for E<T> {
            fn as_ref(&self) -> &T { self }
        }
        "#,
    );
    assert!(out.contains("as_ref() const"), "{out}");
    assert!(
        out.contains("return this->operator*();"),
        "enum as_ref must deref-coerce self, not return the whole value:\n{out}"
    );
}

#[test]
fn test_at_binding_let_emits_subpattern_destructure() {
    // `let whole @ Struct { a, b } = init;` binds `whole` to the value AND
    // destructures its fields. The Pat::Ident emit arm emitted only `whole`,
    // dropping the sub-pattern, so `a`/`b` were undeclared. Regression:
    // string.rs's `let src @ Range { start, end } = slice::range(..)`.
    let out = transpile_str(
        r#"
        pub struct Rg { pub start: usize, pub end: usize }
        pub fn mk() -> Rg { Rg { start: 1, end: 5 } }
        pub fn f() -> usize {
            let whole @ Rg { start, end } = mk();
            start + end + whole.start
        }
        "#,
    );
    // `whole` is bound...
    assert!(out.contains("whole = "), "{out}");
    // ...and the sub-pattern fields are destructured against it.
    assert!(out.contains("_let_pat = whole") || out.contains(".start"), "{out}");
    assert!(out.contains("start ="), "at-binding dropped the start binding:\n{out}");
    assert!(out.contains("end ="), "at-binding dropped the end binding:\n{out}");
    assert!(!out.contains("// TODO: complex pattern binding"), "{out}");
}

#[test]
fn test_crate_owned_string_from_utf8_unchecked_not_remapped_to_runtime() {
    // A crate that declares its own `String` (e.g. the folded string.rs port)
    // and calls `String::from_utf8_unchecked` must route to the CRATE's inherent
    // method, not the runtime `rusty::str_runtime::from_utf8_unchecked` helper
    // (which returns a string_view). The post-recovery remap in emit_call was
    // unconditional; it now consults bare_std_named_type_suppression_applies.
    let out = transpile_str(
        r#"
        pub mod string {
            pub struct String { v: usize }
            impl String {
                pub unsafe fn from_utf8_unchecked(bytes: usize) -> String { String { v: bytes } }
                pub fn caller(&self) -> String {
                    unsafe { String::from_utf8_unchecked(self.v) }
                }
            }
        }
        "#,
    );
    assert!(
        out.contains("String::from_utf8_unchecked(this->v)"),
        "crate-owned String::from_utf8_unchecked call was not preserved:\n{out}"
    );
    assert!(
        !out.contains("rusty::str_runtime::from_utf8_unchecked(this->v)"),
        "crate-owned call was wrongly remapped to the runtime helper:\n{out}"
    );
}

#[test]
fn test_user_deref_type_routes_target_method_through_deref() {
    // A type implementing `Deref<Target=U>` (e.g. PathBuf: Deref<Target=Path>)
    // calling a method that lives only on U must route through the deref
    // (`*receiver`), not emit a plain member call the wrapper can't resolve.
    let out = transpile_str(
        r#"
        pub struct Inner { pub v: usize }
        impl Inner {
            pub fn describe(&self) -> usize { self.v }
        }
        pub struct Wrapper { pub inner: Inner }
        impl std::ops::Deref for Wrapper {
            type Target = Inner;
            fn deref(&self) -> &Inner { &self.inner }
        }
        pub fn use_it(w: Wrapper) -> usize {
            w.describe()
        }
        "#,
    );
    // `w.describe()` — describe is only on Inner, reached via Wrapper's Deref —
    // routes through the deref helper rather than `w.describe()` directly.
    assert!(
        out.contains("deref_if_pointer_like") && out.contains(".describe("),
        "user-Deref method call not routed through deref:\n{out}"
    );
}

#[test]
fn test_method_calling_same_named_free_fn_qualifies_to_avoid_self_recursion() {
    // A method whose body calls a FREE function of the same name (Rust resolves
    // the bare call to the free fn — inherent methods need a receiver) must be
    // emitted QUALIFIED. Emitted unqualified, C++ member-scope lookup binds the
    // call to the method itself → silent infinite recursion at run time (it still
    // compiles). This is std::path's Components::is_sep_byte calling the free
    // sys::path::is_sep_byte. Uses a `use` import so it exercises the
    // scope-import-binding qualification path (the case that reaches bare emission).
    let out = transpile_str(
        r#"
        mod sys {
            pub mod path {
                pub fn is_sep_byte(b: u8) -> bool { b == b'/' }
            }
        }
        use sys::path::is_sep_byte;
        pub struct Comp { pub verbatim: bool }
        impl Comp {
            fn is_sep_byte(&self, b: u8) -> bool { is_sep_byte(b) }
        }
        "#,
    );
    // The inner call must be QUALIFIED to the free fn's path…
    assert!(
        out.contains("sys::path::is_sep_byte(std::move(b))"),
        "member is_sep_byte body should call the QUALIFIED free fn:\n{out}"
    );
    // …and must NOT be the bare `return is_sep_byte(...)` that recurses into the
    // member (the qualified form has `::sys::path::` between `return` and the name).
    assert!(
        !out.contains("return is_sep_byte(std::move(b))"),
        "inner call still emits the bare (recursive) is_sep_byte:\n{out}"
    );
}

#[test]
fn test_match_some_none_iife_gets_explicit_option_return_type() {
    // A match lowered to an IIFE whose arms return `Some(x)` / `None` can't have
    // its C++ return type DEDUCED — `rusty::Some(x)` and `rusty::None` are
    // different types. The IIFE must carry an explicit `-> rusty::Option<T>`.
    // The scrutinee here is a closure param whose type the engine can't infer,
    // so the enum (and thus the Some payload type) is derived from the arm
    // pattern. This is std::path's file_name shape:
    // `next_back().and_then(|p| match p { Comp::Normal(p) => Some(p), _ => None })`.
    let out = transpile_str(
        r#"
        pub enum Comp { Normal(u32), Root }
        pub struct P;
        impl P {
            pub fn pick(&self) -> Option<Comp> { None }
            pub fn last_normal(&self) -> Option<u32> {
                self.pick().and_then(|p| match p {
                    Comp::Normal(p) => Some(p),
                    _ => None,
                })
            }
        }
        "#,
    );
    assert!(
        out.contains("-> rusty::Option<uint32_t>"),
        "Some/None match IIFE should get an explicit Option return type:\n{out}"
    );
}

#[test]
fn test_value_condition_match_applies_guard_on_literal_arm() {
    // A `match slice { b"." if guard => …, b"." => …, _ => … }` lowered to the
    // value-condition form (`_m == std::array{…}`) must APPLY the guard on the
    // literal arm. Previously the guard was gated on `allow_guarded_variant_arms`
    // and silently dropped for literal/path/wildcard arms, so the first `b"."`
    // arm fired unconditionally and the second became dead — std::path's
    // `parse_single_component` (`b"." if HAS_PREFIXES && … => CurDir` then
    // `b"." => None`).
    let out = transpile_str(
        r#"
        pub fn classify(c: &[u8], cond: bool) -> i32 {
            match c {
                b"." if cond => 1,
                b"." => 2,
                b".." => 3,
                _ => 0,
            }
        }
        "#,
    );
    // Value-condition lowering (not std::visit), and the guard is applied.
    assert!(
        out.contains("_m == std::array"),
        "expected the byte-literal value-condition lowering:\n{out}"
    );
    assert!(
        out.contains("if (cond)"),
        "guard on the literal arm was dropped (should wrap the arm body):\n{out}"
    );
}

#[test]
fn test_data_enum_derive_partial_eq_emits_variant_operator_eq() {
    // A data enum deriving PartialEq/Eq lowers to `struct E : std::variant<E_A,
    // E_B, E_C>`; its `==` compares the variant, which needs EACH alternative
    // (the variant member structs) to have `operator==`. Emit a defaulted one on
    // each — including the empty (unit) variant, which otherwise has no `==`.
    let out = transpile_str(
        "#[derive(PartialEq, Eq)] pub enum E { A, B(u32), C { x: i32 } }",
    );
    for v in ["E_A", "E_B", "E_C"] {
        assert!(
            out.contains(&format!("bool operator==(const {v}&) const = default;")),
            "variant member struct {v} missing defaulted operator==:\n{out}"
        );
    }
    // Gated on the derive: an enum WITHOUT PartialEq must not get it.
    let out2 = transpile_str("pub enum F { A, B(u32) }");
    assert!(
        !out2.contains("bool operator==(const F_A&)"),
        "operator== emitted for a non-PartialEq enum:\n{out2}"
    );
}

#[test]
fn test_matches_macro_lowers_to_boolean() {
    // `matches!(e, pat)` was unhandled and emitted a `/* matches!(…) */` comment
    // (a void expression). It now expands to a match and reuses the ordinary
    // lowering, so all pattern kinds work.
    let out = transpile_str("pub fn f(x: i32) -> bool { matches!(x, 1 | 2 | 3) }");
    assert!(
        !out.contains("/* matches!"),
        "matches! left as an unhandled comment:\n{out}"
    );
    assert!(
        out.contains("_m == 1 || _m == 2 || _m == 3"),
        "matches! or-pattern not lowered to the boolean conditions:\n{out}"
    );
    // Guard form.
    let out2 =
        transpile_str("pub fn g(x: i32, hi: i32) -> bool { matches!(x, n if n < hi) }");
    assert!(
        !out2.contains("/* matches!"),
        "guarded matches! left as a comment:\n{out2}"
    );
}

#[test]
fn test_diverging_tail_branch_emitted_as_statement_not_returned() {
    // A diverging if/else branch (panic!/todo!/unreachable!) has no value and its
    // lowered form is `throw …` / a [[noreturn]] void call — it must be emitted
    // as a statement, not `return <void>` ("cannot initialize <T> with void").
    let out = transpile_str("pub fn f(x: i32) -> i32 { if x > 0 { x } else { todo!() } }");
    assert!(
        out.contains("throw std::logic_error"),
        "todo! not lowered:\n{out}"
    );
    assert!(
        !out.contains("return throw"),
        "diverging todo! branch was wrongly return-wrapped:\n{out}"
    );
    // panic! in expression position must emit a real diverging call, not a
    // `/* panic!(…) */` comment (which is a silent no-op).
    let out2 = transpile_str(r#"pub fn g(x: i32) -> i32 { if x > 0 { x } else { panic!("no") } }"#);
    assert!(!out2.contains("/* panic!"), "panic! left as a comment:\n{out2}");
    assert!(
        out2.contains("std::abort()"),
        "panic! not lowered to abort():\n{out2}"
    );
}

#[test]
fn test_match_switch_guarded_then_fallthrough_arm_emits_balanced_else_chain() {
    // A C-like-enum `match` lowered to a C++ `switch` where the same variant
    // appears twice — first guarded, then an unguarded fall-through with a
    // NON-EMPTY body (std::path's Components::next: `State::Body if … => {…}`
    // then `State::Body => {…}`). The old streaming emitter closed the guarded
    // arm with `break; }` before the fall-through arm could chain its `} else {`,
    // producing a dangling `} else {` after a closed case block (unbalanced,
    // wouldn't compile). Arms sharing a case label now emit as one if/else chain.
    let out = transpile_str(
        r#"
        pub enum State { A, B, Done }
        pub struct S { pub front: State, pub n: u32 }
        impl S {
            pub fn step(&mut self) -> u32 {
                match self.front {
                    State::A if self.n > 0 => { return 1; }
                    State::A => { self.front = State::B; }
                    State::B if self.n > 5 => { return 2; }
                    State::B => { self.front = State::Done; }
                    State::Done => { return 0; }
                }
                99
            }
        }
        "#,
    );
    // The guarded/fall-through pairs collapse to `if (...) { ... } else { ... }`.
    assert!(out.contains("} else {"), "expected an else-chain:\n{out}");
    assert!(
        !out.contains("// TODO: duplicate pattern without guard ordering"),
        "duplicate-pattern arm fell into the TODO stub:\n{out}"
    );
    // The malformed shape was `break;` then a case-closing `}` then a dangling
    // `} else` — i.e. `break;}}else` once whitespace is stripped. It must be gone,
    // and the emitted switch must be brace-balanced.
    let dense: String = out.chars().filter(|c| !c.is_whitespace()).collect();
    assert!(
        !dense.contains("break;}}else"),
        "dangling `}} else {{` after a closed case block:\n{out}"
    );
    // Extract the switch body and confirm braces balance.
    let sw = out.find("switch (").expect("no switch emitted");
    let mut depth = 0i32;
    let mut started = false;
    for ch in out[sw..].chars() {
        match ch {
            '{' => {
                depth += 1;
                started = true;
            }
            '}' => {
                depth -= 1;
                if started && depth == 0 {
                    break;
                }
            }
            _ => {}
        }
    }
    assert_eq!(depth, 0, "switch braces do not balance:\n{out}");
}
